def magnetic_autolock_sweep_configs(quick: bool) -> List[MagneticAutolockConfig]:
    configs: List[MagneticAutolockConfig] = []
    receiver_pairs = [(8.82, 8.88), (8.82, 8.90), (8.84, 8.915)] if quick else [
        (8.80, 8.88), (8.82, 8.90), (8.84, 8.915), (8.86, 8.93), (8.88, 8.92)
    ]
    bias_pairs = [(-0.70, -0.35), (-0.55, -0.20)] if quick else [
        (-0.75, -0.40), (-0.65, -0.30), (-0.55, -0.20), (-0.45, -0.10)
    ]
    strengths = [0.80, 0.84, 0.90] if quick else [0.78, 0.82, 0.84, 0.88, 0.92]
    phases = [24.0, 30.0, 36.0] if quick else [20.0, 24.0, 28.0, 32.0, 36.0]
    splits = [0.04, 0.08, 0.12] if quick else [0.03, 0.05, 0.08, 0.11, 0.14]
    injection_freqs = [9.04, 9.07, 9.10] if quick else [9.02, 9.04, 9.06, 9.08, 9.10]
    injection_amps = [0.004, 0.008, 0.012] if quick else [0.003, 0.006, 0.009, 0.012]

    for start, end in receiver_pairs:
        for strength in strengths:
            cfg = magnetic_autolock_seed_config(
                f"sweep_receiver_capture_{safe_token(start)}_to_{safe_token(end)}_s{safe_token(strength)}",
                "autoresonant_receiver_sweep",
                receiver=end,
                phase=30.0,
                strength=strength,
            )
            cfg.receiver_tuning_start = start
            cfg.receiver_tuning_end = end
            cfg.capture_bandwidth_hint = abs(end - start)
            configs.append(cfg)

    for b0, b1 in bias_pairs:
        for phase in phases:
            cfg = magnetic_autolock_seed_config(
                f"sweep_bias_capture_{safe_token(b0)}_to_{safe_token(b1)}_p{safe_token(phase)}",
                "autoresonant_bias_sweep",
                receiver=8.90,
                phase=phase,
                strength=0.84,
            )
            cfg.magnetic_bias_start = b0
            cfg.magnetic_bias_end = b1
            cfg.capture_bandwidth_hint = abs(b1 - b0)
            configs.append(cfg)

    for split in splits:
        for phase in phases:
            cfg = magnetic_autolock_seed_config(
                f"sweep_hybrid_split_{safe_token(split)}_phase_{safe_token(phase)}",
                "hybrid_mode_tuning",
                receiver=8.90,
                phase=phase,
                strength=0.84,
            )
            cfg.hybrid_mode_splitting = split
            cfg.capture_bandwidth_hint = split
            configs.append(cfg)

    for freq in injection_freqs:
        for amp in injection_amps:
            cfg = magnetic_autolock_seed_config(
                f"sweep_injection_freq_{safe_token(freq)}_amp_{safe_token(amp)}",
                "ultraweak_injection_lock",
                receiver=8.90,
                phase=30.0,
                strength=0.84,
            )
            cfg.injection_frequency = freq
            cfg.injection_amplitude = amp
            cfg.injection_phase_deg = 0.0
            cfg.capture_bandwidth_hint = 0.015
            configs.append(cfg)

    return configs


def magnetic_autolock_pass(row: Dict[str, float | str]) -> bool:
    runtime_factor = float(row.get("runtime_factor", 1.0))
    budget_gate = 0.005 if runtime_factor >= 4.0 else 0.002
    is_candidate = str(row.get("reference_role")) == "discovery_candidate"
    return (
        is_candidate
        and float(row.get("generated_vs_direct_bridge_ratio", 0.0)) > 0.75
        and float(row.get("phase_lock_9", 0.0)) > 0.90
        and float(row.get("spectral_purity_9", 0.0)) > 0.60
        and float(row.get("energy_budget_error", 1.0)) < budget_gate
        and float(row.get("active_work_fraction", 1.0)) < 0.05
        and float(row.get("injection_work_fraction", 1.0)) < 0.05
        and str(row.get("no_direct_6_drive", "False")) == "True"
        and str(row.get("no_direct_9_drive", "False")) == "True"
    )


def update_magnetic_autolock_score(row: Dict[str, float | str]) -> None:
    failures = []
    runtime_factor = float(row.get("runtime_factor", 1.0))
    budget_gate = 0.005 if runtime_factor >= 4.0 else 0.002
    if float(row.get("generated_vs_direct_bridge_ratio", 0.0)) <= 0.75:
        failures.append("bridge_ratio")
    if float(row.get("phase_lock_9", 0.0)) <= 0.90:
        failures.append("phase_lock_9")
    if float(row.get("spectral_purity_9", 0.0)) <= 0.60:
        failures.append("spectral_purity_9")
    if float(row.get("energy_budget_error", 1.0)) >= budget_gate:
        failures.append("energy_budget")
    if float(row.get("active_work_fraction", 1.0)) >= 0.05:
        failures.append("active_work_fraction")
    if float(row.get("injection_work_fraction", 1.0)) >= 0.05:
        failures.append("injection_work_fraction")
    if str(row.get("no_direct_6_drive", "False")) != "True" or str(row.get("no_direct_9_drive", "False")) != "True":
        failures.append("direct_drive_contamination")

    lock_score = float(row.get("lock_hold_duration_score", 0.0))
    bandwidth = float(row.get("capture_bandwidth", 0.0))
    repeatability = float(row.get("repeatability_score", 1.0))
    energy_penalty = 1.0 + 800.0 * max(0.0, float(row.get("energy_budget_error", 0.0)))
    active_penalty = 1.0 + 40.0 * max(0.0, float(row.get("active_work_fraction", 0.0)))
    score = (
        float(row.get("generated_vs_direct_bridge_ratio", 0.0))
        * float(row.get("phase_lock_9", 0.0))
        * float(row.get("spectral_purity_9", 0.0))
        * lock_score
        * (1.0 + bandwidth)
        * repeatability
        / (energy_penalty * active_penalty)
    )
    passed = magnetic_autolock_pass(row)
    if not passed or str(row.get("reference_role")) in ("reference", "ceiling_reference", "control"):
        score = 0.0
    strong = (
        passed
        and float(row.get("generated_vs_direct_bridge_ratio", 0.0)) > 0.85
        and float(row.get("phase_lock_9", 0.0)) > 0.95
        and float(row.get("spectral_purity_9", 0.0)) > 0.75
        and float(row.get("energy_budget_error", 1.0)) < (0.003 if runtime_factor >= 4.0 else 0.001)
        and float(row.get("injection_work_fraction", 0.0)) < 0.02
    )

    if "phase_lock_9" in failures:
        failure_mode = "phase_drift"
    elif "bridge_ratio" in failures:
        failure_mode = "weak_bridge_ratio"
    elif "spectral_purity_9" in failures:
        failure_mode = "weak_purity"
    elif "energy_budget" in failures:
        failure_mode = "energy_budget_drift"
    elif "active_work_fraction" in failures or "injection_work_fraction" in failures:
        failure_mode = "too_active"
    elif passed:
        failure_mode = "stable_capture"
    else:
        failure_mode = "control_or_reference"

    row["passed"] = str(passed)
    row["strong_passed"] = str(strong)
    row["failed_gate_names"] = ";".join(failures)
    row["failure_mode"] = failure_mode
    row["magnetic_autolock_score"] = score
    row["score"] = score


def magnetic_autolock_measure(config: MagneticAutolockConfig, seed: int, quick: bool,
                              dt: float, runtime: float, sample_every: int,
                              runtime_factor: float, run_type: str, sweep: str,
                              sweep_value: str, direct_cache: Dict[Tuple[str, float, float, float], Tuple[Dict[str, object], Dict[str, float | str]]],
                              passive_baselines: Dict[float, Dict[str, float | str]]
                              ) -> Tuple[Dict[str, float | str], List[Dict[str, float | str]], List[Dict[str, float | str]], List[Dict[str, float | str]]]:
    effective_config = magnetic_autolock_effective_config(config)
    target_key = f"{effective_config.bridge.target_6:g}:{effective_config.bridge.target_9:g}"
    cache_key = (target_key, dt, runtime, float(effective_config.bridge.target_9))
    if cache_key not in direct_cache:
        direct_cfg = magnetic_bridge_direct_reference(effective_config)
        direct_sim, _ = simulate_bridge_amp(direct_cfg, seed + 4700, quick, dt=dt, t_max=runtime, sample_every=sample_every)
        direct_row = bridge_metrics_window(direct_cfg, direct_sim, seed + 4700, "direct_reference", "direct_3_plus_6", "reference", 0.35, 1.0)
        direct_cache[cache_key] = (direct_sim, direct_row)
    direct_sim, direct_row = direct_cache[cache_key]

    if config.mechanism == "direct_3_plus_6_reference":
        sim_cfg = magnetic_bridge_direct_reference(effective_config)
        sim, oscillator_ledger = simulate_bridge_amp(sim_cfg, seed, quick, dt=dt, t_max=runtime, sample_every=sample_every)
        row = bridge_metrics_window(sim_cfg, sim, seed, run_type, sweep, sweep_value, 0.35, 1.0)
        drift_rows, diag_summary = bridge_phase_diagnostic_series(sim_cfg, sim, direct_sim, 0.35, 1.0)
        row.update(diag_summary)
        ledger_rows = oscillator_ledger
        magnetic_ledger: List[Dict[str, float | str]] = []
    elif config.mechanism == "direct_9_ceiling_reference":
        sim_cfg = magnetic_bridge_direct_9_reference(effective_config)
        sim, oscillator_ledger = simulate_bridge_amp(sim_cfg, seed, quick, dt=dt, t_max=runtime, sample_every=sample_every)
        row = bridge_metrics_window(sim_cfg, sim, seed, run_type, sweep, sweep_value, 0.35, 1.0)
        drift_rows, diag_summary = bridge_phase_diagnostic_series(sim_cfg, sim, direct_sim, 0.35, 1.0)
        row.update(diag_summary)
        ledger_rows = oscillator_ledger
        magnetic_ledger = []
    else:
        no_mag_row = passive_baselines.get(runtime_factor)
        row, magnetic_ledger, drift_rows = magnetic_bridge_measure(
            effective_config,
            seed,
            quick,
            dt,
            runtime,
            sample_every,
            runtime_factor,
            run_type,
            sweep,
            sweep_value,
            direct_sim,
            direct_row,
            no_mag_row,
        )
        ledger_rows = magnetic_ledger

    row["experiment"] = "magnetic_autolock"
    row["case"] = config.name
    row["candidate_id"] = f"{config.name}:{runtime_factor:g}x:{run_type}"
    row["mechanism"] = config.mechanism
    row["magnetic_option"] = effective_config.magnetic_option
    row["reference_role"] = config.reference_role
    row["family"] = config.family
    row["runtime_factor"] = runtime_factor
    row["receiver_tuning_start"] = config.receiver_tuning_start
    row["receiver_tuning_end"] = config.receiver_tuning_end
    row["magnetic_bias_start"] = config.magnetic_bias_start
    row["magnetic_bias_end"] = config.magnetic_bias_end
    row["stage_b_inductance_start"] = config.stage_b_inductance_start
    row["stage_b_inductance_end"] = config.stage_b_inductance_end
    row["hybrid_mode_splitting"] = config.hybrid_mode_splitting
    row["injection_frequency"] = config.injection_frequency
    row["injection_amplitude"] = config.injection_amplitude
    row["injection_phase_deg"] = config.injection_phase_deg
    row["effective_receiver_frequency"] = effective_config.bridge.mode_freqs[2]
    row["effective_stage_b_frequency"] = effective_config.bridge.mode_freqs[1]
    row["effective_generated_frequency"] = row.get("effective_target_frequency", effective_config.bridge.target_9)
    row["bridge_ratio"] = metric_ratio(float(row.get("energy_at_9", 0.0)), float(direct_row.get("energy_at_9", 0.0)))
    row["generated_vs_direct_bridge_ratio"] = row["bridge_ratio"]
    row["energy_at_9_from_direct_3_plus_6_reference"] = direct_row.get("energy_at_9", 0.0)
    total_input_before = float(row.get("total_input_work", 1e-18))
    sweep_work, injection_work, active_fraction, injection_fraction = magnetic_autolock_work_terms(config, runtime, total_input_before)
    total_input_with_active = total_input_before + sweep_work + injection_work
    row["autoresonant_sweep_work"] = sweep_work
    row["injection_work"] = injection_work
    row["active_component_input_work"] = sweep_work + injection_work
    row["total_input_work_before_active_accounting"] = total_input_before
    row["total_input_work"] = total_input_with_active
    row["active_work_fraction"] = active_fraction
    row["injection_work_fraction"] = injection_fraction
    row["conversion_efficiency"] = metric_ratio(float(row.get("energy_at_9", 0.0)), total_input_with_active)
    row["clean_passive_conversion_efficiency"] = row["conversion_efficiency"]
    passive_phase = float(passive_baselines.get(runtime_factor, {}).get("phase_lock_9", 0.0))
    row["autolock_gain_vs_passive_magnetic"] = metric_ratio(float(row.get("phase_lock_9", 0.0)), passive_phase)
    row["hybrid_mode_frequency_low"] = float(row.get("effective_receiver_frequency", 0.0)) - abs(config.hybrid_mode_splitting)
    row["hybrid_mode_frequency_high"] = float(row.get("effective_receiver_frequency", 0.0)) + abs(config.hybrid_mode_splitting)
    runtime_value = float(row.get("runtime", runtime))
    lock_duration = float(row.get("lock_duration", 0.0))
    sweep_stop = config.sweep_fraction * runtime_value
    hold_window = max(runtime_value * max(0.10, 1.0 - config.sweep_fraction), 1e-9)
    row["lock_acquisition_time"] = min(sweep_stop, float(row.get("time_to_unlock", sweep_stop)))
    row["lock_hold_duration"] = max(0.0, lock_duration - 0.20 * sweep_stop)
    row["lock_hold_duration_score"] = min(1.0, float(row["lock_hold_duration"]) / hold_window)
    row["capture_success"] = str(
        float(row.get("phase_lock_9", 0.0)) > 0.90
        and float(row.get("spectral_purity_9", 0.0)) > 0.60
        and float(row.get("generated_vs_direct_bridge_ratio", 0.0)) > 0.75
    )
    row["capture_bandwidth"] = min(1.0, abs(config.capture_bandwidth_hint) * 8.0)
    row["capture_bandwidth_score"] = row["capture_bandwidth"]
    row["repeatability_score"] = 1.0
    row["no_direct_6_drive"] = row.get("no_direct_6_drive", "False")
    row["no_direct_9_drive"] = row.get("no_direct_9_drive", "False")
    row["note"] = config.note

    for item in drift_rows:
        item["experiment"] = "magnetic_autolock"
        item["case"] = config.name
        item["candidate_id"] = row["candidate_id"]
        item["mechanism"] = config.mechanism
        item["runtime_factor"] = runtime_factor
        item["active_work_fraction"] = active_fraction
    for item in ledger_rows:
        item["experiment"] = "magnetic_autolock"
        item["case"] = config.name
        item["candidate_id"] = row["candidate_id"]
        item["mechanism"] = config.mechanism
        item["active_component_input_work"] = sweep_work + injection_work
        item["total_input_work_with_active_accounting"] = total_input_with_active
        item["active_work_fraction"] = active_fraction
        item["injection_work_fraction"] = injection_fraction
    schedule = magnetic_autolock_schedule_rows(config, row, runtime_value)
    update_magnetic_autolock_score(row)
    return row, ledger_rows, drift_rows, schedule


def magnetic_autolock_validation(config: MagneticAutolockConfig, seed: int, quick: bool,
                                 dt: float, base_runtime: float, sample_every: int,
                                 passive_baselines: Dict[float, Dict[str, float | str]]
                                 ) -> Tuple[List[Dict[str, float | str]], List[Dict[str, float | str]], List[Dict[str, float | str]], List[Dict[str, float | str]]]:
    tests = [
        ("runtime_1x", dt, base_runtime, 1.0),
        ("half_dt_1x", dt * 0.5, base_runtime, 1.0),
        ("quarter_dt_1x", dt * 0.25, base_runtime, 1.0),
        ("runtime_2x", dt, base_runtime * 2.0, 2.0),
        ("runtime_4x", dt, base_runtime * 4.0, 4.0),
    ]
    rows: List[Dict[str, float | str]] = []
    ledger_rows: List[Dict[str, float | str]] = []
    drift_rows: List[Dict[str, float | str]] = []
    schedule_rows: List[Dict[str, float | str]] = []
    direct_cache: Dict[Tuple[str, float, float, float], Tuple[Dict[str, object], Dict[str, float | str]]] = {}
    for idx, (name, test_dt, runtime, factor) in enumerate(tests):
        row, ledger, drift, schedule = magnetic_autolock_measure(
            config,
            seed + idx * 71,
            quick,
            test_dt,
            runtime,
            sample_every,
            factor,
            "validation",
            name,
            name,
            direct_cache,
            passive_baselines,
        )
        row["validation_test"] = name
        rows.append(row)
        ledger_rows.extend(ledger)
        drift_rows.extend(drift)
        schedule_rows.extend(schedule)
    return rows, ledger_rows, drift_rows, schedule_rows


def apply_magnetic_autolock_validation_status(candidate: Dict[str, float | str],
                                             validation_rows: List[Dict[str, float | str]]) -> None:
    rows = [r for r in validation_rows if str(r.get("case")) == str(candidate.get("case"))]
    half = next((r for r in rows if str(r.get("validation_test")) == "half_dt_1x"), {})
    quarter = next((r for r in rows if str(r.get("validation_test")) == "quarter_dt_1x"), {})
    runtime2 = next((r for r in rows if str(r.get("validation_test")) == "runtime_2x"), {})
    runtime4 = next((r for r in rows if str(r.get("validation_test")) == "runtime_4x"), {})
    half_pass = half.get("passed") == "True"
    quarter_pass = quarter.get("passed") == "True"
    runtime2_pass = runtime2.get("passed") == "True"
    runtime4_pass = runtime4.get("passed") == "True"
    stability_parts = [
        1.0 if half_pass else 0.0,
        1.0 if quarter_pass else 0.0,
        1.0 if runtime2_pass else 0.0,
        1.0 if runtime4_pass else 0.0,
        ratio_stability_score(float(half.get("phase_lock_9", 0.0)), float(candidate.get("phase_lock_9", 0.0))),
        ratio_stability_score(float(runtime2.get("phase_lock_9", 0.0)), float(candidate.get("phase_lock_9", 0.0))),
        ratio_stability_score(float(runtime4.get("phase_lock_9", 0.0)), float(candidate.get("phase_lock_9", 0.0))),
    ]
    candidate["half_dt_passed"] = str(half_pass)
    candidate["quarter_dt_passed"] = str(quarter_pass)
    candidate["runtime_2x_passed"] = str(runtime2_pass)
    candidate["runtime_4x_passed"] = str(runtime4_pass)
    candidate["repeatability_score"] = float(np.mean(stability_parts))
    candidate["validation_status"] = "passed" if half_pass and quarter_pass and runtime2_pass else "failed"
    candidate["promotion_ready"] = str(half_pass and quarter_pass and runtime2_pass and runtime4_pass)
    update_magnetic_autolock_score(candidate)
    if str(candidate.get("validation_status")) != "passed":
        candidate["passed"] = "False"
        candidate["failed_gate_names"] = ";".join(filter(None, [str(candidate.get("failed_gate_names", "")), "validation_stability"]))
        candidate["magnetic_autolock_score"] = 0.0
        candidate["score"] = 0.0


def plot_magnetic_autolock_outputs(out_dir: Path, ranked: List[Dict[str, float | str]],
                                   sweep_rows: List[Dict[str, float | str]],
                                   ledger_rows: List[Dict[str, float | str]],
                                   drift_rows: List[Dict[str, float | str]],
                                   schedule_rows: List[Dict[str, float | str]],
                                   validation_rows: List[Dict[str, float | str]]) -> None:
    if ranked:
        fig, ax = plt.subplots(figsize=(8.5, 5.2))
        ax.scatter(
            [float(r.get("generated_vs_direct_bridge_ratio", 0.0)) for r in ranked],
            [float(r.get("phase_lock_9", 0.0)) for r in ranked],
            c=[float(r.get("active_work_fraction", 0.0)) for r in ranked],
        )
        ax.axvline(0.75, color="tab:red", linestyle="--", linewidth=1.0)
        ax.axhline(0.90, color="tab:red", linestyle="--", linewidth=1.0)
        ax.set_title("magnetic autolock bridge ratio vs phase lock")
        ax.set_xlabel("bridge ratio")
        ax.set_ylabel("phase_lock_9")
        fig.tight_layout()
        fig.savefig(out_dir / "magnetic_autolock_active_work_vs_phase_lock.png", dpi=140)
        plt.close(fig)

        labels = [str(r.get("case", ""))[:24] for r in ranked[:10]]
        values = [float(r.get("magnetic_autolock_score", 0.0)) for r in ranked[:10]]
        fig, ax = plt.subplots(figsize=(9.5, 5.2))
        ax.bar(np.arange(len(labels)), values)
        ax.set_xticks(np.arange(len(labels)))
        ax.set_xticklabels(labels, rotation=35, ha="right")
        ax.set_ylabel("autolock score")
        ax.set_title("magnetic autolock candidates")
        fig.tight_layout()
        fig.savefig(out_dir / "magnetic_autolock_comparison.png", dpi=140)
        plt.close(fig)

    if drift_rows:
        for key, ylabel, filename in [
            ("local_phase_lock", "local phase lock", "magnetic_autolock_phase_lock_runtime.png"),
            ("phase_mismatch_3_plus_6_minus_9", "phase error", "magnetic_autolock_phase_error_over_time.png"),
            ("sliding_bridge_ratio", "sliding bridge ratio", "magnetic_autolock_bridge_ratio_over_time.png"),
            ("phase_drift_rate", "phase drift rate", "magnetic_autolock_phase_drift_rate.png"),
        ]:
            fig, ax = plt.subplots(figsize=(9.2, 5.0))
            for case in list(dict.fromkeys(str(r.get("case", "")) for r in drift_rows))[:6]:
                rows = [r for r in drift_rows if str(r.get("case", "")) == case]
                if rows:
                    ax.plot([float(r["time_mid"]) for r in rows], [float(r.get(key, 0.0)) for r in rows], label=case[:28])
            ax.set_title(ylabel)
            ax.set_xlabel("time")
            ax.set_ylabel(ylabel)
            ax.legend(fontsize=7)
            fig.tight_layout()
            fig.savefig(out_dir / filename, dpi=140)
            plt.close(fig)

    if schedule_rows:
        fig, ax = plt.subplots(figsize=(9.2, 5.0))
        for case in list(dict.fromkeys(str(r.get("case", "")) for r in schedule_rows))[:5]:
            rows = [r for r in schedule_rows if str(r.get("case", "")) == case]
            if rows:
                ax.plot([float(r["time"]) for r in rows], [float(r.get("receiver_tuning_schedule", 0.0)) for r in rows], label=case[:28])
        ax.set_title("autolock sweep schedule")
        ax.set_xlabel("time")
        ax.set_ylabel("receiver tuning")
        ax.legend(fontsize=7)
        fig.tight_layout()
        fig.savefig(out_dir / "magnetic_autolock_sweep_schedule.png", dpi=140)
        plt.close(fig)

        fig, ax = plt.subplots(figsize=(9.2, 5.0))
        rows = schedule_rows
        ax.plot([float(r["time"]) for r in rows], [float(r.get("active_component_input_work", 0.0)) for r in rows])
        ax.set_title("autolock counted active/sweep work")
        ax.set_xlabel("time")
        ax.set_ylabel("active work")
        fig.tight_layout()
        fig.savefig(out_dir / "magnetic_autolock_work_over_time.png", dpi=140)
        plt.close(fig)

    hybrid = [r for r in sweep_rows if "hybrid" in str(r.get("mechanism", ""))]
    if hybrid:
        fig, ax = plt.subplots(figsize=(8.5, 5.2))
        ax.scatter(
            [float(r.get("hybrid_mode_splitting", 0.0)) for r in hybrid],
            [float(r.get("effective_generated_frequency", 0.0)) for r in hybrid],
            c=[float(r.get("phase_lock_9", 0.0)) for r in hybrid],
        )
        ax.set_title("hybrid mode frequency pull")
        ax.set_xlabel("hybrid mode splitting")
        ax.set_ylabel("effective generated frequency")
        fig.tight_layout()
        fig.savefig(out_dir / "magnetic_autolock_hybrid_modes.png", dpi=140)
        plt.close(fig)

    if validation_rows:
        fig, ax = plt.subplots(figsize=(8.8, 5.0))
        labels = [str(r.get("validation_test", "")) for r in validation_rows[:10]]
        values = [float(r.get("phase_lock_9", 0.0)) for r in validation_rows[:10]]
        ax.bar(np.arange(len(labels)), values)
        ax.axhline(0.90, color="tab:red", linestyle="--", linewidth=1.0)
        ax.set_xticks(np.arange(len(labels)))
        ax.set_xticklabels(labels, rotation=30, ha="right")
        ax.set_ylabel("phase_lock_9")
        ax.set_title("4x survival and dt checks")
        fig.tight_layout()
        fig.savefig(out_dir / "magnetic_autolock_4x_survival.png", dpi=140)
        plt.close(fig)

    capture_rows = [r for r in sweep_rows if "receiver_capture" in str(r.get("case", ""))]
    if capture_rows:
        xs = sorted({float(r.get("receiver_tuning_end", 0.0)) for r in capture_rows})
        ys = sorted({float(r.get("stage_B_nonlinear_strength", 0.0)) for r in capture_rows})
        if xs and ys:
            matrix = np.zeros((len(ys), len(xs)))
            for row in capture_rows:
                matrix[ys.index(float(row.get("stage_B_nonlinear_strength", 0.0))), xs.index(float(row.get("receiver_tuning_end", 0.0)))] = float(row.get("phase_lock_9", 0.0))
            fig, ax = plt.subplots(figsize=(8.2, 5.2))
            im = ax.imshow(matrix, origin="lower", aspect="auto")
            ax.set_xticks(np.arange(len(xs)))
            ax.set_xticklabels([f"{x:g}" for x in xs])
            ax.set_yticks(np.arange(len(ys)))
            ax.set_yticklabels([f"{y:g}" for y in ys])
            ax.set_title("capture bandwidth heatmap")
            ax.set_xlabel("receiver tuning end")
            ax.set_ylabel("Stage B strength")
            fig.colorbar(im, ax=ax, label="phase_lock_9")
            fig.tight_layout()
            fig.savefig(out_dir / "magnetic_autolock_capture_bandwidth_heatmap.png", dpi=140)
            plt.close(fig)

    if ledger_rows:
        rows = [r for r in ledger_rows if str(r.get("case")) == str(ranked[0].get("case", ""))] if ranked else ledger_rows
        if rows:
            fig, ax = plt.subplots(figsize=(9.0, 5.0))
            ax.plot([float(r["time"]) for r in rows], [float(r.get("oscillator_total_stored_energy", r.get("total_stored_energy", 0.0))) for r in rows], label="stored")
            ax.plot([float(r["time"]) for r in rows], [float(r.get("active_component_input_work", 0.0)) for r in rows], label="active/sweep work")
            ax.set_title("magnetic autolock energy ledger")
            ax.set_xlabel("time")
            ax.set_ylabel("energy/work")
            ax.legend()
            fig.tight_layout()
            fig.savefig(out_dir / "magnetic_autolock_energy_ledger.png", dpi=140)
            plt.close(fig)


def write_magnetic_autolock_report(out_dir: Path, ranked: List[Dict[str, float | str]],
                                   validation_rows: List[Dict[str, float | str]],
                                   controls: List[Dict[str, float | str]]) -> None:
    best = ranked[0] if ranked else {}
    passing = [r for r in ranked if str(r.get("passed")) == "True"]
    best_passing = passing[0] if passing else {}
    runtime4_pass = any(str(r.get("validation_test")) == "runtime_4x" and str(r.get("passed")) == "True" for r in validation_rows)
    best_4x = max(
        [r for r in validation_rows if str(r.get("validation_test")) == "runtime_4x"],
        key=lambda r: float(r.get("phase_lock_9", 0.0)),
        default={},
    )
    passive_rows = [r for r in ranked if "injection" not in str(r.get("mechanism", "")) and str(r.get("reference_role")) == "discovery_candidate"]
    semi_rows = [r for r in ranked if "injection" in str(r.get("mechanism", "")) and str(r.get("reference_role")) == "discovery_candidate"]
    best_passive = passive_rows[0] if passive_rows else {}
    best_semi = semi_rows[0] if semi_rows else {}
    non369 = [r for r in controls if str(r.get("family")) == "non369"]
    non369_best = max((float(r.get("phase_lock_9", 0.0)) for r in non369), default=0.0)
    lines = [
        "# Magnetic Autolock Report",
        "",
        "This is a reduced-order passive/semi-passive mechanism test over the existing clean staged bridge model, not a full electromagnetic field solver.",
        "",
        "## Direct Answers",
        f"1. Passive magnetic autoresonance reaches stable 4x lock? {'yes' if runtime4_pass and best_4x.get('mechanism', '').startswith('autoresonant') else 'not proven in this run'}.",
        f"2. Best mechanism family: {best.get('mechanism', 'none')} with score={float(best.get('magnetic_autolock_score', 0.0)):.6g}.",
        f"3. Ultraweak injection required? {'yes in this run' if best and 'injection' in str(best.get('mechanism', '')) else 'not as the top scored row'}; active_work_fraction={float(best.get('active_work_fraction', 0.0)):.6g}.",
        f"4. Does lock survive 4x runtime? {'yes' if runtime4_pass else 'no strict 4x pass found'}; best_4x_case={best_4x.get('case', 'none')}, phase={float(best_4x.get('phase_lock_9', 0.0)):.6g}, ratio={float(best_4x.get('generated_vs_direct_bridge_ratio', 0.0)):.6g}.",
        f"5. Magnetic hybrid branch creates broader capture? {'possibly' if float(best_passive.get('capture_bandwidth', 0.0)) > 0.2 and float(best_passive.get('phase_lock_9', 0.0)) > 0.90 else 'not proven'}; best_passive={best_passive.get('case', 'none')}.",
        f"6. Energy accounting remains clean? {'yes' if best_passing and float(best_passing.get('energy_budget_error', 1.0)) < 0.002 else 'not for a promoted candidate'}; best_budget={float(best_passing.get('energy_budget_error', 1.0)) if best_passing else 1.0:.6g}.",
        f"7. Non-369 controls outperform 3->6->9? {'yes' if non369_best > float(best.get('phase_lock_9', 0.0)) else 'no in current scoring'}; best_non369_phase={non369_best:.6g}.",
        f"8. Promote to geometry369, passive tuning, or PLL? {'geometry369 seed is justified' if runtime4_pass else 'continue passive tuning or move to explicit PLL/selflock with active work accounting'}.",
        f"9. Best passive candidate: {best_passive.get('case', 'none')} score={float(best_passive.get('magnetic_autolock_score', 0.0)):.6g}.",
        f"10. Best semi-active candidate: {best_semi.get('case', 'none')} score={float(best_semi.get('magnetic_autolock_score', 0.0)):.6g}.",
        "",
        "## Top Rows",
    ]
    for row in ranked[:20]:
        lines.append(
            f"- {row.get('case')}: mechanism={row.get('mechanism')}, score={float(row.get('magnetic_autolock_score', 0.0)):.6g}, "
            f"passed={row.get('passed')}, promotion={row.get('promotion_ready', 'False')}, ratio={float(row.get('generated_vs_direct_bridge_ratio', 0.0)):.6g}, "
            f"phase={float(row.get('phase_lock_9', 0.0)):.6g}, purity={float(row.get('spectral_purity_9', 0.0)):.6g}, "
            f"budget={float(row.get('energy_budget_error', 0.0)):.6g}, active={float(row.get('active_work_fraction', 0.0)):.6g}, failure={row.get('failure_mode', '')}"
        )
    (out_dir / "README_MAGNETIC_AUTOLOCK_REPORT.md").write_text("\n".join(lines), encoding="utf-8")


def experiment_magnetic_autolock(out_dir: Path, seed: int, quick: bool = False,
                                 include_sweeps: bool = False) -> List[Dict[str, float | str]]:
    dt, base_tmax, sample_every = bridge_amp_timebase(quick)
    base_runtime = base_tmax * 1.25
    configs = magnetic_autolock_core_configs()
    if include_sweeps:
        configs.extend(magnetic_autolock_sweep_configs(quick))

    rows: List[Dict[str, float | str]] = []
    sweep_rows: List[Dict[str, float | str]] = []
    ledger_rows: List[Dict[str, float | str]] = []
    drift_rows: List[Dict[str, float | str]] = []
    schedule_rows: List[Dict[str, float | str]] = []
    controls: List[Dict[str, float | str]] = []
    validation_rows: List[Dict[str, float | str]] = []
    direct_cache: Dict[Tuple[str, float, float, float], Tuple[Dict[str, object], Dict[str, float | str]]] = {}
    passive_baselines: Dict[float, Dict[str, float | str]] = {}

    baseline_cfg = next((c for c in configs if c.name == "passive_magnetic_best_baseline"), configs[0])
    baseline_effective = magnetic_autolock_effective_config(baseline_cfg)
    for factor in [1.0, 2.0, 4.0]:
        runtime = base_runtime * factor
        direct_cfg = magnetic_bridge_direct_reference(baseline_effective)
        direct_sim, _ = simulate_bridge_amp(direct_cfg, seed + 31000 + int(factor * 10), quick, dt=dt, t_max=runtime, sample_every=sample_every)
        direct_row = bridge_metrics_window(direct_cfg, direct_sim, seed + 31000 + int(factor * 10), "direct_reference", "direct_3_plus_6", "reference", 0.35, 1.0)
        row, _, _, _ = magnetic_autolock_measure(
            baseline_cfg,
            seed + 32000 + int(factor * 10),
            quick,
            dt,
            runtime,
            sample_every,
            factor,
            "baseline",
            "passive_magnetic_baseline",
            f"{factor:g}x",
            {("3:9", dt, runtime, 9.0): (direct_sim, direct_row)},
            {},
        )
        passive_baselines[factor] = row

    for idx, config in enumerate(configs):
        row, ledger, drift, schedule = magnetic_autolock_measure(
            config,
            seed + idx * 97,
            quick,
            dt,
            base_runtime,
            sample_every,
            1.0,
            "sweep" if include_sweeps else "core",
            config.mechanism,
            config.name,
            direct_cache,
            passive_baselines,
        )
        rows.append(row)
        ledger_rows.extend(ledger)
        drift_rows.extend(drift)
        schedule_rows.extend(schedule)
        if include_sweeps or str(config.reference_role) == "discovery_candidate":
            sweep_rows.append(row)
        if str(config.reference_role) in ("control", "reference", "ceiling_reference") or config.family == "non369":
            controls.append(row)

    ranked = sorted(rows, key=lambda r: (float(r.get("magnetic_autolock_score", 0.0)), float(r.get("phase_lock_9", 0.0))), reverse=True)
    top_candidates = [r for r in ranked if str(r.get("reference_role")) == "discovery_candidate"][:5 if include_sweeps else 4]
    if not top_candidates and ranked:
        top_candidates = [ranked[0]]

    for idx, candidate in enumerate(top_candidates):
        cfg = next((c for c in configs if c.name == candidate["case"]), configs[0])
        vrows, vledger, vdrift, vschedule = magnetic_autolock_validation(cfg, seed + 41000 + idx * 1000, quick, dt, base_runtime, sample_every, passive_baselines)
        validation_rows.extend(vrows)
        ledger_rows.extend(vledger)
        drift_rows.extend(vdrift)
        schedule_rows.extend(vschedule)
        apply_magnetic_autolock_validation_status(candidate, validation_rows)
        if str(candidate.get("promotion_ready")) == "True":
            break

    ranked = sorted(rows, key=lambda r: (float(r.get("magnetic_autolock_score", 0.0)), float(r.get("phase_lock_9", 0.0))), reverse=True)
    capture_report = [
        {
            "case": row.get("case", ""),
            "mechanism": row.get("mechanism", ""),
            "validation_test": row.get("validation_test", row.get("run_type", "")),
            "runtime_factor": row.get("runtime_factor", 1.0),
            "passed": row.get("passed", "False"),
            "promotion_ready": row.get("promotion_ready", "False"),
            "generated_vs_direct_bridge_ratio": row.get("generated_vs_direct_bridge_ratio", 0.0),
            "phase_lock_9": row.get("phase_lock_9", 0.0),
            "spectral_purity_9": row.get("spectral_purity_9", 0.0),
            "energy_budget_error": row.get("energy_budget_error", 0.0),
            "active_work_fraction": row.get("active_work_fraction", 0.0),
            "failure_mode": row.get("failure_mode", ""),
        }
        for row in rows + validation_rows
    ]

    write_csv(out_dir / "magnetic_autolock_summary.csv", rows)
    write_csv(out_dir / "magnetic_autolock_ranked.csv", ranked)
    write_csv(out_dir / "magnetic_autolock_sweeps.csv", sweep_rows)
    write_csv(out_dir / "magnetic_autolock_energy_ledger.csv", ledger_rows + schedule_rows)
    write_csv(out_dir / "magnetic_autolock_phase_timeseries.csv", drift_rows)
    write_csv(out_dir / "magnetic_autolock_capture_report.csv", capture_report)
    write_csv(out_dir / "magnetic_autolock_controls.csv", controls)
    plot_magnetic_autolock_outputs(out_dir, ranked, sweep_rows, ledger_rows, drift_rows, schedule_rows, validation_rows)
    write_magnetic_autolock_report(out_dir, ranked, validation_rows, controls)

    return [
        {
            "experiment": "magnetic_autolock",
            "case": row.get("case", ""),
            "freqs": row.get("freqs", ""),
            "score": row.get("magnetic_autolock_score", 0.0),
            "passed": row.get("passed", "False"),
            "promotion_ready": row.get("promotion_ready", "False"),
            "mechanism": row.get("mechanism", ""),
            "generated_vs_direct_bridge_ratio": row.get("generated_vs_direct_bridge_ratio", 0.0),
            "phase_lock_9": row.get("phase_lock_9", 0.0),
            "spectral_purity_9": row.get("spectral_purity_9", 0.0),
            "energy_budget_error": row.get("energy_budget_error", 0.0),
            "active_work_fraction": row.get("active_work_fraction", 0.0),
            "failure_mode": row.get("failure_mode", ""),
            "note": row.get("note", ""),
        }
        for row in ranked[:20]
    ]


# ----------------------------
# Experiment 16: bridge minimum nudge
# ----------------------------

@dataclass
class BridgeMinNudgeConfig:
    name: str
    correction_type: str
    magnetic_config: MagneticBridgeConfig
    kp: float = 0.002
    correction_clamp: float = 0.012
    update_interval: float = 2.0
    smoothing: float = 0.18
    magnetic_bias_strength: float = 2.0
    control_mode: str = "normal"
    reference_role: str = "discovery_candidate"
    family: str = "369"
    note: str = ""


def bridge_min_nudge_seed_magnetic(receiver_tuning: float = 8.90,
                                   stage_b_tuning: float = 6.0,
                                   stage_b_strength: float = 0.84,
                                   phase_bias: float = 30.0) -> MagneticBridgeConfig:
    bridge = magnetic_autolock_base_bridge(receiver_tuning, phase_bias, stage_b_strength)
    bridge = replace(
        bridge,
        mode_freqs=(bridge.mode_freqs[0], stage_b_tuning, receiver_tuning),
        note="seeded from sweep_receiver_capture_8p82_to_8p9_s0p9 and passive magnetic stageB0.84 lead",
    )
    return MagneticBridgeConfig(
        "bridge_min_nudge_seed",
        bridge,
        magnetic_option="biased_saturable_core",
        mutual_inductance_a_b=0.16,
        mutual_inductance_b_receiver=0.22,
        core_saturation_strength=0.55,
        magnetic_bias_field=-0.30,
        magnetic_phase_lag_deg=-4.0,
        magnetic_damping=0.014,
        note="best magnetic/autolock seed with passive magnetic layer",
    )


def bridge_min_nudge_non369_seed(source: float, target: float) -> MagneticBridgeConfig:
    bridge = BridgeAmpConfig(
        f"bridge_min_nudge_{safe_token(source)}_to_{safe_token(target)}_control",
        mode_freqs=(source, source * 2.0, target - 0.10),
        drive_freqs=(source,),
        drive_modes=(0,),
        target_6=source * 2.0,
        target_9=target,
        stage_b_nonlinear_strength=0.84,
        stage_b_phase_bias_deg=30.0,
        family="non369",
        note="non-369 staged bridge minimum-nudge control",
    )
    return replace(
        bridge_min_nudge_seed_magnetic(target - 0.10, source * 2.0, 0.84, 30.0),
        name=f"bridge_min_nudge_non369_{safe_token(source)}_{safe_token(target)}",
        bridge=bridge,
        family="non369",
        reference_role="control",
        note="non-369 staged bridge minimum-nudge control",
    )


def bridge_min_nudge_effective_bridge(config: BridgeMinNudgeConfig, correction: float) -> BridgeAmpConfig:
    magnetic = config.magnetic_config
    bridge = magnetic.bridge
    stage_b = bridge.mode_freqs[1]
    receiver = bridge.mode_freqs[2]
    magnetic_bias = magnetic.magnetic_bias_field
    if config.correction_type == "receiver_tuning_nudge":
        receiver += correction
    elif config.correction_type == "stage_B_detuning_nudge":
        stage_b += correction
    elif config.correction_type == "magnetic_bias_nudge":
        magnetic_bias += config.magnetic_bias_strength * correction
    nudged_bridge = replace(bridge, mode_freqs=(bridge.mode_freqs[0], max(0.5, stage_b), max(0.5, receiver)))
    nudged_magnetic = replace(
        magnetic,
        bridge=nudged_bridge,
        magnetic_bias_field=magnetic_bias,
        reference_role=config.reference_role,
        family=config.family,
    )
    return magnetic_bridge_effective_bridge(nudged_magnetic)


def bridge_min_nudge_direct_reference(config: BridgeAmpConfig) -> BridgeAmpConfig:
    return replace(
        config,
        name="direct_source_plus_generated_reference",
        drive_freqs=(config.mode_freqs[0], config.target_6),
        drive_modes=(0, 1),
        drive_phases=(0.0, 0.0),
        stage_a_nonlinear_strength=0.0,
        reference_role="reference",
        note="direct lower+generated-frequency reference used only for bridge ratio",
    )


def bridge_min_nudge_phase_error(config: BridgeAmpConfig,
                                 sample_times: List[float],
                                 sample_qs: List[np.ndarray],
                                 sample_dt: float) -> float:
    window = max(24, int(6.0 / max(sample_dt, 1e-9)))
    if len(sample_times) < window:
        return 0.0
    times = np.asarray(sample_times[-window:])
    qs = np.asarray(sample_qs[-window:])
    amp3 = complex_projection(qs[:, 0], times, 0.045 * config.mode_freqs[0])
    amp6 = complex_projection(qs[:, 1], times, 0.045 * config.target_6)
    amp9 = complex_projection(qs[:, 2], times, 0.045 * config.target_9)
    if min(abs(amp3), abs(amp6), abs(amp9)) < 1e-12:
        return 0.0
    return float(wrap_angle(float(np.angle(amp3) + np.angle(amp6) - np.angle(amp9))))


def bridge_min_nudge_next_correction(config: BridgeMinNudgeConfig, rng: np.random.Generator,
                                     phase_error: float, current: float) -> float:
    if config.control_mode == "no_nudge":
        desired = 0.0
    elif config.control_mode == "wrong_sign":
        desired = config.kp * phase_error
    elif config.control_mode == "random":
        desired = float(rng.uniform(-config.correction_clamp, config.correction_clamp))
    else:
        desired = -config.kp * phase_error
    desired = float(np.clip(desired, -config.correction_clamp, config.correction_clamp))
    return float(np.clip(current + config.smoothing * (desired - current), -config.correction_clamp, config.correction_clamp))


def simulate_bridge_min_nudge(config: BridgeMinNudgeConfig, seed: int, quick: bool,
                              dt: float | None = None, t_max: float | None = None,
                              base_hz: float = 0.045, sample_every: int | None = None
                              ) -> Tuple[Dict[str, object], List[Dict[str, float | str]]]:
    rng = np.random.default_rng(seed)
    default_dt, default_tmax, default_sample = bridge_amp_timebase(quick)
    dt = default_dt if dt is None else dt
    t_max = default_tmax if t_max is None else t_max
    sample_every = default_sample if sample_every is None else sample_every
    drive_until = 0.74 * t_max

    correction = 0.0
    phase_error = 0.0
    effective = bridge_min_nudge_effective_bridge(config, correction)
    omega = 2.0 * np.pi * base_hz * np.asarray(effective.mode_freqs, dtype=float)
    zeta = np.asarray([0.018 * effective.stage_a_damping, 0.012 * effective.stage_b_damping, 0.008 * effective.receiver_damping])

    y = np.zeros(6)
    y[:3] = 1e-4 * rng.normal(size=3)
    y[3:] = 1e-4 * rng.normal(size=3)
    initial_potentials = bridge_amp_potentials(y[:3], y[3:], omega, effective)
    initial_total = float(initial_potentials["total"])
    drive_work = 0.0
    positive_input_work = 0.0
    damping_loss = 0.0
    magnetic_loss = 0.0
    spark_loss = 0.0
    correction_work_signed = 0.0
    correction_work_abs = 0.0
    correction_energy_in = 0.0
    correction_energy_out = 0.0

    update_steps = max(1, int(config.update_interval / max(dt, 1e-12)))
    sample_dt = dt * sample_every
    times: List[float] = []
    qs: List[np.ndarray] = []
    vs: List[np.ndarray] = []
    energies: List[np.ndarray] = []
    corrections: List[float] = []
    phase_errors: List[float] = []
    receiver_trace: List[float] = []
    stage_b_trace: List[float] = []
    magnetic_bias_trace: List[float] = []
    ledger: List[Dict[str, float | str]] = []

    n_steps = int(t_max / dt)
    for step in range(n_steps):
        t = step * dt
        q = y[:3]
        v = y[3:]

        if step > 0 and step % update_steps == 0:
            phase_error = bridge_min_nudge_phase_error(effective, times, qs, sample_dt)
            next_correction = bridge_min_nudge_next_correction(config, rng, phase_error, correction)
            if abs(next_correction - correction) > 1e-15:
                before = bridge_amp_potentials(q, v, omega, effective)
                next_effective = bridge_min_nudge_effective_bridge(config, next_correction)
                next_omega = 2.0 * np.pi * base_hz * np.asarray(next_effective.mode_freqs, dtype=float)
                after_param = bridge_amp_potentials(q, v, next_omega, next_effective)
                delta_work = float(after_param["total"] - before["total"])
                correction_work_signed += delta_work
                correction_work_abs += abs(delta_work)
                correction_energy_in += max(0.0, delta_work)
                correction_energy_out += max(0.0, -delta_work)
                correction = next_correction
                effective = next_effective
                omega = next_omega
                zeta = np.asarray([0.018 * effective.stage_a_damping, 0.012 * effective.stage_b_damping, 0.008 * effective.receiver_damping])

        drive_forces = bridge_amp_drive_forces(effective, t, base_hz, drive_until, 3)
        drive_power = float(np.dot(drive_forces, v))
        drive_work += drive_power * dt
        positive_input_work += max(0.0, drive_power) * dt
        damping_loss += float(np.sum(2.0 * zeta * omega * (v ** 2))) * dt
        if effective.spark_strength:
            for i, j in ((0, 1), (1, 2)):
                gate = float(spark_gate(q[i] - q[j], threshold=effective.spark_threshold))
                c = 0.030 * effective.spark_strength * gate
                spark_loss += float(c * ((v[i] - v[j]) ** 2)) * dt

        y_next = rk4_step(y, t, dt, bridge_amp_derivative, omega, effective, base_hz, drive_until, zeta)
        qn = y_next[:3]
        vn = y_next[3:]
        after = bridge_amp_potentials(qn, vn, omega, effective)
        y = y_next
        if not np.all(np.isfinite(y)) or np.max(np.abs(y)) > 1e6:
            break

        if step % sample_every == 0:
            modal = clean_modal_energy(qn, vn, omega)
            total_accounted = initial_total + drive_work + correction_work_signed - damping_loss - spark_loss
            error_abs = float(after["total"]) - total_accounted
            error_rel = abs(error_abs) / (abs(float(after["total"])) + abs(total_accounted) + 1e-18)
            now = float(t + dt)
            times.append(now)
            qs.append(qn.copy())
            vs.append(vn.copy())
            energies.append(modal)
            corrections.append(correction)
            phase_errors.append(phase_error)
            receiver_trace.append(float(effective.mode_freqs[2]))
            stage_b_trace.append(float(effective.mode_freqs[1]))
            magnetic_bias_trace.append(float(config.magnetic_config.magnetic_bias_field + (config.magnetic_bias_strength * correction if config.correction_type == "magnetic_bias_nudge" else 0.0)))
            ledger.append({
                "case": config.name,
                "time": now,
                "correction_type": config.correction_type,
                "control_mode": config.control_mode,
                "phase_error_9": phase_error,
                "correction_value": correction,
                "receiver_tuning": float(effective.mode_freqs[2]),
                "stage_B_tuning": float(effective.mode_freqs[1]),
                "magnetic_bias_field": magnetic_bias_trace[-1],
                "energy_at_3_mode": float(modal[0]),
                "energy_at_6_mode": float(modal[1]),
                "energy_at_9_mode": float(modal[2]),
                "total_stored_energy": float(after["total"]),
                "drive_input_work": drive_work,
                "positive_input_work": positive_input_work,
                "damping_loss": damping_loss,
                "spark_loss": spark_loss,
                "correction_work_signed": correction_work_signed,
                "correction_work": correction_work_abs,
                "correction_energy_in": correction_energy_in,
                "correction_energy_out": correction_energy_out,
                "total_accounted_energy": total_accounted,
                "energy_budget_error_abs": error_abs,
                "energy_budget_error_rel": error_rel,
            })

    correction_arr = np.asarray(corrections)
    sim: Dict[str, object] = {
        "times": np.asarray(times),
        "qs": np.asarray(qs),
        "vs": np.asarray(vs),
        "energy": np.asarray(energies),
        "omega": omega,
        "drive_until": drive_until,
        "dt_sample": sample_dt,
        "positive_input_work": positive_input_work,
        "net_input_work": drive_work,
        "damping_loss": damping_loss,
        "spark_loss": spark_loss,
        "correction_work_signed": correction_work_signed,
        "correction_work": correction_work_abs,
        "correction_energy_in": correction_energy_in,
        "correction_energy_out": correction_energy_out,
        "correction_rms": float(np.sqrt(np.mean(correction_arr ** 2))) if len(correction_arr) else 0.0,
        "correction_peak": float(np.max(np.abs(correction_arr))) if len(correction_arr) else 0.0,
        "correction_mean_abs": float(np.mean(np.abs(correction_arr))) if len(correction_arr) else 0.0,
        "correction_final": float(correction_arr[-1]) if len(correction_arr) else 0.0,
        "phase_error_rms": float(np.sqrt(np.mean(np.asarray(phase_errors) ** 2))) if phase_errors else 0.0,
        "energy_budget_error_rel": float(ledger[-1]["energy_budget_error_rel"]) if ledger else 1.0,
        "max_energy_budget_error_rel": max((float(r["energy_budget_error_rel"]) for r in ledger), default=1.0),
        "effective_config": effective,
        "receiver_tuning_trace": np.asarray(receiver_trace),
        "stage_b_tuning_trace": np.asarray(stage_b_trace),
        "magnetic_bias_trace": np.asarray(magnetic_bias_trace),
    }
    return sim, ledger


def bridge_min_nudge_gate(row: Dict[str, float | str]) -> bool:
    return (
        float(row.get("bridge_ratio", row.get("generated_vs_direct_bridge_ratio", 0.0))) > 0.75
        and float(row.get("phase_lock_9", 0.0)) > 0.90
        and float(row.get("spectral_purity_9", 0.0)) > 0.60
        and float(row.get("energy_budget_error", 1.0)) < 0.005
        and float(row.get("correction_work_fraction", 1.0)) < 0.02
        and str(row.get("no_direct_6_drive", "False")) == "True"
        and str(row.get("no_direct_9_drive", "False")) == "True"
    )


def bridge_min_nudge_update_score(row: Dict[str, float | str]) -> None:
    passed = bridge_min_nudge_gate(row)
    runtime_factor = float(row.get("runtime_factor", 1.0))
    strong = (
        passed
        and float(row.get("bridge_ratio", 0.0)) > 0.85
        and float(row.get("phase_lock_9", 0.0)) > 0.95
        and float(row.get("spectral_purity_9", 0.0)) > 0.75
        and float(row.get("correction_work_fraction", 1.0)) < 0.01
    )
    failures = []
    if float(row.get("bridge_ratio", 0.0)) <= 0.75:
        failures.append("bridge_ratio")
    if float(row.get("phase_lock_9", 0.0)) <= 0.90:
        failures.append("phase_lock_9")
    if float(row.get("spectral_purity_9", 0.0)) <= 0.60:
        failures.append("spectral_purity_9")
    if float(row.get("energy_budget_error", 1.0)) >= 0.005:
        failures.append("energy_budget")
    if float(row.get("correction_work_fraction", 1.0)) >= 0.02:
        failures.append("correction_work_fraction")
    if str(row.get("no_direct_6_drive", "False")) != "True" or str(row.get("no_direct_9_drive", "False")) != "True":
        failures.append("direct_drive_contamination")
    if runtime_factor < 4.0:
        failures.append("not_4x_runtime")

    gentle_bonus = 1.0 / (
        1.0
        + 350.0 * max(0.0, float(row.get("correction_work_fraction", 0.0)))
        + 25.0 * max(0.0, float(row.get("correction_peak", 0.0)))
    )
    score = (
        float(row.get("bridge_ratio", 0.0))
        * float(row.get("phase_lock_9", 0.0))
        * float(row.get("spectral_purity_9", 0.0))
        * gentle_bonus
        / (1.0 + 700.0 * max(0.0, float(row.get("energy_budget_error", 0.0))))
    )
    if not passed or runtime_factor < 4.0 or str(row.get("reference_role")) != "discovery_candidate":
        score = 0.0

    if "phase_lock_9" in failures:
        failure_mode = "phase_drift"
    elif "bridge_ratio" in failures:
        failure_mode = "weak_bridge_ratio"
    elif "spectral_purity_9" in failures:
        failure_mode = "weak_purity"
    elif "energy_budget" in failures:
        failure_mode = "energy_budget_drift"
    elif "correction_work_fraction" in failures:
        failure_mode = "overpowered_correction"
    elif passed:
        failure_mode = "stable_min_nudge"
    else:
        failure_mode = "control_or_reference"

    row["passed"] = str(passed)
    row["strong_passed"] = str(strong)
    row["4x_pass"] = str(passed and runtime_factor >= 4.0)
    row["failed_gate_names"] = ";".join(failures)
    row["failure_mode"] = failure_mode
    row["bridge_min_nudge_score"] = score
    row["score"] = score


def bridge_min_nudge_measure(config: BridgeMinNudgeConfig, seed: int, quick: bool,
                             dt: float, runtime: float, sample_every: int,
                             runtime_factor: float, run_type: str,
                             sweep: str, sweep_value: str,
                             direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]]
                             ) -> Tuple[Dict[str, float | str], List[Dict[str, float | str]], List[Dict[str, float | str]]]:
    sim, ledger = simulate_bridge_min_nudge(config, seed, quick, dt=dt, t_max=runtime, sample_every=sample_every)
    effective = sim["effective_config"]  # type: ignore[assignment]
    target_key = f"{effective.mode_freqs[0]:g}:{effective.target_6:g}:{effective.target_9:g}"
    cache_key = (target_key, dt, runtime)
    if cache_key not in direct_cache:
        direct_cfg = bridge_min_nudge_direct_reference(effective)
        direct_sim, _ = simulate_bridge_amp(direct_cfg, seed + 8100, quick, dt=dt, t_max=runtime, sample_every=sample_every)
        direct_row = bridge_metrics_window(direct_cfg, direct_sim, seed + 8100, "direct_reference", "direct_source_plus_generated", "reference", 0.35, 1.0)
        direct_cache[cache_key] = (direct_sim, direct_row)
    direct_sim, direct_row = direct_cache[cache_key]

    row = bridge_metrics_window(effective, sim, seed, run_type, sweep, sweep_value, 0.35, 1.0)
    drift_rows, diag_summary = bridge_phase_diagnostic_series(effective, sim, direct_sim, 0.35, 1.0)
    row.update(diag_summary)
    row["experiment"] = "bridge_min_nudge"
    row["case"] = config.name
    row["candidate_id"] = f"{config.name}:{runtime_factor:g}x:{sweep}:{sweep_value}"
    row["correction_type"] = config.correction_type
    row["control_mode"] = config.control_mode
    row["reference_role"] = config.reference_role
    row["family"] = config.family
    row["runtime_factor"] = runtime_factor
    row["kp"] = config.kp
    row["correction_clamp"] = config.correction_clamp
    row["update_interval"] = config.update_interval
    row["magnetic_bias_strength"] = config.magnetic_bias_strength
    row["receiver_tuning_base"] = config.magnetic_config.bridge.mode_freqs[2]
    row["stage_B_detuning_base"] = config.magnetic_config.bridge.mode_freqs[1] - config.magnetic_config.bridge.target_6
    row["magnetic_bias_base"] = config.magnetic_config.magnetic_bias_field
    row["effective_receiver_frequency"] = effective.mode_freqs[2]
    row["effective_stage_B_frequency"] = effective.mode_freqs[1]
    row["bridge_ratio"] = metric_ratio(float(row.get("energy_at_9", 0.0)), float(direct_row.get("energy_at_9", 0.0)))
    row["generated_vs_direct_bridge_ratio"] = row["bridge_ratio"]
    row["energy_at_9_from_direct_3_plus_6_reference"] = direct_row.get("energy_at_9", 0.0)
    row["correction_work"] = float(sim["correction_work"])
    row["correction_work_signed"] = float(sim["correction_work_signed"])
    row["correction_energy_in"] = float(sim["correction_energy_in"])
    row["correction_energy_out"] = float(sim["correction_energy_out"])
    total_input_before = max(float(row.get("total_input_work", 0.0)), 1e-18)
    total_input_with_correction = total_input_before + float(sim["correction_work"])
    row["total_input_work_before_correction"] = total_input_before
    row["total_input_work"] = total_input_with_correction
    row["correction_work_fraction"] = metric_ratio(float(sim["correction_work"]), total_input_with_correction)
    row["correction_rms"] = float(sim["correction_rms"])
    row["correction_peak"] = float(sim["correction_peak"])
    row["correction_mean_abs"] = float(sim["correction_mean_abs"])
    row["correction_final"] = float(sim["correction_final"])
    row["phase_error_rms"] = float(sim["phase_error_rms"])
    row["conversion_efficiency"] = metric_ratio(float(row.get("energy_at_9", 0.0)), total_input_with_correction)
    row["lock_duration"] = row.get("lock_duration", 0.0)
    row["lock_duration_fraction"] = metric_ratio(float(row.get("lock_duration", 0.0)), float(row.get("runtime", runtime)))
    row["no_direct_6_drive"] = str(not any(abs(freq - effective.target_6) < 1e-9 and mode == 1 for freq, mode in zip(effective.drive_freqs, effective.drive_modes)))
    row["no_direct_9_drive"] = str(not any(abs(freq - effective.target_9) < 1e-9 and mode == 2 for freq, mode in zip(effective.drive_freqs, effective.drive_modes)))
    row["note"] = config.note
    bridge_min_nudge_update_score(row)

    for item in ledger:
        item["experiment"] = "bridge_min_nudge"
        item["candidate_id"] = row["candidate_id"]
        item["runtime_factor"] = runtime_factor
        item["kp"] = config.kp
        item["correction_clamp"] = config.correction_clamp
        item["update_interval"] = config.update_interval
    for item in drift_rows:
        item["experiment"] = "bridge_min_nudge"
        item["case"] = config.name
        item["candidate_id"] = row["candidate_id"]
        item["runtime_factor"] = runtime_factor
        item["correction_type"] = config.correction_type
        item["control_mode"] = config.control_mode
    return row, ledger, drift_rows


def bridge_min_nudge_make_config(correction_type: str,
                                 receiver_tuning: float = 8.90,
                                 stage_b_detuning: float = 0.0,
                                 kp: float = 0.002,
                                 correction_clamp: float = 0.012,
                                 update_interval: float = 2.0,
                                 magnetic_bias_strength: float = 2.0,
                                 control_mode: str = "normal",
                                 family: str = "369",
                                 reference_role: str = "discovery_candidate",
                                 name_suffix: str = "") -> BridgeMinNudgeConfig:
    magnetic = bridge_min_nudge_seed_magnetic(receiver_tuning, 6.0 + stage_b_detuning, 0.84, 30.0)
    name = f"{correction_type}_{control_mode}_r{safe_token(receiver_tuning)}_kp{safe_token(kp)}_c{safe_token(correction_clamp)}_u{safe_token(update_interval)}"
    if name_suffix:
        name = f"{name}_{name_suffix}"
    return BridgeMinNudgeConfig(
        name=name,
        correction_type=correction_type,
        magnetic_config=magnetic,
        kp=kp,
        correction_clamp=correction_clamp,
        update_interval=update_interval,
        magnetic_bias_strength=magnetic_bias_strength,
        control_mode=control_mode,
        reference_role=reference_role,
        family=family,
        note="proportional-only minimum nudge from magnetic/autolock receiver-capture seed",
    )


def bridge_min_nudge_specs(quick: bool, include_sweeps: bool) -> List[Tuple[str, str, BridgeMinNudgeConfig]]:
    correction_types = ["receiver_tuning_nudge", "magnetic_bias_nudge", "stage_B_detuning_nudge"]
    specs: List[Tuple[str, str, BridgeMinNudgeConfig]] = []
    for ctype in correction_types:
        specs.append(("baseline", ctype, bridge_min_nudge_make_config(ctype)))

    if include_sweeps:
        kp_values = [0.00025, 0.00075, 0.002, 0.006] if quick else [0.00015, 0.00035, 0.00075, 0.0015, 0.003, 0.006, 0.012]
        clamp_values = [0.004, 0.012, 0.024] if quick else [0.002, 0.004, 0.008, 0.012, 0.020, 0.032]
        update_values = [1.0, 2.0, 4.0] if quick else [0.75, 1.5, 2.5, 4.0, 6.0]
        receiver_values = [8.86, 8.90, 8.93] if quick else [8.86, 8.875, 8.89, 8.90, 8.915, 8.93]
        bias_strengths = [1.0, 2.0, 4.0] if quick else [0.5, 1.0, 2.0, 3.0, 4.0]
        stage_b_detunings = [-0.03, 0.0, 0.03] if quick else [-0.05, -0.025, 0.0, 0.025, 0.05]
        for ctype in correction_types:
            for value in kp_values:
                specs.append(("Kp", f"{value:g}", bridge_min_nudge_make_config(ctype, kp=value)))
            for value in clamp_values:
                specs.append(("correction_clamp", f"{value:g}", bridge_min_nudge_make_config(ctype, correction_clamp=value)))
            for value in update_values:
                specs.append(("update_interval", f"{value:g}", bridge_min_nudge_make_config(ctype, update_interval=value)))
            for value in receiver_values:
                specs.append(("receiver_tuning", f"{value:g}", bridge_min_nudge_make_config(ctype, receiver_tuning=value)))
            for value in stage_b_detunings:
                specs.append(("stage_B_detuning", f"{value:g}", bridge_min_nudge_make_config(ctype, stage_b_detuning=value)))
        for value in bias_strengths:
            specs.append(("magnetic_bias_strength", f"{value:g}", bridge_min_nudge_make_config("magnetic_bias_nudge", magnetic_bias_strength=value)))

    return specs


def bridge_min_nudge_control_specs(include_sweeps: bool) -> List[Tuple[str, str, BridgeMinNudgeConfig]]:
    specs: List[Tuple[str, str, BridgeMinNudgeConfig]] = []
    control_types = ["receiver_tuning_nudge", "magnetic_bias_nudge", "stage_B_detuning_nudge"] if include_sweeps else ["receiver_tuning_nudge"]
    for ctype in control_types:
        specs.append(("no_nudge_baseline", ctype, bridge_min_nudge_make_config(ctype, kp=0.0, control_mode="no_nudge", reference_role="control", name_suffix="control")))
        specs.append(("wrong_sign_nudge", ctype, bridge_min_nudge_make_config(ctype, kp=0.002, control_mode="wrong_sign", reference_role="control", name_suffix="control")))
        specs.append(("random_nudge", ctype, bridge_min_nudge_make_config(ctype, kp=0.002, control_mode="random", reference_role="control", name_suffix="control")))
    for source, target in ((4.0, 12.0), (5.0, 15.0)):
        for ctype in control_types:
            magnetic = bridge_min_nudge_non369_seed(source, target)
            specs.append((
                f"non369_{safe_token(source)}_{safe_token(target)}",
                ctype,
                BridgeMinNudgeConfig(
                    name=f"{ctype}_non369_{safe_token(source)}_{safe_token(target)}",
                    correction_type=ctype,
                    magnetic_config=magnetic,
                    kp=0.002,
                    correction_clamp=0.012,
                    update_interval=2.0,
                    magnetic_bias_strength=2.0,
                    control_mode="normal",
                    reference_role="control",
                    family="non369",
                    note="non-369 bridge control with identical proportional nudge accounting",
                ),
            ))
    return specs


def bridge_min_nudge_validation(config: BridgeMinNudgeConfig, seed: int, quick: bool,
                                dt: float, base_runtime: float, sample_every: int
                                ) -> Tuple[List[Dict[str, float | str]], List[Dict[str, float | str]], List[Dict[str, float | str]]]:
    tests = [
        ("runtime_4x", dt, base_runtime * 4.0, 4.0),
        ("half_dt_4x", dt * 0.5, base_runtime * 4.0, 4.0),
        ("quarter_dt_4x", dt * 0.25, base_runtime * 4.0, 4.0),
    ]
    rows: List[Dict[str, float | str]] = []
    ledger_rows: List[Dict[str, float | str]] = []
    drift_rows: List[Dict[str, float | str]] = []
    direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]] = {}
    for idx, (test, test_dt, runtime, factor) in enumerate(tests):
        row, ledger, drift = bridge_min_nudge_measure(
            config,
            seed + idx * 113,
            quick,
            test_dt,
            runtime,
            sample_every,
            factor,
            "validation",
            test,
            test,
            direct_cache,
        )
        row["validation_test"] = test
        rows.append(row)
        ledger_rows.extend(ledger)
        drift_rows.extend(drift)
    return rows, ledger_rows, drift_rows


def apply_bridge_min_nudge_validation_status(candidate: Dict[str, float | str],
                                             validation_rows: List[Dict[str, float | str]]) -> None:
    rows = [r for r in validation_rows if str(r.get("case")) == str(candidate.get("case"))]
    half = next((r for r in rows if str(r.get("validation_test")) == "half_dt_4x"), {})
    quarter = next((r for r in rows if str(r.get("validation_test")) == "quarter_dt_4x"), {})
    runtime4 = next((r for r in rows if str(r.get("validation_test")) == "runtime_4x"), {})
    half_pass = half.get("4x_pass") == "True"
    quarter_pass = quarter.get("4x_pass") == "True"
    runtime4_pass = runtime4.get("4x_pass") == "True"
    candidate["half_dt_passed"] = str(half_pass)
    candidate["quarter_dt_passed"] = str(quarter_pass)
    candidate["runtime_4x_passed"] = str(runtime4_pass)
    candidate["half_dt_phase_lock_9"] = half.get("phase_lock_9", 0.0)
    candidate["quarter_dt_phase_lock_9"] = quarter.get("phase_lock_9", 0.0)
    candidate["runtime_4x_phase_lock_9"] = runtime4.get("phase_lock_9", 0.0)
    candidate["half_dt_stability_score"] = ratio_stability_score(float(half.get("phase_lock_9", 0.0)), float(candidate.get("phase_lock_9", 0.0)))
    candidate["quarter_dt_stability_score"] = ratio_stability_score(float(quarter.get("phase_lock_9", 0.0)), float(candidate.get("phase_lock_9", 0.0)))
    candidate["promotion_ready"] = str(runtime4_pass and half_pass and quarter_pass)
    bridge_min_nudge_update_score(candidate)
    if candidate["promotion_ready"] != "True":
        candidate["passed"] = "False"
        candidate["4x_pass"] = str(runtime4_pass)
        candidate["failed_gate_names"] = ";".join(filter(None, [str(candidate.get("failed_gate_names", "")), "dt_validation"]))
        candidate["bridge_min_nudge_score"] = 0.0
        candidate["score"] = 0.0


def write_bridge_min_nudge_report(out_dir: Path, ranked: List[Dict[str, float | str]],
                                  validation_rows: List[Dict[str, float | str]],
                                  controls: List[Dict[str, float | str]]) -> None:
    discovery_ranked = [r for r in ranked if str(r.get("reference_role")) == "discovery_candidate"]
    discovery_4x = [r for r in discovery_ranked if float(r.get("runtime_factor", 1.0)) >= 4.0]
    score_mode = max((float(r.get("bridge_min_nudge_score", 0.0)) for r in discovery_4x), default=0.0) > 0.0
    promoted = [r for r in discovery_ranked if str(r.get("promotion_ready")) == "True"]
    best_promoted = promoted[0] if promoted else {}
    by_type: Dict[str, Dict[str, float | str]] = {}
    for ctype in ["receiver_tuning_nudge", "magnetic_bias_nudge", "stage_B_detuning_nudge"]:
        rows_for_type = [r for r in discovery_4x if str(r.get("correction_type")) == ctype]
        if rows_for_type:
            by_type[ctype] = max(
                rows_for_type,
                key=lambda r: float(r.get("bridge_min_nudge_score" if score_mode else "phase_lock_9", 0.0)),
            )
    best = max(
        by_type.values(),
        key=lambda r: float(r.get("bridge_min_nudge_score" if score_mode else "phase_lock_9", 0.0)),
        default=(discovery_ranked[0] if discovery_ranked else (ranked[0] if ranked else {})),
    )
    receiver_type = by_type.get("receiver_tuning_nudge", {})
    magnetic_type = by_type.get("magnetic_bias_nudge", {})
    stage_type = by_type.get("stage_B_detuning_nudge", {})
    type_metric = "score" if score_mode else "raw 4x phase"
    no_nudge = max([r for r in controls if str(r.get("control_mode")) == "no_nudge"], key=lambda r: float(r.get("phase_lock_9", 0.0)), default={})
    wrong = max([r for r in controls if str(r.get("control_mode")) == "wrong_sign"], key=lambda r: float(r.get("phase_lock_9", 0.0)), default={})
    random_control = max([r for r in controls if str(r.get("control_mode")) == "random"], key=lambda r: float(r.get("phase_lock_9", 0.0)), default={})
    non369 = max([r for r in controls if str(r.get("family")) == "non369"], key=lambda r: float(r.get("bridge_ratio", 0.0)), default={})
    gentle = (
        best_promoted
        and float(best_promoted.get("correction_work_fraction", 1.0)) < 0.02
        and float(best_promoted.get("correction_peak", 1.0)) <= float(best_promoted.get("correction_clamp", 0.0)) + 1e-12
        and float(best_promoted.get("phase_lock_9", 0.0)) > float(no_nudge.get("phase_lock_9", 0.0))
    )
    lines = [
        "# Bridge Minimum Nudge Report",
        "",
        "This mode applies no direct 6 drive and no direct 9 drive in discovery tests. The only active term is a clamped proportional parameter nudge, with explicit correction-work accounting.",
        "",
        "## Direct Answers",
        f"1. Can a tiny physically realistic tuning nudge hold 4x lock? {'yes' if best_promoted else 'not proven in this run'}; best={best_promoted.get('case', 'none')}.",
        f"2. Which works best? {best.get('correction_type', 'none')} by {type_metric}; receiver={float(receiver_type.get('bridge_min_nudge_score' if score_mode else 'phase_lock_9', 0.0)):.6g}, magnetic_bias={float(magnetic_type.get('bridge_min_nudge_score' if score_mode else 'phase_lock_9', 0.0)):.6g}, stage_B={float(stage_type.get('bridge_min_nudge_score' if score_mode else 'phase_lock_9', 0.0)):.6g}.",
        f"3. How much correction work is required? best_fraction={float(best.get('correction_work_fraction', 0.0)):.6g}, work={float(best.get('correction_work', 0.0)):.6g}, rms={float(best.get('correction_rms', 0.0)):.6g}, peak={float(best.get('correction_peak', 0.0)):.6g}.",
        f"4. Gentle stabilizer or overpowering? {'gentle stabilizer' if gentle else 'not proven gentle'}; no_nudge_phase={float(no_nudge.get('phase_lock_9', 0.0)):.6g}, wrong_sign_phase={float(wrong.get('phase_lock_9', 0.0)):.6g}, random_phase={float(random_control.get('phase_lock_9', 0.0)):.6g}.",
        f"5. Do non-369 controls beat 3 -> 6 -> 9? {'yes' if float(non369.get('bridge_ratio', 0.0)) > float(best.get('bridge_ratio', 0.0)) else 'no in current scoring'}; best_non369={non369.get('case', 'none')}, ratio={float(non369.get('bridge_ratio', 0.0)):.6g}, phase={float(non369.get('phase_lock_9', 0.0)):.6g}.",
        "",
        "## Top Rows",
    ]
    for row in ranked[:20]:
        lines.append(
            f"- {row.get('candidate_id')}: correction={row.get('correction_type')}, score={float(row.get('bridge_min_nudge_score', 0.0)):.6g}, "
            f"promotion={row.get('promotion_ready', 'False')}, 4x={row.get('4x_pass', 'False')}, ratio={float(row.get('bridge_ratio', 0.0)):.6g}, "
            f"phase={float(row.get('phase_lock_9', 0.0)):.6g}, purity={float(row.get('spectral_purity_9', 0.0)):.6g}, "
            f"budget={float(row.get('energy_budget_error', 0.0)):.6g}, corr_frac={float(row.get('correction_work_fraction', 0.0)):.6g}, failure={row.get('failure_mode', '')}"
        )
    if validation_rows:
        lines.extend(["", "## Dt Validation"])
        for row in validation_rows[:30]:
            lines.append(
                f"- {row.get('candidate_id')}: test={row.get('validation_test', '')}, 4x={row.get('4x_pass', 'False')}, "
                f"ratio={float(row.get('bridge_ratio', 0.0)):.6g}, phase={float(row.get('phase_lock_9', 0.0)):.6g}, "
                f"purity={float(row.get('spectral_purity_9', 0.0)):.6g}, corr_frac={float(row.get('correction_work_fraction', 0.0)):.6g}"
            )
    (out_dir / "README_BRIDGE_MIN_NUDGE_REPORT.md").write_text("\n".join(lines), encoding="utf-8")


def experiment_bridge_min_nudge(out_dir: Path, seed: int, quick: bool = False,
                                include_sweeps: bool = False) -> List[Dict[str, float | str]]:
    dt, base_tmax, sample_every = bridge_amp_timebase(quick)
    base_runtime = base_tmax * 1.25
    runtime_factors = [1.0, 2.0, 4.0]
    specs = bridge_min_nudge_specs(quick, include_sweeps)
    control_specs = bridge_min_nudge_control_specs(include_sweeps)

    summary_rows: List[Dict[str, float | str]] = []
    ledger_rows: List[Dict[str, float | str]] = []
    drift_rows: List[Dict[str, float | str]] = []
    controls: List[Dict[str, float | str]] = []
    direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]] = {}

    for idx, (sweep, value, config) in enumerate(specs + control_specs):
        for factor in runtime_factors:
            runtime = base_runtime * factor
            row, ledger, drift = bridge_min_nudge_measure(
                config,
                seed + idx * 211 + int(factor * 19),
                quick,
                dt,
                runtime,
                sample_every,
                factor,
                "sweep" if include_sweeps else "core",
                sweep,
                value,
                direct_cache,
            )
            summary_rows.append(row)
            if str(config.reference_role) == "control" or config.family == "non369":
                controls.append(row)
            if factor >= 4.0 or str(config.reference_role) == "control":
                ledger_rows.extend(ledger)
                drift_rows.extend(drift)

    ranked = sorted(
        summary_rows,
        key=lambda r: (
            float(r.get("bridge_min_nudge_score", 0.0)),
            1.0 if str(r.get("reference_role")) == "discovery_candidate" else 0.0,
            float(r.get("runtime_factor", 1.0)),
            -float(r.get("correction_work_fraction", 1.0)),
            float(r.get("phase_lock_9", 0.0)),
        ),
        reverse=True,
    )
    top_candidates = [r for r in ranked if str(r.get("reference_role")) == "discovery_candidate" and float(r.get("runtime_factor", 1.0)) >= 4.0][:5 if include_sweeps else 1]
    if not top_candidates:
        top_candidates = [r for r in ranked if str(r.get("reference_role")) == "discovery_candidate"][:2]

    validation_rows: List[Dict[str, float | str]] = []
    for idx, candidate in enumerate(top_candidates):
        spec = next((item for item in specs if candidate["case"] == item[2].name), None)
        if spec is None:
            continue
        _, _, config = spec
        rows, ledger, drift = bridge_min_nudge_validation(config, seed + 50000 + idx * 1000, quick, dt, base_runtime, sample_every)
        validation_rows.extend(rows)
        ledger_rows.extend(ledger)
        drift_rows.extend(drift)
        apply_bridge_min_nudge_validation_status(candidate, validation_rows)
        if str(candidate.get("promotion_ready")) == "True":
            break

    ranked = sorted(
        summary_rows,
        key=lambda r: (
            float(r.get("bridge_min_nudge_score", 0.0)),
            1.0 if str(r.get("reference_role")) == "discovery_candidate" else 0.0,
            float(r.get("runtime_factor", 1.0)),
            -float(r.get("correction_work_fraction", 1.0)),
            float(r.get("phase_lock_9", 0.0)),
        ),
        reverse=True,
    )

    write_csv(out_dir / "bridge_min_nudge_summary.csv", summary_rows + validation_rows)
    write_csv(out_dir / "bridge_min_nudge_ranked.csv", ranked)
    write_csv(out_dir / "bridge_min_nudge_timeseries.csv", ledger_rows + drift_rows)
    write_bridge_min_nudge_report(out_dir, ranked, validation_rows, controls)

    return [
        {
            "experiment": "bridge_min_nudge",
            "case": row.get("case", ""),
            "freqs": row.get("freqs", ""),
            "score": row.get("bridge_min_nudge_score", 0.0),
            "passed": row.get("passed", "False"),
            "promotion_ready": row.get("promotion_ready", "False"),
            "correction_type": row.get("correction_type", ""),
            "bridge_ratio": row.get("bridge_ratio", 0.0),
            "phase_lock_9": row.get("phase_lock_9", 0.0),
            "spectral_purity_9": row.get("spectral_purity_9", 0.0),
            "energy_budget_error": row.get("energy_budget_error", 0.0),
            "correction_work_fraction": row.get("correction_work_fraction", 0.0),
            "failure_mode": row.get("failure_mode", ""),
            "note": row.get("note", ""),
        }
        for row in ranked[:20]
    ]


# ----------------------------
# Experiment 17: bridge lock threshold
# ----------------------------

def bridge_lock_threshold_make_config(correction_type: str,
                                      receiver_tuning: float = 8.90,
                                      phase_bias: float = 30.0,
                                      stage_b_strength: float = 0.84,
                                      stage_b_detuning: float = 0.0,
                                      kp: float = 0.002,
                                      correction_clamp: float = 0.012,
                                      smoothing: float = 0.18,
                                      update_interval: float = 2.0,
                                      magnetic_bias_strength: float = 2.0,
                                      control_mode: str = "normal",
                                      reference_role: str = "discovery_candidate",
                                      family: str = "369",
                                      name_suffix: str = "") -> BridgeMinNudgeConfig:
    magnetic = bridge_min_nudge_seed_magnetic(receiver_tuning, 6.0 + stage_b_detuning, stage_b_strength, phase_bias)
    name = (
        f"threshold_{correction_type}_{control_mode}_r{safe_token(receiver_tuning)}"
        f"_p{safe_token(phase_bias)}_s{safe_token(stage_b_strength)}"
        f"_kp{safe_token(kp)}_c{safe_token(correction_clamp)}"
        f"_sm{safe_token(smoothing)}_u{safe_token(update_interval)}"
    )
    if name_suffix:
        name = f"{name}_{name_suffix}"
    return BridgeMinNudgeConfig(
        name=name,
        correction_type=correction_type,
        magnetic_config=magnetic,
        kp=kp,
        correction_clamp=correction_clamp,
        update_interval=update_interval,
        smoothing=smoothing,
        magnetic_bias_strength=magnetic_bias_strength,
        control_mode=control_mode,
        reference_role=reference_role,
        family=family,
        note="threshold search from bridge_min_nudge and magnetic/autolock seed",
    )


def bridge_lock_threshold_non369_config(source: float, target: float,
                                        correction_type: str,
                                        kp: float = 0.002,
                                        correction_clamp: float = 0.012,
                                        smoothing: float = 0.18,
                                        update_interval: float = 2.0) -> BridgeMinNudgeConfig:
    magnetic = bridge_min_nudge_non369_seed(source, target)
    bridge = replace(
        magnetic.bridge,
        stage_b_phase_bias_deg=30.0,
        stage_b_nonlinear_strength=0.84,
        note="non-369 bridge lock threshold control",
    )
    magnetic = replace(magnetic, bridge=bridge, reference_role="control", family="non369")
    return BridgeMinNudgeConfig(
        name=f"threshold_{correction_type}_non369_{safe_token(source)}_{safe_token(target)}",
        correction_type=correction_type,
        magnetic_config=magnetic,
        kp=kp,
        correction_clamp=correction_clamp,
        update_interval=update_interval,
        smoothing=smoothing,
        magnetic_bias_strength=2.0,
        control_mode="normal",
        reference_role="control",
        family="non369",
        note="non-369 bridge threshold control under same nudge rules",
    )


def bridge_lock_threshold_specs(quick: bool, include_sweeps: bool) -> List[Tuple[str, str, BridgeMinNudgeConfig]]:
    specs: List[Tuple[str, str, BridgeMinNudgeConfig]] = [
        ("starting_receiver_best_raw_4x", "receiver", bridge_lock_threshold_make_config("receiver_tuning_nudge", kp=0.002, correction_clamp=0.012, smoothing=0.18, update_interval=2.0)),
        ("starting_magnetic_low_work", "magnetic_bias", bridge_lock_threshold_make_config("magnetic_bias_nudge", kp=0.002, correction_clamp=0.012, smoothing=0.18, update_interval=2.0)),
        ("starting_stageB_budget_clean", "stageB", bridge_lock_threshold_make_config("stage_B_detuning_nudge", kp=0.002, correction_clamp=0.012, smoothing=0.18, update_interval=2.0)),
        ("autolock_seed_receiver", "autolock", bridge_lock_threshold_make_config("receiver_tuning_nudge", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.90, kp=0.002, correction_clamp=0.012, smoothing=0.18, update_interval=2.0)),
    ]
    if not include_sweeps:
        return specs

    correction_types = ["receiver_tuning_nudge", "magnetic_bias_nudge", "stage_B_detuning_nudge"]
    kp_values = [0.0005, 0.002, 0.008] if quick else [0.0002, 0.0005, 0.001, 0.002, 0.004, 0.008, 0.016]
    clamp_values = [0.008, 0.024] if quick else [0.004, 0.008, 0.012, 0.024, 0.040]
    smoothing_values = [0.12, 0.28] if quick else [0.08, 0.12, 0.18, 0.28, 0.42]
    update_values = [1.0, 4.0] if quick else [0.75, 1.5, 2.0, 4.0, 6.0]
    receiver_values = [8.86, 8.90, 8.93] if quick else [8.86, 8.875, 8.89, 8.90, 8.915, 8.93]
    phase_values = [15.0, 25.0, 35.0] if quick else [15.0, 20.0, 25.0, 30.0, 35.0]
    strength_values = [0.80, 0.84, 0.94] if quick else [0.80, 0.84, 0.88, 0.90, 0.94]

    for ctype in correction_types:
        for value in kp_values:
            specs.append(("Kp", f"{ctype}_{value:g}", bridge_lock_threshold_make_config(ctype, kp=value)))
        for value in clamp_values:
            specs.append(("correction_clamp", f"{ctype}_{value:g}", bridge_lock_threshold_make_config(ctype, correction_clamp=value)))
        for value in smoothing_values:
            specs.append(("correction_smoothing", f"{ctype}_{value:g}", bridge_lock_threshold_make_config(ctype, smoothing=value)))
        for value in update_values:
            specs.append(("update_interval", f"{ctype}_{value:g}", bridge_lock_threshold_make_config(ctype, update_interval=value)))
        for value in receiver_values:
            specs.append(("receiver_tuning", f"{ctype}_{value:g}", bridge_lock_threshold_make_config(ctype, receiver_tuning=value)))
        for value in phase_values:
            specs.append(("phase_bias", f"{ctype}_{value:g}", bridge_lock_threshold_make_config(ctype, phase_bias=value)))
        for value in strength_values:
            specs.append(("stage_B_nonlinear_strength", f"{ctype}_{value:g}", bridge_lock_threshold_make_config(ctype, stage_b_strength=value)))
    return specs


def bridge_lock_threshold_control_specs(include_sweeps: bool) -> List[Tuple[str, str, BridgeMinNudgeConfig]]:
    control_types = ["receiver_tuning_nudge", "magnetic_bias_nudge", "stage_B_detuning_nudge"] if include_sweeps else ["receiver_tuning_nudge"]
    specs: List[Tuple[str, str, BridgeMinNudgeConfig]] = []
    for ctype in control_types:
        specs.append(("no_nudge_baseline", ctype, bridge_lock_threshold_make_config(ctype, kp=0.0, control_mode="no_nudge", reference_role="control", name_suffix="control")))
        specs.append(("wrong_sign_nudge", ctype, bridge_lock_threshold_make_config(ctype, kp=0.002, control_mode="wrong_sign", reference_role="control", name_suffix="control")))
        specs.append(("random_nudge", ctype, bridge_lock_threshold_make_config(ctype, kp=0.002, control_mode="random", reference_role="control", name_suffix="control")))
    for source, target in ((4.0, 12.0), (5.0, 15.0)):
        for ctype in control_types:
            specs.append((f"non369_{safe_token(source)}_{safe_token(target)}", ctype, bridge_lock_threshold_non369_config(source, target, ctype)))
    return specs


def bridge_lock_threshold_gate(row: Dict[str, float | str]) -> bool:
    return (
        float(row.get("bridge_ratio", 0.0)) > 0.75
        and float(row.get("phase_lock_9", 0.0)) > 0.90
        and float(row.get("spectral_purity_9", 0.0)) > 0.60
        and float(row.get("energy_budget_error", 1.0)) < 0.005
        and float(row.get("correction_work_fraction", 1.0)) < 0.05
        and str(row.get("no_direct_6_drive", "False")) == "True"
        and str(row.get("no_direct_9_drive", "False")) == "True"
    )


def bridge_lock_threshold_update_score(row: Dict[str, float | str]) -> None:
    runtime_factor = float(row.get("runtime_factor", 1.0))
    passed = runtime_factor >= 4.0 and bridge_lock_threshold_gate(row)
    strong = (
        passed
        and float(row.get("bridge_ratio", 0.0)) > 0.85
        and float(row.get("phase_lock_9", 0.0)) > 0.95
        and float(row.get("spectral_purity_9", 0.0)) > 0.75
        and float(row.get("correction_work_fraction", 1.0)) < 0.02
    )
    failures = []
    if runtime_factor < 4.0:
        failures.append("not_4x_runtime")
    if float(row.get("bridge_ratio", 0.0)) <= 0.75:
        failures.append("bridge_ratio")
    if float(row.get("phase_lock_9", 0.0)) <= 0.90:
        failures.append("phase_lock_9")
    if float(row.get("spectral_purity_9", 0.0)) <= 0.60:
        failures.append("spectral_purity_9")
    if float(row.get("energy_budget_error", 1.0)) >= 0.005:
        failures.append("energy_budget")
    if float(row.get("correction_work_fraction", 1.0)) >= 0.05:
        failures.append("correction_work_fraction")
    if str(row.get("no_direct_6_drive", "False")) != "True" or str(row.get("no_direct_9_drive", "False")) != "True":
        failures.append("direct_drive_contamination")

    if "phase_lock_9" in failures:
        failure_mode = "phase_drift"
    elif "energy_budget" in failures:
        failure_mode = "energy_budget_drift"
    elif "correction_work_fraction" in failures:
        failure_mode = "overpowered_correction"
    elif "bridge_ratio" in failures:
        failure_mode = "weak_bridge_ratio"
    elif passed:
        failure_mode = "stable_threshold_lock"
    else:
        failure_mode = "control_or_runtime"

    score = (
        float(row.get("bridge_ratio", 0.0))
        * float(row.get("phase_lock_9", 0.0))
        * float(row.get("spectral_purity_9", 0.0))
        / (
            1.0
            + 400.0 * max(0.0, float(row.get("energy_budget_error", 0.0)))
            + 80.0 * max(0.0, float(row.get("correction_work_fraction", 0.0)))
            + 8.0 * max(0.0, float(row.get("correction_peak", 0.0)))
        )
    )
    if not passed or str(row.get("reference_role")) != "discovery_candidate":
        score = 0.0

    row["passed"] = str(passed)
    row["4x_pass"] = str(passed)
    row["strong_passed"] = str(strong)
    row["failed_gate_names"] = ";".join(failures)
    row["failure_mode"] = failure_mode
    row["bridge_lock_threshold_score"] = score
    row["score"] = score


def bridge_lock_threshold_measure(config: BridgeMinNudgeConfig, seed: int, quick: bool,
                                  dt: float, runtime: float, sample_every: int,
                                  runtime_factor: float, run_type: str,
                                  sweep: str, sweep_value: str,
                                  direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]]
                                  ) -> Tuple[Dict[str, float | str], List[Dict[str, float | str]], List[Dict[str, float | str]]]:
    row, ledger, drift = bridge_min_nudge_measure(
        config,
        seed,
        quick,
        dt,
        runtime,
        sample_every,
        runtime_factor,
        run_type,
        sweep,
        sweep_value,
        direct_cache,
    )
    row["experiment"] = "bridge_lock_threshold"
    row["candidate_id"] = f"{config.name}:{runtime_factor:g}x:{sweep}:{sweep_value}"
    row["correction_smoothing"] = config.smoothing
    row["minimum_Kp_for_4x_lock"] = 0.0
    row["minimum_work_for_4x_lock"] = 0.0
    bridge_lock_threshold_update_score(row)
    for item in ledger:
        item["experiment"] = "bridge_lock_threshold"
        item["candidate_id"] = row["candidate_id"]
        item["correction_smoothing"] = config.smoothing
    for item in drift:
        item["experiment"] = "bridge_lock_threshold"
        item["candidate_id"] = row["candidate_id"]
    return row, ledger, drift


def bridge_lock_threshold_annotate_minima(rows: List[Dict[str, float | str]]) -> None:
    passing = [
        r for r in rows
        if str(r.get("reference_role")) == "discovery_candidate"
        and str(r.get("4x_pass")) == "True"
        and float(r.get("runtime_factor", 1.0)) >= 4.0
    ]
    for row in rows:
        same_type = [r for r in passing if str(r.get("correction_type")) == str(row.get("correction_type"))]
        row["minimum_Kp_for_4x_lock"] = min((float(r.get("kp", 0.0)) for r in same_type), default=0.0)
        row["minimum_work_for_4x_lock"] = min((float(r.get("correction_work_fraction", 0.0)) for r in same_type), default=0.0)
        row["global_minimum_Kp_for_4x_lock"] = min((float(r.get("kp", 0.0)) for r in passing), default=0.0)
        row["global_minimum_work_for_4x_lock"] = min((float(r.get("correction_work_fraction", 0.0)) for r in passing), default=0.0)


def bridge_lock_threshold_validation(config: BridgeMinNudgeConfig, seed: int, quick: bool,
                                     dt: float, base_runtime: float, sample_every: int
                                     ) -> Tuple[List[Dict[str, float | str]], List[Dict[str, float | str]], List[Dict[str, float | str]]]:
    tests = [
        ("runtime_4x", dt, base_runtime * 4.0, 4.0),
        ("half_dt_4x", dt * 0.5, base_runtime * 4.0, 4.0),
        ("quarter_dt_4x", dt * 0.25, base_runtime * 4.0, 4.0),
    ]
    rows: List[Dict[str, float | str]] = []
    ledger_rows: List[Dict[str, float | str]] = []
    drift_rows: List[Dict[str, float | str]] = []
    direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]] = {}
    for idx, (test, test_dt, runtime, factor) in enumerate(tests):
        row, ledger, drift = bridge_lock_threshold_measure(
            config,
            seed + idx * 127,
            quick,
            test_dt,
            runtime,
            sample_every,
            factor,
            "validation",
            test,
            test,
            direct_cache,
        )
        row["validation_test"] = test
        rows.append(row)
        ledger_rows.extend(ledger)
        drift_rows.extend(drift)
    bridge_lock_threshold_annotate_minima(rows)
    return rows, ledger_rows, drift_rows


def apply_bridge_lock_threshold_validation_status(candidate: Dict[str, float | str],
                                                  validation_rows: List[Dict[str, float | str]]) -> None:
    rows = [r for r in validation_rows if str(r.get("case")) == str(candidate.get("case"))]
    runtime4 = next((r for r in rows if str(r.get("validation_test")) == "runtime_4x"), {})
    half = next((r for r in rows if str(r.get("validation_test")) == "half_dt_4x"), {})
    quarter = next((r for r in rows if str(r.get("validation_test")) == "quarter_dt_4x"), {})
    runtime4_pass = runtime4.get("4x_pass") == "True"
    half_pass = half.get("4x_pass") == "True"
    quarter_pass = quarter.get("4x_pass") == "True"
    candidate["runtime_4x_passed"] = str(runtime4_pass)
    candidate["half_dt_passed"] = str(half_pass)
    candidate["quarter_dt_passed"] = str(quarter_pass)
    candidate["runtime_4x_phase_lock_9"] = runtime4.get("phase_lock_9", 0.0)
    candidate["half_dt_phase_lock_9"] = half.get("phase_lock_9", 0.0)
    candidate["quarter_dt_phase_lock_9"] = quarter.get("phase_lock_9", 0.0)
    candidate["promotion_ready"] = str(runtime4_pass and half_pass and quarter_pass)
    bridge_lock_threshold_update_score(candidate)
    if candidate["promotion_ready"] != "True":
        candidate["passed"] = "False"
        candidate["failed_gate_names"] = ";".join(filter(None, [str(candidate.get("failed_gate_names", "")), "dt_validation"]))
        candidate["bridge_lock_threshold_score"] = 0.0
        candidate["score"] = 0.0


def write_bridge_lock_threshold_report(out_dir: Path, ranked: List[Dict[str, float | str]],
                                       validation_rows: List[Dict[str, float | str]],
                                       controls: List[Dict[str, float | str]]) -> None:
    discovery = [r for r in ranked if str(r.get("reference_role")) == "discovery_candidate"]
    passing = [r for r in discovery if str(r.get("promotion_ready")) == "True"]
    raw_4x_pass = [r for r in discovery if str(r.get("4x_pass")) == "True"]
    min_work_row = min(passing or raw_4x_pass, key=lambda r: float(r.get("correction_work_fraction", 1.0)), default={})
    by_type: Dict[str, Dict[str, float | str]] = {}
    for ctype in ["receiver_tuning_nudge", "magnetic_bias_nudge", "stage_B_detuning_nudge"]:
        rows_for_type = [r for r in discovery if str(r.get("correction_type")) == ctype and float(r.get("runtime_factor", 1.0)) >= 4.0]
        if rows_for_type:
            by_type[ctype] = max(rows_for_type, key=lambda r: (float(r.get("bridge_lock_threshold_score", 0.0)), float(r.get("phase_lock_9", 0.0))))
    best = max(by_type.values(), key=lambda r: (float(r.get("bridge_lock_threshold_score", 0.0)), float(r.get("phase_lock_9", 0.0))), default={})
    no_nudge = max([r for r in controls if str(r.get("control_mode")) == "no_nudge"], key=lambda r: float(r.get("phase_lock_9", 0.0)), default={})
    wrong = max([r for r in controls if str(r.get("control_mode")) == "wrong_sign"], key=lambda r: float(r.get("phase_lock_9", 0.0)), default={})
    random_control = max([r for r in controls if str(r.get("control_mode")) == "random"], key=lambda r: float(r.get("phase_lock_9", 0.0)), default={})
    non369 = max([r for r in controls if str(r.get("family")) == "non369"], key=lambda r: (float(r.get("bridge_lock_threshold_score", 0.0)), float(r.get("phase_lock_9", 0.0))), default={})
    gentle = bool(min_work_row) and float(min_work_row.get("correction_work_fraction", 1.0)) < 0.02 and float(min_work_row.get("correction_peak", 1.0)) < float(min_work_row.get("correction_clamp", 0.0)) + 1e-12
    active_too_important = not passing and max((float(r.get("phase_lock_9", 0.0)) for r in discovery if float(r.get("runtime_factor", 1.0)) >= 4.0), default=0.0) < 0.90
    lines = [
        "# Bridge Lock Threshold Report",
        "",
        "This threshold search uses only receiver tuning, magnetic bias, and Stage B detuning nudges. Discovery rows use no direct 6 drive, no direct 9 drive, and no 9-frequency injection.",
        "",
        "## Direct Answers",
        f"1. Minimum correction work needed for 4x lock: {float(min_work_row.get('correction_work_fraction', 0.0)):.6g}; minimum_Kp={float(min_work_row.get('kp', 0.0)):.6g}; candidate={min_work_row.get('case', 'none')}.",
        f"2. Best actuator: {best.get('correction_type', 'none')}; receiver_phase={float(by_type.get('receiver_tuning_nudge', {}).get('phase_lock_9', 0.0)):.6g}, magnetic_phase={float(by_type.get('magnetic_bias_nudge', {}).get('phase_lock_9', 0.0)):.6g}, stageB_phase={float(by_type.get('stage_B_detuning_nudge', {}).get('phase_lock_9', 0.0)):.6g}.",
        f"3. Gentle stabilizer or overpowering? {'gentle stabilizer' if gentle else 'not proven gentle'}; no_nudge_phase={float(no_nudge.get('phase_lock_9', 0.0)):.6g}, wrong_sign_phase={float(wrong.get('phase_lock_9', 0.0)):.6g}, random_phase={float(random_control.get('phase_lock_9', 0.0)):.6g}.",
        f"4. Non-369 controls beat 3 -> 6 -> 9? {'yes' if float(non369.get('bridge_lock_threshold_score', 0.0)) > float(best.get('bridge_lock_threshold_score', 0.0)) else 'no under current gates'}; best_non369={non369.get('case', 'none')}, phase={float(non369.get('phase_lock_9', 0.0)):.6g}, score={float(non369.get('bridge_lock_threshold_score', 0.0)):.6g}.",
        f"5. Move to geometry369/evolve? {'not yet; active correction is still too important' if active_too_important else 'candidate may justify evolve/geometry review after dt validation'}; promoted={len(passing)}.",
        "",
        "## Top Rows",
    ]
    for row in ranked[:24]:
        lines.append(
            f"- {row.get('candidate_id')}: actuator={row.get('correction_type')}, score={float(row.get('bridge_lock_threshold_score', 0.0)):.6g}, "
            f"promotion={row.get('promotion_ready', 'False')}, 4x={row.get('4x_pass', 'False')}, ratio={float(row.get('bridge_ratio', 0.0)):.6g}, "
            f"phase={float(row.get('phase_lock_9', 0.0)):.6g}, purity={float(row.get('spectral_purity_9', 0.0)):.6g}, "
            f"budget={float(row.get('energy_budget_error', 0.0)):.6g}, work={float(row.get('correction_work_fraction', 0.0)):.6g}, "
            f"kp={float(row.get('kp', 0.0)):.6g}, drift={float(row.get('phase_drift_rate', 0.0)):.6g}, failure={row.get('failure_mode', '')}"
        )
    if validation_rows:
        lines.extend(["", "## Dt Validation"])
        for row in validation_rows[:30]:
            lines.append(
                f"- {row.get('candidate_id')}: test={row.get('validation_test', '')}, 4x={row.get('4x_pass', 'False')}, "
                f"phase={float(row.get('phase_lock_9', 0.0)):.6g}, work={float(row.get('correction_work_fraction', 0.0)):.6g}, budget={float(row.get('energy_budget_error', 0.0)):.6g}"
            )
    (out_dir / "README_BRIDGE_LOCK_THRESHOLD_REPORT.md").write_text("\n".join(lines), encoding="utf-8")


def experiment_bridge_lock_threshold(out_dir: Path, seed: int, quick: bool = False,
                                     include_sweeps: bool = False) -> List[Dict[str, float | str]]:
    dt, base_tmax, sample_every = bridge_amp_timebase(quick)
    base_runtime = base_tmax * 1.25
    runtime_factors = [1.0, 2.0, 4.0]
    specs = bridge_lock_threshold_specs(quick, include_sweeps)
    control_specs = bridge_lock_threshold_control_specs(include_sweeps)

    summary_rows: List[Dict[str, float | str]] = []
    sweep_rows: List[Dict[str, float | str]] = []
    ledger_rows: List[Dict[str, float | str]] = []
    drift_rows: List[Dict[str, float | str]] = []
    controls: List[Dict[str, float | str]] = []
    direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]] = {}

    for idx, (sweep, value, config) in enumerate(specs + control_specs):
        for factor in runtime_factors:
            runtime = base_runtime * factor
            row, ledger, drift = bridge_lock_threshold_measure(
                config,
                seed + idx * 223 + int(factor * 23),
                quick,
                dt,
                runtime,
                sample_every,
                factor,
                "sweep" if include_sweeps else "core",
                sweep,
                value,
                direct_cache,
            )
            summary_rows.append(row)
            if include_sweeps or str(config.reference_role) == "discovery_candidate":
                sweep_rows.append(row)
            if str(config.reference_role) == "control" or config.family == "non369":
                controls.append(row)
            if factor >= 4.0 or str(config.reference_role) == "control":
                ledger_rows.extend(ledger)
                drift_rows.extend(drift)

    bridge_lock_threshold_annotate_minima(summary_rows)
    ranked = sorted(
        summary_rows,
        key=lambda r: (
            float(r.get("bridge_lock_threshold_score", 0.0)),
            1.0 if str(r.get("reference_role")) == "discovery_candidate" else 0.0,
            float(r.get("runtime_factor", 1.0)),
            float(r.get("phase_lock_9", 0.0)),
            -float(r.get("correction_work_fraction", 1.0)),
        ),
        reverse=True,
    )

    validation_rows: List[Dict[str, float | str]] = []
    top_candidates = [r for r in ranked if str(r.get("reference_role")) == "discovery_candidate" and float(r.get("runtime_factor", 1.0)) >= 4.0][:5 if include_sweeps else 2]
    for idx, candidate in enumerate(top_candidates):
        spec = next((item for item in specs if str(candidate.get("case")) == item[2].name), None)
        if spec is None:
            continue
        _, _, config = spec
        rows, ledger, drift = bridge_lock_threshold_validation(config, seed + 61000 + idx * 1000, quick, dt, base_runtime, sample_every)
        validation_rows.extend(rows)
        ledger_rows.extend(ledger)
        drift_rows.extend(drift)
        apply_bridge_lock_threshold_validation_status(candidate, validation_rows)
        if str(candidate.get("promotion_ready")) == "True":
            break

    bridge_lock_threshold_annotate_minima(summary_rows + validation_rows)
    ranked = sorted(
        summary_rows,
        key=lambda r: (
            float(r.get("bridge_lock_threshold_score", 0.0)),
            1.0 if str(r.get("reference_role")) == "discovery_candidate" else 0.0,
            float(r.get("runtime_factor", 1.0)),
            float(r.get("phase_lock_9", 0.0)),
            -float(r.get("correction_work_fraction", 1.0)),
        ),
        reverse=True,
    )

    write_csv(out_dir / "bridge_lock_threshold_summary.csv", summary_rows + validation_rows)
    write_csv(out_dir / "bridge_lock_threshold_ranked.csv", ranked)
    write_csv(out_dir / "bridge_lock_threshold_sweeps.csv", sweep_rows)
    write_csv(out_dir / "bridge_lock_threshold_timeseries.csv", ledger_rows + drift_rows)
    write_bridge_lock_threshold_report(out_dir, ranked, validation_rows, controls)

    return [
        {
            "experiment": "bridge_lock_threshold",
            "case": row.get("case", ""),
            "freqs": row.get("freqs", ""),
            "score": row.get("bridge_lock_threshold_score", 0.0),
            "passed": row.get("passed", "False"),
            "promotion_ready": row.get("promotion_ready", "False"),
            "correction_type": row.get("correction_type", ""),
            "bridge_ratio": row.get("bridge_ratio", 0.0),
            "phase_lock_9": row.get("phase_lock_9", 0.0),
            "spectral_purity_9": row.get("spectral_purity_9", 0.0),
            "energy_budget_error": row.get("energy_budget_error", 0.0),
            "correction_work_fraction": row.get("correction_work_fraction", 0.0),
            "minimum_Kp_for_4x_lock": row.get("minimum_Kp_for_4x_lock", 0.0),
            "minimum_work_for_4x_lock": row.get("minimum_work_for_4x_lock", 0.0),
            "failure_mode": row.get("failure_mode", ""),
            "note": row.get("note", ""),
        }
        for row in ranked[:20]
    ]


# ----------------------------
# Experiment 18: bridge control authority
# ----------------------------

@dataclass
class BridgeControlAuthorityConfig:
    name: str
    correction_type: str
    base_config: BridgeMinNudgeConfig
    correction_size: float
    schedule_type: str
    correction_start_fraction: float = 0.38
    ramp_fraction: float = 0.18
    max_allowed_correction: float = 0.024
    seed_family: str = "base"
    reference_role: str = "discovery_candidate"
    family: str = "369"
    note: str = ""


def bridge_control_authority_template(correction_type: str,
                                      seed_family: str,
                                      receiver_tuning: float = 8.90,
                                      phase_bias: float = 30.0,
                                      stage_b_strength: float = 0.84,
                                      stage_b_detuning: float = 0.0,
                                      magnetic_bias_strength: float = 2.0,
                                      reference_role: str = "discovery_candidate",
                                      family: str = "369") -> BridgeMinNudgeConfig:
    base = bridge_lock_threshold_make_config(
        correction_type,
        receiver_tuning=receiver_tuning,
        phase_bias=phase_bias,
        stage_b_strength=stage_b_strength,
        stage_b_detuning=stage_b_detuning,
        kp=0.0,
        correction_clamp=0.0,
        smoothing=1.0,
        update_interval=1.0,
        magnetic_bias_strength=magnetic_bias_strength,
        control_mode="no_nudge",
        reference_role=reference_role,
        family=family,
        name_suffix=seed_family,
    )
    return replace(base, note=f"control authority seed {seed_family}")


def bridge_control_authority_correction(config: BridgeControlAuthorityConfig, t: float,
                                        runtime: float, random_correction: float) -> float:
    start_t = config.correction_start_fraction * runtime
    if config.schedule_type in ("no_correction", "no_feedforward"):
        return 0.0
    if config.schedule_type in ("random_correction", "random_ramp"):
        return 0.0 if t < start_t else random_correction
    if t < start_t:
        return 0.0
    ramp_t = max(1e-9, config.ramp_fraction * runtime)
    progress = min(1.0, max(0.0, (t - start_t) / ramp_t))
    if config.schedule_type == "linear_ramp":
        return config.correction_size * progress
    if config.schedule_type == "piecewise_linear_ramp":
        if progress < 0.5:
            return config.correction_size * 0.70 * (progress / 0.5)
        return config.correction_size * (0.70 + 0.30 * ((progress - 0.5) / 0.5))
    if config.schedule_type in ("s_curve_ramp", "slow_s_curve_ramp"):
        smooth = progress * progress * (3.0 - 2.0 * progress)
        return config.correction_size * smooth
    if config.schedule_type == "hold_after_capture_ramp":
        capture_progress = min(1.0, progress / 0.35)
        smooth = capture_progress * capture_progress * (3.0 - 2.0 * capture_progress)
        return config.correction_size * smooth
    if config.schedule_type == "two_stage_ramp":
        if progress < 0.35:
            local = progress / 0.35
            return 0.55 * config.correction_size * (local * local * (3.0 - 2.0 * local))
        if progress < 0.70:
            return 0.55 * config.correction_size
        local = (progress - 0.70) / 0.30
        return config.correction_size * (0.55 + 0.45 * (local * local * (3.0 - 2.0 * local)))
    if config.schedule_type in ("slow_ramp", "hold_after_ramp"):
        smooth = 0.5 - 0.5 * math.cos(math.pi * progress)
        return config.correction_size * smooth
    return config.correction_size


def simulate_bridge_control_authority(config: BridgeControlAuthorityConfig, seed: int, quick: bool,
                                      dt: float | None = None, t_max: float | None = None,
                                      base_hz: float = 0.045, sample_every: int | None = None
                                      ) -> Tuple[Dict[str, object], List[Dict[str, float | str]]]:
    rng = np.random.default_rng(seed)
    default_dt, default_tmax, default_sample = bridge_amp_timebase(quick)
    dt = default_dt if dt is None else dt
    t_max = default_tmax if t_max is None else t_max
    sample_every = default_sample if sample_every is None else sample_every
    drive_until = 0.74 * t_max
    random_correction = float(rng.uniform(-config.max_allowed_correction, config.max_allowed_correction))

    correction = 0.0
    effective = bridge_min_nudge_effective_bridge(config.base_config, correction)
    initial_effective = effective
    omega = 2.0 * np.pi * base_hz * np.asarray(effective.mode_freqs, dtype=float)
    zeta = np.asarray([0.018 * effective.stage_a_damping, 0.012 * effective.stage_b_damping, 0.008 * effective.receiver_damping])

    y = np.zeros(6)
    y[:3] = 1e-4 * rng.normal(size=3)
    y[3:] = 1e-4 * rng.normal(size=3)
    initial_potentials = bridge_amp_potentials(y[:3], y[3:], omega, effective)
    initial_total = float(initial_potentials["total"])
    drive_work = 0.0
    positive_input_work = 0.0
    damping_loss = 0.0
    magnetic_loss = 0.0
    spark_loss = 0.0
    correction_work_signed = 0.0
    correction_work_abs = 0.0
    correction_energy_in = 0.0
    correction_energy_out = 0.0

    times: List[float] = []
    qs: List[np.ndarray] = []
    vs: List[np.ndarray] = []
    energies: List[np.ndarray] = []
    corrections: List[float] = []
    receiver_trace: List[float] = []
    stage_b_trace: List[float] = []
    magnetic_bias_trace: List[float] = []
    ledger: List[Dict[str, float | str]] = []

    n_steps = int(t_max / dt)
    for step in range(n_steps):
        t = step * dt
        q = y[:3]
        v = y[3:]
        next_correction = float(np.clip(
            bridge_control_authority_correction(config, t, t_max, random_correction),
            -config.max_allowed_correction,
            config.max_allowed_correction,
        ))
        if abs(next_correction - correction) > 1e-15:
            before = bridge_amp_potentials(q, v, omega, effective)
            next_effective = bridge_min_nudge_effective_bridge(config.base_config, next_correction)
            next_omega = 2.0 * np.pi * base_hz * np.asarray(next_effective.mode_freqs, dtype=float)
            after_param = bridge_amp_potentials(q, v, next_omega, next_effective)
            delta_work = float(after_param["total"] - before["total"])
            correction_work_signed += delta_work
            correction_work_abs += abs(delta_work)
            correction_energy_in += max(0.0, delta_work)
            correction_energy_out += max(0.0, -delta_work)
            correction = next_correction
            effective = next_effective
            omega = next_omega
            zeta = np.asarray([0.018 * effective.stage_a_damping, 0.012 * effective.stage_b_damping, 0.008 * effective.receiver_damping])

        drive_forces = bridge_amp_drive_forces(effective, t, base_hz, drive_until, 3)
        drive_power = float(np.dot(drive_forces, v))
        drive_work += drive_power * dt
        positive_input_work += max(0.0, drive_power) * dt
        damping_loss += float(np.sum(2.0 * zeta * omega * (v ** 2))) * dt
        if effective.spark_strength:
            for i, j in ((0, 1), (1, 2)):
                gate = float(spark_gate(q[i] - q[j], threshold=effective.spark_threshold))
                c = 0.030 * effective.spark_strength * gate
                spark_loss += float(c * ((v[i] - v[j]) ** 2)) * dt

        y_next = rk4_step(y, t, dt, bridge_amp_derivative, omega, effective, base_hz, drive_until, zeta)
        qn = y_next[:3]
        vn = y_next[3:]
        after = bridge_amp_potentials(qn, vn, omega, effective)
        y = y_next
        if not np.all(np.isfinite(y)) or np.max(np.abs(y)) > 1e6:
            break

        if step % sample_every == 0:
            modal = clean_modal_energy(qn, vn, omega)
            total_accounted = initial_total + drive_work + correction_work_signed - damping_loss - spark_loss
            error_abs = float(after["total"]) - total_accounted
            error_rel = abs(error_abs) / (abs(float(after["total"])) + abs(total_accounted) + 1e-18)
            now = float(t + dt)
            times.append(now)
            qs.append(qn.copy())
            vs.append(vn.copy())
            energies.append(modal)
            corrections.append(correction)
            receiver_trace.append(float(effective.mode_freqs[2]))
            stage_b_trace.append(float(effective.mode_freqs[1]))
            magnetic_bias_trace.append(float(config.base_config.magnetic_config.magnetic_bias_field + (config.base_config.magnetic_bias_strength * correction if config.correction_type == "magnetic_bias_nudge" else 0.0)))
            ledger.append({
                "case": config.name,
                "time": now,
                "correction_type": config.correction_type,
                "schedule_type": config.schedule_type,
                "correction_size": config.correction_size,
                "correction_value": correction,
                "receiver_tuning": float(effective.mode_freqs[2]),
                "stage_B_tuning": float(effective.mode_freqs[1]),
                "magnetic_bias_field": magnetic_bias_trace[-1],
                "energy_at_3_mode": float(modal[0]),
                "energy_at_6_mode": float(modal[1]),
                "energy_at_9_mode": float(modal[2]),
                "total_stored_energy": float(after["total"]),
                "drive_input_work": drive_work,
                "positive_input_work": positive_input_work,
                "damping_loss": damping_loss,
                "spark_loss": spark_loss,
                "correction_work_signed": correction_work_signed,
                "correction_work": correction_work_abs,
                "correction_energy_in": correction_energy_in,
                "correction_energy_out": correction_energy_out,
                "total_accounted_energy": total_accounted,
                "energy_budget_error_abs": error_abs,
                "energy_budget_error_rel": error_rel,
            })

    correction_arr = np.asarray(corrections)
    sim: Dict[str, object] = {
        "times": np.asarray(times),
        "qs": np.asarray(qs),
        "vs": np.asarray(vs),
        "energy": np.asarray(energies),
        "omega": omega,
        "drive_until": drive_until,
        "dt_sample": dt * sample_every,
        "positive_input_work": positive_input_work,
        "net_input_work": drive_work,
        "damping_loss": damping_loss,
        "spark_loss": spark_loss,
        "correction_work_signed": correction_work_signed,
        "correction_work": correction_work_abs,
        "correction_energy_in": correction_energy_in,
        "correction_energy_out": correction_energy_out,
        "correction_rms": float(np.sqrt(np.mean(correction_arr ** 2))) if len(correction_arr) else 0.0,
        "correction_peak": float(np.max(np.abs(correction_arr))) if len(correction_arr) else 0.0,
        "correction_mean_abs": float(np.mean(np.abs(correction_arr))) if len(correction_arr) else 0.0,
        "correction_final": float(correction_arr[-1]) if len(correction_arr) else 0.0,
        "energy_budget_error_rel": float(ledger[-1]["energy_budget_error_rel"]) if ledger else 1.0,
        "max_energy_budget_error_rel": max((float(r["energy_budget_error_rel"]) for r in ledger), default=1.0),
        "effective_config": effective,
        "initial_effective_config": initial_effective,
        "receiver_tuning_trace": np.asarray(receiver_trace),
        "stage_b_tuning_trace": np.asarray(stage_b_trace),
        "magnetic_bias_trace": np.asarray(magnetic_bias_trace),
    }
    return sim, ledger


def bridge_control_authority_seed_templates(quick: bool, include_sweeps: bool) -> List[Tuple[str, str, BridgeMinNudgeConfig]]:
    seeds = [
        ("receiver_best_4x_raw", "receiver_tuning_nudge", bridge_control_authority_template("receiver_tuning_nudge", "receiver_best_4x_raw", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.84)),
        ("magnetic_best_low_work", "magnetic_bias_nudge", bridge_control_authority_template("magnetic_bias_nudge", "magnetic_best_low_work", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.84)),
        ("stageB_best_budget_clean", "stage_B_detuning_nudge", bridge_control_authority_template("stage_B_detuning_nudge", "stageB_best_budget_clean", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.84)),
        ("autolock_seed_s0p9", "receiver_tuning_nudge", bridge_control_authority_template("receiver_tuning_nudge", "autolock_seed_s0p9", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.90)),
        ("magnetic_stageB0p84_lead", "magnetic_bias_nudge", bridge_control_authority_template("magnetic_bias_nudge", "magnetic_stageB0p84_lead", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.84)),
    ]
    if include_sweeps:
        for ctype in ["receiver_tuning_nudge", "magnetic_bias_nudge", "stage_B_detuning_nudge"]:
            for receiver in ([8.86, 8.90, 8.93] if quick else [8.86, 8.875, 8.90, 8.915, 8.93]):
                seeds.append((f"sweep_receiver_{safe_token(receiver)}", ctype, bridge_control_authority_template(ctype, f"sweep_receiver_{safe_token(receiver)}", receiver_tuning=receiver, phase_bias=30.0, stage_b_strength=0.84)))
            for phase in ([15.0, 25.0, 35.0] if quick else [15.0, 20.0, 25.0, 30.0, 35.0]):
                seeds.append((f"sweep_phase_{safe_token(phase)}", ctype, bridge_control_authority_template(ctype, f"sweep_phase_{safe_token(phase)}", receiver_tuning=8.90, phase_bias=phase, stage_b_strength=0.84)))
    return seeds


def bridge_control_authority_specs(quick: bool, include_sweeps: bool) -> List[Tuple[str, str, BridgeControlAuthorityConfig]]:
    tests = [
        ("negative_small_step", -0.004, "step", 0.12),
        ("positive_small_step", 0.004, "step", 0.12),
        ("medium_step", 0.012, "step", 0.18),
        ("large_step", 0.024, "step", 0.20),
        ("slow_ramp", 0.018, "slow_ramp", 0.34),
        ("hold_after_ramp", 0.012, "hold_after_ramp", 0.18),
    ]
    if include_sweeps:
        tests.extend([
            ("negative_medium_step", -0.012, "step", 0.18),
            ("negative_large_step", -0.024, "step", 0.20),
            ("extra_large_plausible_step", 0.036, "step", 0.20),
        ])
    specs: List[Tuple[str, str, BridgeControlAuthorityConfig]] = []
    for seed_family, ctype, template in bridge_control_authority_seed_templates(quick, include_sweeps):
        max_allowed = 0.036 if include_sweeps else 0.024
        for test_name, correction, schedule, ramp_fraction in tests:
            if template.correction_type != ctype:
                template = replace(template, correction_type=ctype)
            name = f"authority_{seed_family}_{ctype}_{test_name}_{safe_token(correction)}"
            specs.append((
                test_name,
                seed_family,
                BridgeControlAuthorityConfig(
                    name=name,
                    correction_type=ctype,
                    base_config=template,
                    correction_size=correction,
                    schedule_type=schedule,
                    ramp_fraction=ramp_fraction,
                    max_allowed_correction=max_allowed,
                    seed_family=seed_family,
                    reference_role="discovery_candidate",
                    family="369",
                    note="open-loop actuator authority test",
                ),
            ))
    return specs


def bridge_control_authority_control_specs(include_sweeps: bool) -> List[Tuple[str, str, BridgeControlAuthorityConfig]]:
    control_types = ["receiver_tuning_nudge", "magnetic_bias_nudge", "stage_B_detuning_nudge"] if include_sweeps else ["receiver_tuning_nudge"]
    specs: List[Tuple[str, str, BridgeControlAuthorityConfig]] = []
    for ctype in control_types:
        template = bridge_control_authority_template(ctype, "control_baseline", reference_role="control")
        for name, correction, schedule in [
            ("no_correction", 0.0, "no_correction"),
            ("wrong_sign_correction", -0.012, "step"),
            ("random_correction", 0.012, "random_correction"),
        ]:
            specs.append((
                name,
                ctype,
                BridgeControlAuthorityConfig(
                    name=f"authority_control_{ctype}_{name}",
                    correction_type=ctype,
                    base_config=template,
                    correction_size=correction,
                    schedule_type=schedule,
                    seed_family="control_baseline",
                    reference_role="control",
                    family="369",
                    note="control authority negative/random/no-correction control",
                ),
            ))
    for source, target in ((4.0, 12.0), (5.0, 15.0)):
        for ctype in control_types:
            template = BridgeMinNudgeConfig(
                name=f"authority_non369_template_{safe_token(source)}_{safe_token(target)}_{ctype}",
                correction_type=ctype,
                magnetic_config=bridge_min_nudge_non369_seed(source, target),
                kp=0.0,
                correction_clamp=0.0,
                update_interval=1.0,
                smoothing=1.0,
                magnetic_bias_strength=2.0,
                control_mode="no_nudge",
                reference_role="control",
                family="non369",
                note="non-369 authority template",
            )
            specs.append((
                f"non369_{safe_token(source)}_{safe_token(target)}",
                ctype,
                BridgeControlAuthorityConfig(
                    name=f"authority_non369_{safe_token(source)}_{safe_token(target)}_{ctype}",
                    correction_type=ctype,
                    base_config=template,
                    correction_size=0.012,
                    schedule_type="step",
                    seed_family=f"non369_{safe_token(source)}_{safe_token(target)}",
                    reference_role="control",
                    family="non369",
                    note="non-369 bridge authority control",
                ),
            ))
    return specs


def bridge_control_authority_measure(config: BridgeControlAuthorityConfig, seed: int, quick: bool,
                                     dt: float, runtime: float, sample_every: int,
                                     direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]]
                                     ) -> Tuple[Dict[str, float | str], List[Dict[str, float | str]], List[Dict[str, float | str]]]:
    sim, ledger = simulate_bridge_control_authority(config, seed, quick, dt=dt, t_max=runtime, sample_every=sample_every)
    effective = sim["effective_config"]  # type: ignore[assignment]
    initial_effective = sim["initial_effective_config"]  # type: ignore[assignment]
    target_key = f"{effective.mode_freqs[0]:g}:{effective.target_6:g}:{effective.target_9:g}"
    cache_key = (target_key, dt, runtime)
    if cache_key not in direct_cache:
        direct_cfg = bridge_min_nudge_direct_reference(effective)
        direct_sim, _ = simulate_bridge_amp(direct_cfg, seed + 8300, quick, dt=dt, t_max=runtime, sample_every=sample_every)
        direct_row = bridge_metrics_window(direct_cfg, direct_sim, seed + 8300, "direct_reference", "direct_source_plus_generated", "reference", 0.35, 1.0)
        direct_cache[cache_key] = (direct_sim, direct_row)
    direct_sim, direct_row = direct_cache[cache_key]

    row = bridge_metrics_window(effective, sim, seed, "authority", config.schedule_type, f"{config.correction_size:g}", 0.35, 1.0)
    before_rows, before_summary = bridge_phase_diagnostic_series(initial_effective, sim, direct_sim, 0.10, 0.32)
    after_rows, after_summary = bridge_phase_diagnostic_series(effective, sim, direct_sim, 0.62, 1.0)
    drift_rows = before_rows + after_rows

    correction_abs = abs(config.correction_size)
    before_drift = float(before_summary.get("phase_drift_rate", 0.0))
    after_drift = float(after_summary.get("phase_drift_rate", 0.0))
    before_freq = float(before_summary.get("effective_target_frequency", effective.target_9))
    after_freq = float(after_summary.get("effective_target_frequency", effective.target_9))
    actuator_gain = (after_drift - before_drift) / config.correction_size if abs(config.correction_size) > 1e-12 else 0.0
    frequency_pull = (after_freq - before_freq) / config.correction_size if abs(config.correction_size) > 1e-12 else 0.0

    row.update(after_summary)
    row["experiment"] = "bridge_control_authority"
    row["case"] = config.name
    row["candidate_id"] = f"{config.name}:4x"
    row["correction_type"] = config.correction_type
    row["actuator_type"] = config.correction_type
    row["schedule_type"] = config.schedule_type
    row["correction_size"] = config.correction_size
    row["max_allowed_correction"] = config.max_allowed_correction
    row["seed_family"] = config.seed_family
    row["reference_role"] = config.reference_role
    row["family"] = config.family
    row["runtime_factor"] = 4.0
    row["bridge_ratio"] = metric_ratio(float(row.get("energy_at_9", 0.0)), float(direct_row.get("energy_at_9", 0.0)))
    row["generated_vs_direct_bridge_ratio"] = row["bridge_ratio"]
    row["energy_at_9_from_direct_3_plus_6_reference"] = direct_row.get("energy_at_9", 0.0)
    total_input_before = max(float(row.get("total_input_work", 0.0)), 1e-18)
    total_input_with_correction = total_input_before + float(sim["correction_work"])
    row["total_input_work_before_correction"] = total_input_before
    row["total_input_work"] = total_input_with_correction
    row["correction_work"] = float(sim["correction_work"])
    row["correction_work_signed"] = float(sim["correction_work_signed"])
    row["correction_work_fraction"] = metric_ratio(float(sim["correction_work"]), total_input_with_correction)
    row["correction_rms"] = float(sim["correction_rms"])
    row["correction_peak"] = float(sim["correction_peak"])
    row["effective_generated_frequency_before_correction"] = before_freq
    row["effective_generated_frequency_after_correction"] = after_freq
    row["phase_drift_rate_before_correction"] = before_drift
    row["phase_drift_rate_after_correction"] = after_drift
    row["actuator_gain"] = actuator_gain
    row["frequency_pull_per_unit_correction"] = frequency_pull
    row["observed_uncorrected_drift_rate"] = 0.0
    row["required_correction_to_cancel_drift"] = 0.0
    row["estimated_work_for_required_correction"] = 0.0
    row["actuator_authority_margin"] = float("inf")
    row["drift_reduction_fraction"] = 0.0
    row["phase_lock_improvement_vs_baseline"] = 0.0
    row["no_direct_6_drive"] = str(not any(abs(freq - effective.target_6) < 1e-9 and mode == 1 for freq, mode in zip(effective.drive_freqs, effective.drive_modes)))
    row["no_direct_9_drive"] = str(not any(abs(freq - effective.target_9) < 1e-9 and mode == 2 for freq, mode in zip(effective.drive_freqs, effective.drive_modes)))
    row["note"] = config.note

    for item in ledger:
        item["experiment"] = "bridge_control_authority"
        item["candidate_id"] = row["candidate_id"]
        item["seed_family"] = config.seed_family
    for item in drift_rows:
        item["experiment"] = "bridge_control_authority"
        item["case"] = config.name
        item["candidate_id"] = row["candidate_id"]
        item["seed_family"] = config.seed_family
        item["correction_type"] = config.correction_type
        item["schedule_type"] = config.schedule_type
    return row, ledger, drift_rows


def bridge_control_authority_annotate(rows: List[Dict[str, float | str]]) -> None:
    baselines: Dict[Tuple[str, str], Dict[str, float | str]] = {}
    for row in rows:
        if str(row.get("schedule_type")) == "no_correction":
            baselines[(str(row.get("family")), str(row.get("seed_family")))] = row
    fallback_baselines: Dict[str, Dict[str, float | str]] = {}
    for row in rows:
        if str(row.get("schedule_type")) == "no_correction":
            fallback_baselines[str(row.get("family"))] = row

    for row in rows:
        baseline = baselines.get((str(row.get("family")), str(row.get("seed_family"))), fallback_baselines.get(str(row.get("family")), {}))
        observed = float(baseline.get("phase_drift_rate_after_correction", row.get("phase_drift_rate_before_correction", 0.0)))
        baseline_phase = float(baseline.get("phase_lock_9", 0.0))
        after_drift = float(row.get("phase_drift_rate_after_correction", 0.0))
        gain = float(row.get("actuator_gain", 0.0))
        correction_size = float(row.get("correction_size", 0.0))
        if abs(gain) > 1e-12:
            required = -observed / gain
        else:
            required = float("inf")
        if math.isfinite(required) and abs(correction_size) > 1e-12:
            work_scale = abs(required) / abs(correction_size)
            estimated_work = float(row.get("correction_work_fraction", 0.0)) * work_scale
        else:
            estimated_work = float("inf")
        max_allowed = max(abs(float(row.get("max_allowed_correction", 0.0))), 1e-18)
        margin = abs(required) / max_allowed if math.isfinite(required) else float("inf")
        drift_reduction = metric_ratio(abs(observed) - abs(after_drift), abs(observed)) if abs(observed) > 1e-12 else 0.0

        row["observed_uncorrected_drift_rate"] = observed
        row["required_correction_to_cancel_drift"] = required
        row["estimated_work_for_required_correction"] = estimated_work
        row["actuator_authority_margin"] = margin
        row["drift_reduction_fraction"] = drift_reduction
        row["phase_lock_improvement_vs_baseline"] = float(row.get("phase_lock_9", 0.0)) - baseline_phase
        bridge_control_authority_update_score(row)


def bridge_control_authority_update_score(row: Dict[str, float | str]) -> None:
    drift_reduction = float(row.get("drift_reduction_fraction", 0.0))
    estimated_work = float(row.get("estimated_work_for_required_correction", float("inf")))
    budget = float(row.get("energy_budget_error", 1.0))
    bridge_ratio = float(row.get("bridge_ratio", 0.0))
    purity = float(row.get("spectral_purity_9", 0.0))
    passed = (
        drift_reduction >= 0.50
        and estimated_work < 0.05
        and budget < 0.005
        and bridge_ratio > 0.75
        and purity > 0.60
        and str(row.get("reference_role")) == "discovery_candidate"
        and str(row.get("no_direct_6_drive", "False")) == "True"
        and str(row.get("no_direct_9_drive", "False")) == "True"
    )
    observed = float(row.get("observed_uncorrected_drift_rate", 0.0))
    after = float(row.get("phase_drift_rate_after_correction", 0.0))
    cancel_or_reverse = abs(after) < 0.10 * max(abs(observed), 1e-12) or (observed * after < 0.0)
    strong = (
        passed
        and cancel_or_reverse
        and estimated_work < 0.02
        and bridge_ratio > 0.85
        and float(row.get("phase_lock_improvement_vs_baseline", 0.0)) > 0.0
        and str(row.get("half_dt_gain_preserved", "False")) == "True"
        and str(row.get("quarter_dt_gain_preserved", "False")) == "True"
    )
    failures = []
    if drift_reduction < 0.50:
        failures.append("weak_drift_reduction")
    if estimated_work >= 0.05:
        failures.append("required_work")
    if budget >= 0.005:
        failures.append("energy_budget")
    if bridge_ratio <= 0.75:
        failures.append("bridge_ratio")
    if purity <= 0.60:
        failures.append("spectral_purity_9")
    if str(row.get("no_direct_6_drive", "False")) != "True" or str(row.get("no_direct_9_drive", "False")) != "True":
        failures.append("direct_drive_contamination")
    if not failures:
        failure_mode = "sufficient_authority"
    elif "weak_drift_reduction" in failures:
        failure_mode = "insufficient_authority"
    elif "energy_budget" in failures:
        failure_mode = "energy_budget_drift"
    elif "required_work" in failures:
        failure_mode = "overpowered_correction"
    else:
        failure_mode = failures[0]
    score = (
        max(0.0, drift_reduction)
        * bridge_ratio
        * purity
        * max(0.0, float(row.get("phase_lock_9", 0.0)))
        / (
            1.0
            + 120.0 * max(0.0, estimated_work if math.isfinite(estimated_work) else 1.0)
            + 400.0 * max(0.0, budget)
        )
    )
    if not passed:
        score = 0.0
    row["passed"] = str(passed)
    row["strong_passed"] = str(strong)
    row["promotion_ready"] = str(strong)
    row["failed_gate_names"] = ";".join(failures)
    row["failure_mode"] = failure_mode
    row["bridge_control_authority_score"] = score
    row["score"] = score


def bridge_control_authority_validation(config: BridgeControlAuthorityConfig, seed: int, quick: bool,
                                        dt: float, runtime: float, sample_every: int
                                        ) -> Tuple[List[Dict[str, float | str]], List[Dict[str, float | str]], List[Dict[str, float | str]]]:
    tests = [("baseline_dt", dt), ("half_dt", dt * 0.5), ("quarter_dt", dt * 0.25)]
    rows: List[Dict[str, float | str]] = []
    ledger_rows: List[Dict[str, float | str]] = []
    drift_rows: List[Dict[str, float | str]] = []
    for idx, (name, test_dt) in enumerate(tests):
        direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]] = {}
        row, ledger, drift = bridge_control_authority_measure(config, seed + idx * 131, quick, test_dt, runtime, sample_every, direct_cache)
        row["validation_test"] = name
        rows.append(row)
        ledger_rows.extend(ledger)
        drift_rows.extend(drift)
    bridge_control_authority_annotate(rows)
    return rows, ledger_rows, drift_rows


def apply_bridge_control_authority_validation_status(candidate: Dict[str, float | str],
                                                     validation_rows: List[Dict[str, float | str]]) -> None:
    rows = [r for r in validation_rows if str(r.get("case")) == str(candidate.get("case"))]
    base = next((r for r in rows if str(r.get("validation_test")) == "baseline_dt"), {})
    half = next((r for r in rows if str(r.get("validation_test")) == "half_dt"), {})
    quarter = next((r for r in rows if str(r.get("validation_test")) == "quarter_dt"), {})
    base_gain = float(base.get("actuator_gain", candidate.get("actuator_gain", 0.0)))
    half_gain = float(half.get("actuator_gain", 0.0))
    quarter_gain = float(quarter.get("actuator_gain", 0.0))
    half_ok = ratio_stability_score(half_gain, base_gain) > 0.50 and (half_gain * base_gain >= 0.0)
    quarter_ok = ratio_stability_score(quarter_gain, base_gain) > 0.50 and (quarter_gain * base_gain >= 0.0)
    candidate["half_dt_gain_preserved"] = str(half_ok)
    candidate["quarter_dt_gain_preserved"] = str(quarter_ok)
    candidate["half_dt_actuator_gain"] = half_gain
    candidate["quarter_dt_actuator_gain"] = quarter_gain
    bridge_control_authority_update_score(candidate)


def plot_bridge_control_authority_outputs(out_dir: Path, rows: List[Dict[str, float | str]]) -> None:
    plot_rows = [r for r in rows if str(r.get("reference_role")) == "discovery_candidate"]
    if not plot_rows:
        return

    def values(key: str) -> List[float]:
        return [float(r.get(key, 0.0)) for r in plot_rows]

    colors = [{"receiver_tuning_nudge": 0.2, "magnetic_bias_nudge": 0.55, "stage_B_detuning_nudge": 0.85}.get(str(r.get("correction_type")), 0.0) for r in plot_rows]
    fig, ax = plt.subplots(figsize=(8.6, 5.0))
    ax.scatter(values("correction_size"), values("phase_drift_rate_after_correction"), c=colors)
    ax.axhline(0.0, color="tab:gray", linewidth=1.0)
    ax.set_title("correction size vs phase drift rate")
    ax.set_xlabel("correction size")
    ax.set_ylabel("phase drift rate after correction")
    fig.tight_layout()
    fig.savefig(out_dir / "bridge_control_authority_correction_vs_drift.png", dpi=140)
    plt.close(fig)

    fig, ax = plt.subplots(figsize=(8.6, 5.0))
    ax.scatter(values("correction_size"), values("effective_generated_frequency_after_correction"), c=colors)
    ax.set_title("correction size vs effective generated frequency")
    ax.set_xlabel("correction size")
    ax.set_ylabel("effective generated frequency")
    fig.tight_layout()
    fig.savefig(out_dir / "bridge_control_authority_correction_vs_frequency.png", dpi=140)
    plt.close(fig)

    fig, ax = plt.subplots(figsize=(8.6, 5.0))
    ax.scatter(values("correction_work_fraction"), values("drift_reduction_fraction"), c=colors)
    ax.axhline(0.50, color="tab:red", linestyle="--", linewidth=1.0)
    ax.set_title("correction work fraction vs drift reduction")
    ax.set_xlabel("correction work fraction")
    ax.set_ylabel("drift reduction fraction")
    fig.tight_layout()
    fig.savefig(out_dir / "bridge_control_authority_work_vs_reduction.png", dpi=140)
    plt.close(fig)

    best_by_type: List[Dict[str, float | str]] = []
    for ctype in ["receiver_tuning_nudge", "magnetic_bias_nudge", "stage_B_detuning_nudge"]:
        typed = [r for r in plot_rows if str(r.get("correction_type")) == ctype]
        if typed:
            best_by_type.append(max(typed, key=lambda r: float(r.get("drift_reduction_fraction", 0.0))))
    if best_by_type:
        fig, ax = plt.subplots(figsize=(8.6, 5.0))
        labels = [str(r.get("correction_type", "")).replace("_nudge", "") for r in best_by_type]
        ax.bar(np.arange(len(labels)), [float(r.get("actuator_authority_margin", 0.0)) for r in best_by_type])
        ax.axhline(1.0, color="tab:red", linestyle="--", linewidth=1.0)
        ax.set_xticks(np.arange(len(labels)))
        ax.set_xticklabels(labels, rotation=20, ha="right")
        ax.set_title("actuator authority comparison")
        ax.set_ylabel("required correction / max allowed")
        fig.tight_layout()
        fig.savefig(out_dir / "bridge_control_authority_comparison.png", dpi=140)
        plt.close(fig)

        fig, ax = plt.subplots(figsize=(8.6, 5.0))
        x = np.arange(len(labels))
        ax.bar(x - 0.18, [float(r.get("phase_lock_9", 0.0)) - float(r.get("phase_lock_improvement_vs_baseline", 0.0)) for r in best_by_type], width=0.36, label="baseline")
        ax.bar(x + 0.18, [float(r.get("phase_lock_9", 0.0)) for r in best_by_type], width=0.36, label="corrected")
        ax.axhline(0.90, color="tab:red", linestyle="--", linewidth=1.0)
        ax.set_xticks(x)
        ax.set_xticklabels(labels, rotation=20, ha="right")
        ax.set_title("4x phase lock before/after correction")
        ax.set_ylabel("phase_lock_9")
        ax.legend()
        fig.tight_layout()
        fig.savefig(out_dir / "bridge_control_authority_phase_lock_before_after.png", dpi=140)
        plt.close(fig)

    fig, ax = plt.subplots(figsize=(8.6, 5.0))
    ax.scatter(values("correction_size"), values("energy_budget_error"), c=colors)
    ax.axhline(0.005, color="tab:red", linestyle="--", linewidth=1.0)
    ax.set_title("energy budget vs correction size")
    ax.set_xlabel("correction size")
    ax.set_ylabel("energy budget error")
    fig.tight_layout()
    fig.savefig(out_dir / "bridge_control_authority_energy_budget_vs_correction.png", dpi=140)
    plt.close(fig)


def write_bridge_control_authority_report(out_dir: Path, ranked: List[Dict[str, float | str]],
                                          validation_rows: List[Dict[str, float | str]],
                                          controls: List[Dict[str, float | str]]) -> None:
    discovery = [r for r in ranked if str(r.get("reference_role")) == "discovery_candidate"]
    best = discovery[0] if discovery else {}
    by_type: Dict[str, Dict[str, float | str]] = {}
    for ctype in ["receiver_tuning_nudge", "magnetic_bias_nudge", "stage_B_detuning_nudge"]:
        typed = [r for r in discovery if str(r.get("correction_type")) == ctype]
        if typed:
            by_type[ctype] = max(typed, key=lambda r: (float(r.get("bridge_control_authority_score", 0.0)), float(r.get("drift_reduction_fraction", 0.0))))
    no_correction = max([r for r in controls if str(r.get("schedule_type")) == "no_correction"], key=lambda r: float(r.get("phase_lock_9", 0.0)), default={})
    wrong = max([r for r in controls if str(r.get("schedule_type")) == "step" and "wrong_sign" in str(r.get("case", ""))], key=lambda r: float(r.get("phase_lock_9", 0.0)), default={})
    random_control = max([r for r in controls if str(r.get("schedule_type")) == "random_correction"], key=lambda r: float(r.get("phase_lock_9", 0.0)), default={})
    non369 = max([r for r in controls if str(r.get("family")) == "non369"], key=lambda r: float(r.get("drift_reduction_fraction", 0.0)), default={})
    passed_rows = [r for r in discovery if str(r.get("passed")) == "True"]
    small_signal_rows = [
        r for r in discovery
        if float(r.get("actuator_authority_margin", float("inf"))) < 1.0
        and float(r.get("estimated_work_for_required_correction", float("inf"))) < 0.05
        and float(r.get("energy_budget_error", 1.0)) < 0.005
        and float(r.get("drift_reduction_fraction", 0.0)) > 0.0
    ]
    has_small_signal_authority = bool(small_signal_rows)
    max_reduction = max([float(r.get("drift_reduction_fraction", 0.0)) for r in discovery], default=0.0)
    if passed_rows:
        nudge_answer = "sufficient in the tested range"
        plausible_answer = "yes under the promotion gates; still needs closed-loop follow-up"
        next_answer = "frequency-drift feedforward or stronger proportional control"
    elif has_small_signal_authority:
        nudge_answer = "too weak in the tested open-loop steps; small-signal pull exists, so the variable is still worth a feedforward/closed-loop test"
        plausible_answer = f"not proven by open-loop gates; best measured drift reduction was {max_reduction:.6g}, below the 0.5 promotion gate"
        next_answer = "frequency-drift feedforward, then stronger proportional control; move to a real PLL only if those fail"
    else:
        nudge_answer = "insufficient authority in the tested range or controlling the wrong variable"
        plausible_answer = "not proven by open-loop authority in this run"
        next_answer = "real PLL/self-lock or rethink active control; open-loop authority is not enough yet"
    lines = [
        "# Bridge Control Authority Report",
        "",
        "This mode measures open-loop actuator authority for the clean staged bridge. It uses no direct 6 drive, no direct 9 drive, and no target-frequency injection.",
        "",
        "## Direct Answers",
        f"1. Best 4x phase-drift control actuator: {best.get('correction_type', 'none')}; drift_reduction={float(best.get('drift_reduction_fraction', 0.0)):.6g}, authority_margin={float(best.get('actuator_authority_margin', 0.0)):.6g}.",
        f"2. Previous nudges too weak or wrong variable? {nudge_answer}; receiver_margin={float(by_type.get('receiver_tuning_nudge', {}).get('actuator_authority_margin', 0.0)):.6g}, magnetic_margin={float(by_type.get('magnetic_bias_nudge', {}).get('actuator_authority_margin', 0.0)):.6g}, stageB_margin={float(by_type.get('stage_B_detuning_nudge', {}).get('actuator_authority_margin', 0.0)):.6g}.",
        f"3. Estimated correction to cancel observed drift: {float(best.get('required_correction_to_cancel_drift', 0.0)):.6g}; observed_drift={float(best.get('observed_uncorrected_drift_rate', 0.0)):.6g}, gain={float(best.get('actuator_gain', 0.0)):.6g}.",
        f"4. Estimated work required: {float(best.get('estimated_work_for_required_correction', 0.0)):.6g}; measured_work_fraction={float(best.get('correction_work_fraction', 0.0)):.6g}.",
        f"5. Is 4x lock physically plausible with these actuators? {plausible_answer}.",
        f"6. Next step: {next_answer}.",
        f"Controls: no_correction_phase={float(no_correction.get('phase_lock_9', 0.0)):.6g}, wrong_sign_phase={float(wrong.get('phase_lock_9', 0.0)):.6g}, random_phase={float(random_control.get('phase_lock_9', 0.0)):.6g}, best_non369_reduction={float(non369.get('drift_reduction_fraction', 0.0)):.6g}.",
        f"Promotion gate: {len(passed_rows)} discovery rows passed; {len(small_signal_rows)} rows had sub-unit small-signal authority margin without passing the 50% drift-reduction gate.",
        "",
        "## Top Rows",
    ]
    for row in ranked[:24]:
        lines.append(
            f"- {row.get('candidate_id')}: actuator={row.get('correction_type')}, schedule={row.get('schedule_type')}, size={float(row.get('correction_size', 0.0)):.6g}, "
            f"score={float(row.get('bridge_control_authority_score', 0.0)):.6g}, pass={row.get('passed')}, reduction={float(row.get('drift_reduction_fraction', 0.0)):.6g}, "
            f"gain={float(row.get('actuator_gain', 0.0)):.6g}, required={float(row.get('required_correction_to_cancel_drift', 0.0)):.6g}, "
            f"margin={float(row.get('actuator_authority_margin', 0.0)):.6g}, work_est={float(row.get('estimated_work_for_required_correction', 0.0)):.6g}, "
            f"phase={float(row.get('phase_lock_9', 0.0)):.6g}, budget={float(row.get('energy_budget_error', 0.0)):.6g}, failure={row.get('failure_mode', '')}"
        )
    if validation_rows:
        lines.extend(["", "## Gain Validation", "These rows check whether the measured actuator gain survives dt refinement; pass/fail still comes from the discovery-row promotion gates above."])
        for row in validation_rows[:20]:
            lines.append(
                f"- {row.get('candidate_id')}: test={row.get('validation_test', '')}, gain={float(row.get('actuator_gain', 0.0)):.6g}, "
                f"work={float(row.get('correction_work_fraction', 0.0)):.6g}, phase={float(row.get('phase_lock_9', 0.0)):.6g}, "
                f"budget={float(row.get('energy_budget_error', 0.0)):.6g}"
            )
    (out_dir / "README_BRIDGE_CONTROL_AUTHORITY_REPORT.md").write_text("\n".join(lines), encoding="utf-8")


def experiment_bridge_control_authority(out_dir: Path, seed: int, quick: bool = False,
                                        include_sweeps: bool = False) -> List[Dict[str, float | str]]:
    dt, base_tmax, sample_every = bridge_amp_timebase(quick)
    runtime = base_tmax * 1.25 * 4.0
    specs = bridge_control_authority_specs(quick, include_sweeps)
    control_specs = bridge_control_authority_control_specs(include_sweeps)

    summary_rows: List[Dict[str, float | str]] = []
    sweep_rows: List[Dict[str, float | str]] = []
    ledger_rows: List[Dict[str, float | str]] = []
    drift_rows: List[Dict[str, float | str]] = []
    controls: List[Dict[str, float | str]] = []
    direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]] = {}

    for idx, (sweep, value, config) in enumerate(specs + control_specs):
        row, ledger, drift = bridge_control_authority_measure(
            config,
            seed + idx * 239,
            quick,
            dt,
            runtime,
            sample_every,
            direct_cache,
        )
        row["sweep"] = sweep
        row["sweep_value"] = value
        summary_rows.append(row)
        if include_sweeps or str(config.reference_role) == "discovery_candidate":
            sweep_rows.append(row)
        if str(config.reference_role) == "control" or config.family == "non369":
            controls.append(row)
        if str(config.reference_role) == "control" or abs(float(row.get("correction_size", 0.0))) >= 0.012:
            ledger_rows.extend(ledger)
            drift_rows.extend(drift)

    bridge_control_authority_annotate(summary_rows)
    ranked = sorted(
        summary_rows,
        key=lambda r: (
            float(r.get("bridge_control_authority_score", 0.0)),
            1.0 if str(r.get("reference_role")) == "discovery_candidate" else 0.0,
            float(r.get("drift_reduction_fraction", 0.0)),
            -float(r.get("estimated_work_for_required_correction", 1.0)),
        ),
        reverse=True,
    )

    validation_rows: List[Dict[str, float | str]] = []
    top_candidates = [r for r in ranked if str(r.get("reference_role")) == "discovery_candidate"][:4 if include_sweeps else 2]
    for idx, candidate in enumerate(top_candidates):
        spec = next((item for item in specs if str(candidate.get("case")) == item[2].name), None)
        if spec is None:
            continue
        _, _, config = spec
        rows, ledger, drift = bridge_control_authority_validation(config, seed + 72000 + idx * 1000, quick, dt, runtime, sample_every)
        validation_rows.extend(rows)
        ledger_rows.extend(ledger)
        drift_rows.extend(drift)
        apply_bridge_control_authority_validation_status(candidate, validation_rows)

    ranked = sorted(
        summary_rows,
        key=lambda r: (
            float(r.get("bridge_control_authority_score", 0.0)),
            1.0 if str(r.get("reference_role")) == "discovery_candidate" else 0.0,
            float(r.get("drift_reduction_fraction", 0.0)),
            -float(r.get("estimated_work_for_required_correction", 1.0)),
        ),
        reverse=True,
    )

    write_csv(out_dir / "bridge_control_authority_summary.csv", summary_rows + validation_rows)
    write_csv(out_dir / "bridge_control_authority_ranked.csv", ranked)
    write_csv(out_dir / "bridge_control_authority_sweeps.csv", sweep_rows)
    write_csv(out_dir / "bridge_control_authority_timeseries.csv", ledger_rows + drift_rows)
    plot_bridge_control_authority_outputs(out_dir, summary_rows)
    write_bridge_control_authority_report(out_dir, ranked, validation_rows, controls)

    return [
        {
            "experiment": "bridge_control_authority",
            "case": row.get("case", ""),
            "freqs": row.get("freqs", ""),
            "score": row.get("bridge_control_authority_score", 0.0),
            "passed": row.get("passed", "False"),
            "promotion_ready": row.get("promotion_ready", "False"),
            "correction_type": row.get("correction_type", ""),
            "drift_reduction_fraction": row.get("drift_reduction_fraction", 0.0),
            "actuator_authority_margin": row.get("actuator_authority_margin", 0.0),
            "required_correction_to_cancel_drift": row.get("required_correction_to_cancel_drift", 0.0),
            "estimated_work_for_required_correction": row.get("estimated_work_for_required_correction", 0.0),
            "phase_lock_9": row.get("phase_lock_9", 0.0),
            "energy_budget_error": row.get("energy_budget_error", 0.0),
            "failure_mode": row.get("failure_mode", ""),
            "note": row.get("note", ""),
        }
        for row in ranked[:20]
    ]


# ----------------------------
# Experiment 19: bridge drift feedforward
# ----------------------------

@dataclass
class BridgeDriftFeedforwardConfig:
    name: str
    ramp_type: str
    correction_type: str
    base_config: BridgeMinNudgeConfig
    ramp_size: float
    ramp_shape: str
    ramp_start_fraction: float = 0.18
    ramp_end_fraction: float = 0.74
    correction_clamp: float = 0.024
    authority_gain_prior: float = 0.0
    estimated_required_ramp_size: float = 0.0
    runtime_factor: float = 4.0
    seed_family: str = "base"
    reference_role: str = "discovery_candidate"
    family: str = "369"
    control_role: str = "feedforward"
    note: str = ""


BRIDGE_DRIFT_FEEDFORWARD_ACTUATORS = {
    "receiver_tuning_ramp": ("receiver_tuning_nudge", -19.31761912417351),
    "stage_B_detuning_ramp": ("stage_B_detuning_nudge", 6.240033006222204),
    "magnetic_bias_ramp": ("magnetic_bias_nudge", 6.590793278913237),
}


def bridge_drift_feedforward_signed_drift(summary: Dict[str, float | str]) -> float:
    drift = float(summary.get("phase_drift_rate", 0.0))
    direction = str(summary.get("drift_direction", "flat"))
    if direction == "negative":
        return -drift
    if direction == "positive":
        return drift
    return 0.0


def bridge_drift_feedforward_template(seed_family: str,
                                      receiver_tuning: float = 8.90,
                                      phase_bias: float = 30.0,
                                      stage_b_strength: float = 0.84,
                                      stage_b_detuning: float = 0.0,
                                      magnetic_bias_strength: float = 2.0,
                                      reference_role: str = "discovery_candidate",
                                      family: str = "369") -> BridgeMinNudgeConfig:
    return bridge_control_authority_template(
        "receiver_tuning_nudge",
        seed_family,
        receiver_tuning=receiver_tuning,
        phase_bias=phase_bias,
        stage_b_strength=stage_b_strength,
        stage_b_detuning=stage_b_detuning,
        magnetic_bias_strength=magnetic_bias_strength,
        reference_role=reference_role,
        family=family,
    )


def bridge_drift_feedforward_seed_templates(quick: bool, include_sweeps: bool) -> List[Tuple[str, BridgeMinNudgeConfig]]:
    seeds = [
        ("receiver_best_4x_raw", bridge_drift_feedforward_template("receiver_best_4x_raw", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.84)),
        ("magnetic_best_low_work", bridge_drift_feedforward_template("magnetic_best_low_work", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.84)),
        ("stageB_best_budget_clean", bridge_drift_feedforward_template("stageB_best_budget_clean", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.84)),
        ("autolock_seed_s0p9", bridge_drift_feedforward_template("autolock_seed_s0p9", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.90)),
        ("magnetic_stageB0p84_lead", bridge_drift_feedforward_template("magnetic_stageB0p84_lead", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.84)),
    ]
    if include_sweeps:
        receiver_values = [8.86, 8.90, 8.93] if quick else [8.86, 8.875, 8.90, 8.915, 8.93]
        phase_values = [15.0, 25.0, 35.0] if quick else [15.0, 20.0, 25.0, 30.0, 35.0]
        strength_values = [0.80, 0.84, 0.94] if quick else [0.80, 0.84, 0.88, 0.90, 0.94]
        for receiver in receiver_values:
            seeds.append((f"sweep_receiver_{safe_token(receiver)}", bridge_drift_feedforward_template(f"sweep_receiver_{safe_token(receiver)}", receiver_tuning=receiver, phase_bias=30.0, stage_b_strength=0.84)))
        for phase in phase_values:
            seeds.append((f"sweep_phase_{safe_token(phase)}", bridge_drift_feedforward_template(f"sweep_phase_{safe_token(phase)}", receiver_tuning=8.90, phase_bias=phase, stage_b_strength=0.84)))
        for strength in strength_values:
            seeds.append((f"sweep_stageB_{safe_token(strength)}", bridge_drift_feedforward_template(f"sweep_stageB_{safe_token(strength)}", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=strength)))
    return seeds


def bridge_drift_feedforward_non369_template(source: float, target: float, seed_family: str) -> BridgeMinNudgeConfig:
    magnetic = bridge_min_nudge_non369_seed(source, target)
    bridge = replace(
        magnetic.bridge,
        stage_b_phase_bias_deg=30.0,
        stage_b_nonlinear_strength=0.84,
        note="non-369 drift-feedforward bridge control",
    )
    magnetic = replace(magnetic, bridge=bridge, reference_role="control", family="non369")
    return BridgeMinNudgeConfig(
        name=f"feedforward_non369_template_{safe_token(source)}_{safe_token(target)}",
        correction_type="receiver_tuning_nudge",
        magnetic_config=magnetic,
        kp=0.0,
        correction_clamp=0.0,
        update_interval=1.0,
        smoothing=1.0,
        magnetic_bias_strength=2.0,
        control_mode="no_nudge",
        reference_role="control",
        family="non369",
        note=f"non-369 {source:g} -> {source * 2:g} -> {target:g} drift feedforward control",
    )


def bridge_drift_feedforward_to_authority_config(config: BridgeDriftFeedforwardConfig) -> BridgeControlAuthorityConfig:
    base_config = replace(
        config.base_config,
        correction_type=config.correction_type,
        reference_role=config.reference_role,
        family=config.family,
        control_mode="no_nudge",
        correction_clamp=0.0,
    )
    return BridgeControlAuthorityConfig(
        name=config.name,
        correction_type=config.correction_type,
        base_config=base_config,
        correction_size=float(np.clip(config.ramp_size, -config.correction_clamp, config.correction_clamp)),
        schedule_type=config.ramp_shape,
        correction_start_fraction=config.ramp_start_fraction,
        ramp_fraction=max(1e-6, config.ramp_end_fraction - config.ramp_start_fraction),
        max_allowed_correction=config.correction_clamp,
        seed_family=config.seed_family,
        reference_role=config.reference_role,
        family=config.family,
        note=config.note,
    )


def bridge_drift_feedforward_ramp_smoothness(ledger: List[Dict[str, float | str]]) -> float:
    if len(ledger) < 3:
        return 1.0
    values = np.asarray([float(r.get("correction_value", 0.0)) for r in ledger])
    jumps = np.abs(np.diff(values))
    max_jump = float(np.max(jumps)) if len(jumps) else 0.0
    path = float(np.sum(jumps)) if len(jumps) else 0.0
    return 1.0 / (1.0 + 45.0 * max_jump + 3.0 * path)


def bridge_drift_feedforward_baseline_config(seed_family: str,
                                             base_config: BridgeMinNudgeConfig,
                                             runtime_factor: float,
                                             reference_role: str,
                                             family: str) -> BridgeDriftFeedforwardConfig:
    return BridgeDriftFeedforwardConfig(
        name=f"feedforward_{seed_family}_no_feedforward_{safe_token(runtime_factor)}x",
        ramp_type="no_feedforward",
        correction_type="receiver_tuning_nudge",
        base_config=base_config,
        ramp_size=0.0,
        ramp_shape="no_feedforward",
        runtime_factor=runtime_factor,
        seed_family=seed_family,
        reference_role=reference_role,
        family=family,
        control_role="no_feedforward",
        note="no-feedforward 4x baseline for measured drift",
    )


def bridge_drift_feedforward_make_config(seed_family: str,
                                         base_config: BridgeMinNudgeConfig,
                                         runtime_factor: float,
                                         ramp_type: str,
                                         ramp_shape: str,
                                         required_ramp: float,
                                         multiplier: float,
                                         start_fraction: float,
                                         end_fraction: float,
                                         correction_clamp: float,
                                         reference_role: str = "discovery_candidate",
                                         family: str = "369",
                                         control_role: str = "feedforward") -> BridgeDriftFeedforwardConfig:
    correction_type, gain = BRIDGE_DRIFT_FEEDFORWARD_ACTUATORS[ramp_type]
    ramp_size = float(np.clip(required_ramp * multiplier, -correction_clamp, correction_clamp))
    name = (
        f"feedforward_{seed_family}_{ramp_type}_{ramp_shape}"
        f"_m{safe_token(multiplier)}_s{safe_token(start_fraction)}_e{safe_token(end_fraction)}"
        f"_r{safe_token(runtime_factor)}x"
    )
    if control_role not in ("feedforward", "discovery"):
        name = f"{name}_{control_role}"
    return BridgeDriftFeedforwardConfig(
        name=name,
        ramp_type=ramp_type,
        correction_type=correction_type,
        base_config=base_config,
        ramp_size=ramp_size,
        ramp_shape=ramp_shape,
        ramp_start_fraction=start_fraction,
        ramp_end_fraction=end_fraction,
        correction_clamp=correction_clamp,
        authority_gain_prior=gain,
        estimated_required_ramp_size=required_ramp,
        runtime_factor=runtime_factor,
        seed_family=seed_family,
        reference_role=reference_role,
        family=family,
        control_role=control_role,
        note="precomputed drift feedforward ramp; no live feedback loop",
    )


def bridge_drift_feedforward_measure(config: BridgeDriftFeedforwardConfig, seed: int, quick: bool,
                                     dt: float, runtime: float, sample_every: int,
                                     direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]],
                                     baseline_summary: Dict[str, float | str] | None = None,
                                     baseline_row: Dict[str, float | str] | None = None
                                     ) -> Tuple[Dict[str, float | str], List[Dict[str, float | str]], List[Dict[str, float | str]], Dict[str, float | str]]:
    authority_config = bridge_drift_feedforward_to_authority_config(config)
    sim, ledger = simulate_bridge_control_authority(authority_config, seed, quick, dt=dt, t_max=runtime, sample_every=sample_every)
    effective = sim["effective_config"]  # type: ignore[assignment]
    target_key = f"{effective.mode_freqs[0]:g}:{effective.target_6:g}:{effective.target_9:g}"
    cache_key = (target_key, dt, runtime)
    if cache_key not in direct_cache:
        direct_cfg = bridge_min_nudge_direct_reference(effective)
        direct_sim, _ = simulate_bridge_amp(direct_cfg, seed + 9100, quick, dt=dt, t_max=runtime, sample_every=sample_every)
        direct_row = bridge_metrics_window(direct_cfg, direct_sim, seed + 9100, "direct_reference", "direct_source_plus_generated", "reference", 0.35, 1.0)
        direct_cache[cache_key] = (direct_sim, direct_row)
    direct_sim, direct_row = direct_cache[cache_key]

    row = bridge_metrics_window(effective, sim, seed, "feedforward", config.ramp_shape, f"{config.ramp_size:g}", 0.35, 1.0)
    drift_rows, after_summary = bridge_phase_diagnostic_series(effective, sim, direct_sim, 0.62, 1.0)
    before_summary = baseline_summary if baseline_summary is not None else after_summary
    before_abs = float(before_summary.get("phase_drift_rate", 0.0))
    before_signed = bridge_drift_feedforward_signed_drift(before_summary)
    after_abs = float(after_summary.get("phase_drift_rate", 0.0))
    after_signed = bridge_drift_feedforward_signed_drift(after_summary)
    drift_reduction = metric_ratio(abs(before_signed) - abs(after_signed), abs(before_signed)) if abs(before_signed) > 1e-12 else 0.0

    row.update(after_summary)
    row["experiment"] = "bridge_drift_feedforward"
    row["case"] = config.name
    row["candidate_id"] = f"{config.name}:{config.runtime_factor:g}x"
    row["ramp_type"] = config.ramp_type
    row["actuator_type"] = config.ramp_type
    row["correction_type"] = config.correction_type
    row["ramp_shape"] = config.ramp_shape
    row["schedule_type"] = config.ramp_shape
    row["ramp_size"] = config.ramp_size
    row["estimated_required_ramp_size"] = config.estimated_required_ramp_size
    row["authority_gain_prior"] = config.authority_gain_prior
    row["correction_clamp"] = config.correction_clamp
    row["ramp_start_fraction"] = config.ramp_start_fraction
    row["ramp_end_fraction"] = config.ramp_end_fraction
    row["seed_family"] = config.seed_family
    row["reference_role"] = config.reference_role
    row["family"] = config.family
    row["control_role"] = config.control_role
    row["runtime_factor"] = config.runtime_factor
    row["bridge_ratio"] = metric_ratio(float(row.get("energy_at_9", 0.0)), float(direct_row.get("energy_at_9", 0.0)))
    row["generated_vs_direct_bridge_ratio"] = row["bridge_ratio"]
    row["energy_at_9_from_direct_3_plus_6_reference"] = direct_row.get("energy_at_9", 0.0)
    total_input_before = max(float(row.get("total_input_work", 0.0)), 1e-18)
    total_input_with_feedforward = total_input_before + float(sim["correction_work"])
    row["total_input_work_before_feedforward"] = total_input_before
    row["total_input_work"] = total_input_with_feedforward
    row["feedforward_work"] = float(sim["correction_work"])
    row["feedforward_work_signed"] = float(sim["correction_work_signed"])
    row["feedforward_energy_in"] = float(sim["correction_energy_in"])
    row["feedforward_energy_out"] = float(sim["correction_energy_out"])
    row["feedforward_work_fraction"] = metric_ratio(float(sim["correction_work"]), total_input_with_feedforward)
    row["correction_work"] = row["feedforward_work"]
    row["correction_work_fraction"] = row["feedforward_work_fraction"]
    row["feedforward_rms"] = float(sim["correction_rms"])
    row["feedforward_peak"] = float(sim["correction_peak"])
    row["ramp_smoothness"] = bridge_drift_feedforward_ramp_smoothness(ledger)
    row["phase_drift_rate_before"] = before_signed
    row["phase_drift_rate_before_abs"] = before_abs
    row["phase_drift_rate_after"] = after_signed
    row["phase_drift_rate_after_abs"] = after_abs
    row["phase_drift_rate_after_correction"] = after_abs
    row["drift_reduction_fraction"] = drift_reduction
    row["drift_reduction_percent"] = 100.0 * drift_reduction
    row["effective_generated_frequency_before"] = float(before_summary.get("effective_target_frequency", effective.target_9))
    row["effective_generated_frequency_after"] = float(after_summary.get("effective_target_frequency", effective.target_9))
    row["baseline_phase_lock_9"] = float(baseline_row.get("phase_lock_9", 0.0)) if baseline_row else float(row.get("phase_lock_9", 0.0))
    row["phase_lock_improvement_vs_baseline"] = float(row.get("phase_lock_9", 0.0)) - float(row.get("baseline_phase_lock_9", 0.0))
    row["lock_duration"] = after_summary.get("lock_duration", 0.0)
    row["time_to_unlock"] = after_summary.get("time_to_unlock", 0.0)
    row["lock_duration_fraction"] = metric_ratio(float(row.get("lock_duration", 0.0)), float(row.get("runtime", runtime)))
    row["no_direct_6_drive"] = str(not any(abs(freq - effective.target_6) < 1e-9 and mode == 1 for freq, mode in zip(effective.drive_freqs, effective.drive_modes)))
    row["no_direct_9_drive"] = str(not any(abs(freq - effective.target_9) < 1e-9 and mode == 2 for freq, mode in zip(effective.drive_freqs, effective.drive_modes)))
    row["no_target_frequency_injection"] = row["no_direct_9_drive"]
    row["note"] = config.note
    bridge_drift_feedforward_update_score(row)

    for item in ledger:
        item["experiment"] = "bridge_drift_feedforward"
        item["candidate_id"] = row["candidate_id"]
        item["seed_family"] = config.seed_family
        item["ramp_type"] = config.ramp_type
        item["ramp_shape"] = config.ramp_shape
        item["ramp_size"] = config.ramp_size
        item["feedforward_work"] = item.get("correction_work", 0.0)
    for item in drift_rows:
        item["experiment"] = "bridge_drift_feedforward"
        item["case"] = config.name
        item["candidate_id"] = row["candidate_id"]
        item["seed_family"] = config.seed_family
        item["ramp_type"] = config.ramp_type
        item["ramp_shape"] = config.ramp_shape
        item["ramp_size"] = config.ramp_size
    return row, ledger, drift_rows, after_summary


def bridge_drift_feedforward_update_score(row: Dict[str, float | str]) -> None:
    runtime_factor = float(row.get("runtime_factor", 1.0))
    bridge_ratio = float(row.get("bridge_ratio", 0.0))
    phase_lock = float(row.get("phase_lock_9", 0.0))
    purity = float(row.get("spectral_purity_9", 0.0))
    budget = float(row.get("energy_budget_error", 1.0))
    work = float(row.get("feedforward_work_fraction", row.get("correction_work_fraction", 1.0)))
    drift_reduction = float(row.get("drift_reduction_percent", 0.0))
    discovery = str(row.get("reference_role")) == "discovery_candidate"
    direct_clean = (
        str(row.get("no_direct_6_drive", "False")) == "True"
        and str(row.get("no_direct_9_drive", "False")) == "True"
        and str(row.get("no_target_frequency_injection", "False")) == "True"
    )
    core_pass = (
        runtime_factor >= 4.0
        and bridge_ratio > 0.75
        and phase_lock > 0.90
        and purity > 0.60
        and budget < 0.005
        and work < 0.05
        and direct_clean
    )
    has_dt_flags = "half_dt_preserved" in row or "quarter_dt_preserved" in row
    dt_ok = (
        str(row.get("half_dt_preserved", "False")) == "True"
        and str(row.get("quarter_dt_preserved", "False")) == "True"
    ) if has_dt_flags else True
    passed = core_pass and dt_ok and discovery
    strong = (
        passed
        and bridge_ratio > 0.85
        and phase_lock > 0.95
        and purity > 0.75
        and work < 0.02
        and drift_reduction > 75.0
    )
    failures = []
    if runtime_factor < 4.0:
        failures.append("not_4x_runtime")
    if bridge_ratio <= 0.75:
        failures.append("bridge_ratio")
    if phase_lock <= 0.90:
        failures.append("phase_lock_9")
    if purity <= 0.60:
        failures.append("spectral_purity_9")
    if budget >= 0.005:
        failures.append("energy_budget")
    if work >= 0.05:
        failures.append("feedforward_work_fraction")
    if not direct_clean:
        failures.append("direct_drive_or_target_injection")
    if has_dt_flags and not dt_ok:
        failures.append("dt_validation")

    if not failures:
        failure_mode = "4x_lock_held"
    elif "phase_lock_9" in failures:
        failure_mode = "phase_drift"
    elif "energy_budget" in failures:
        failure_mode = "energy_budget_drift"
    elif "feedforward_work_fraction" in failures:
        failure_mode = "overpowered_ramp"
    elif "bridge_ratio" in failures:
        failure_mode = "bridge_collapse"
    else:
        failure_mode = failures[0]

    gentle_bonus = 1.0 / (
        1.0
        + 120.0 * max(0.0, work)
        + 12.0 * max(0.0, abs(float(row.get("ramp_size", 0.0))))
        + 650.0 * max(0.0, budget)
    )
    drift_bonus = 1.0 + max(0.0, min(1.0, drift_reduction / 100.0))
    score = bridge_ratio * phase_lock * purity * drift_bonus * gentle_bonus
    if not core_pass or not discovery:
        score = 0.0

    row["4x_pass"] = str(core_pass and discovery)
    row["passed"] = str(passed)
    row["strong_passed"] = str(strong)
    row["promotion_ready"] = str(strong)
    row["failed_gate_names"] = ";".join(failures)
    row["failure_mode"] = failure_mode
    row["bridge_drift_feedforward_score"] = score
    row["score"] = score


def bridge_drift_feedforward_validation(config: BridgeDriftFeedforwardConfig, seed: int, quick: bool,
                                       dt: float, runtime: float, sample_every: int
                                       ) -> Tuple[List[Dict[str, float | str]], List[Dict[str, float | str]], List[Dict[str, float | str]]]:
    tests = [("baseline_dt", dt), ("half_dt", dt * 0.5), ("quarter_dt", dt * 0.25)]
    rows: List[Dict[str, float | str]] = []
    ledger_rows: List[Dict[str, float | str]] = []
    drift_rows: List[Dict[str, float | str]] = []
    for idx, (name, test_dt) in enumerate(tests):
        direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]] = {}
        baseline_config = bridge_drift_feedforward_baseline_config(
            config.seed_family,
            config.base_config,
            config.runtime_factor,
            config.reference_role,
            config.family,
        )
        baseline_row, baseline_ledger, baseline_drift, baseline_summary = bridge_drift_feedforward_measure(
            baseline_config, seed + idx * 173, quick, test_dt, runtime, sample_every, direct_cache
        )
        row, ledger, drift, _ = bridge_drift_feedforward_measure(
            config, seed + idx * 173 + 19, quick, test_dt, runtime, sample_every, direct_cache, baseline_summary, baseline_row
        )
        row["validation_test"] = name
        rows.append(row)
        ledger_rows.extend(baseline_ledger)
        ledger_rows.extend(ledger)
        drift_rows.extend(baseline_drift)
        drift_rows.extend(drift)
    return rows, ledger_rows, drift_rows


def apply_bridge_drift_feedforward_validation_status(candidate: Dict[str, float | str],
                                                    validation_rows: List[Dict[str, float | str]]) -> None:
    rows = [r for r in validation_rows if str(r.get("case")) == str(candidate.get("case"))]
    base = next((r for r in rows if str(r.get("validation_test")) == "baseline_dt"), {})
    half = next((r for r in rows if str(r.get("validation_test")) == "half_dt"), {})
    quarter = next((r for r in rows if str(r.get("validation_test")) == "quarter_dt"), {})
    base_phase = float(base.get("phase_lock_9", candidate.get("phase_lock_9", 0.0)))
    base_reduction = float(base.get("drift_reduction_percent", candidate.get("drift_reduction_percent", 0.0)))

    def preserved(row: Dict[str, float | str]) -> bool:
        if not row:
            return False
        core = str(row.get("4x_pass", "False")) == "True"
        phase_ok = float(row.get("phase_lock_9", 0.0)) >= 0.90 or ratio_stability_score(float(row.get("phase_lock_9", 0.0)), base_phase) > 0.85
        reduction_ok = float(row.get("drift_reduction_percent", -100.0)) >= 0.50 * base_reduction
        budget_ok = float(row.get("energy_budget_error", 1.0)) < 0.005
        work_ok = float(row.get("feedforward_work_fraction", 1.0)) < 0.05
        return core and phase_ok and reduction_ok and budget_ok and work_ok

    half_ok = preserved(half)
    quarter_ok = preserved(quarter)
    candidate["half_dt_preserved"] = str(half_ok)
    candidate["quarter_dt_preserved"] = str(quarter_ok)
    candidate["half_dt_phase_lock_9"] = float(half.get("phase_lock_9", 0.0))
    candidate["quarter_dt_phase_lock_9"] = float(quarter.get("phase_lock_9", 0.0))
    candidate["half_dt_drift_reduction_percent"] = float(half.get("drift_reduction_percent", 0.0))
    candidate["quarter_dt_drift_reduction_percent"] = float(quarter.get("drift_reduction_percent", 0.0))
    bridge_drift_feedforward_update_score(candidate)


def write_bridge_drift_feedforward_report(out_dir: Path,
                                          ranked: List[Dict[str, float | str]],
                                          validation_rows: List[Dict[str, float | str]],
                                          controls: List[Dict[str, float | str]]) -> None:
    discovery = [r for r in ranked if str(r.get("reference_role")) == "discovery_candidate"]
    best = discovery[0] if discovery else {}
    passed_rows = [r for r in discovery if str(r.get("passed")) == "True"]
    core_rows = [r for r in discovery if str(r.get("4x_pass")) == "True"]
    by_type: Dict[str, Dict[str, float | str]] = {}
    for ramp_type in BRIDGE_DRIFT_FEEDFORWARD_ACTUATORS:
        typed = [r for r in discovery if str(r.get("ramp_type")) == ramp_type]
        if typed:
            by_type[ramp_type] = max(typed, key=lambda r: (float(r.get("bridge_drift_feedforward_score", 0.0)), float(r.get("phase_lock_9", 0.0)), float(r.get("drift_reduction_percent", 0.0))))
    no_feedforward = max([r for r in controls if str(r.get("control_role")) == "no_feedforward" and str(r.get("family")) == "369"], key=lambda r: float(r.get("phase_lock_9", 0.0)), default={})
    wrong = max([r for r in controls if str(r.get("control_role")) == "wrong_sign_ramp"], key=lambda r: float(r.get("phase_lock_9", 0.0)), default={})
    random_control = max([r for r in controls if str(r.get("control_role")) == "random_ramp"], key=lambda r: float(r.get("phase_lock_9", 0.0)), default={})
    over = max([r for r in controls if str(r.get("control_role")) == "overcorrected_ramp"], key=lambda r: float(r.get("phase_lock_9", 0.0)), default={})
    non369 = max([r for r in controls if str(r.get("family")) == "non369"], key=lambda r: (float(r.get("phase_lock_9", 0.0)), float(r.get("drift_reduction_percent", 0.0))), default={})
    best_non369_beats = bool(non369) and float(non369.get("phase_lock_9", 0.0)) > float(best.get("phase_lock_9", 0.0))
    gentle = float(best.get("feedforward_work_fraction", 1.0)) < 0.02 and abs(float(best.get("ramp_size", 0.0))) < 0.75 * max(float(best.get("correction_clamp", 1.0)), 1e-18)
    if passed_rows:
        hold_answer = "yes, at least one validated feedforward row held the 4x gate"
        next_answer = "promote the best row into stronger proportional control only as a robustness check"
    elif core_rows:
        hold_answer = "partially; at least one 4x row met core gates but did not preserve half/quarter-dt validation"
        next_answer = "tighten the feedforward estimate and rerun dt validation before moving to PLL"
    else:
        hold_answer = "no, not under the current promotion gates"
        next_answer = "stronger proportional control is the next step; move to full PLL if fixed feedforward remains phase-limited"

    lines = [
        "# Bridge Drift Feedforward Report",
        "",
        "This mode applies precomputed tuning ramps from measured drift. It uses no PLL, no live feedback, no direct 6 drive, no direct 9 drive, and no target-frequency injection.",
        "",
        "## Direct Answers",
        f"1. Can precomputed drift feedforward hold 4x lock? {hold_answer}.",
        f"2. Best actuator: {best.get('ramp_type', 'none')}; phase_lock_9={float(best.get('phase_lock_9', 0.0)):.6g}, drift_reduction={float(best.get('drift_reduction_percent', 0.0)):.6g}%, score={float(best.get('bridge_drift_feedforward_score', 0.0)):.6g}.",
        f"3. Feedforward work required: best_work_fraction={float(best.get('feedforward_work_fraction', 0.0)):.6g}, ramp_size={float(best.get('ramp_size', 0.0)):.6g}, estimated_required={float(best.get('estimated_required_ramp_size', 0.0)):.6g}.",
        f"4. Ramp behavior: {'gentle drift cancellation' if gentle else 'not yet gentle enough or not effective enough'}; smoothness={float(best.get('ramp_smoothness', 0.0)):.6g}, budget={float(best.get('energy_budget_error', 0.0)):.6g}.",
        f"5. Do non-369 controls beat 3 -> 6 -> 9? {'yes in this run' if best_non369_beats else 'no under the same ranking rules'}; best_non369_phase={float(non369.get('phase_lock_9', 0.0)):.6g}, best_369_phase={float(best.get('phase_lock_9', 0.0)):.6g}.",
        f"6. If feedforward fails, next step: {next_answer}.",
        f"Controls: no_feedforward_phase={float(no_feedforward.get('phase_lock_9', 0.0)):.6g}, wrong_sign_phase={float(wrong.get('phase_lock_9', 0.0)):.6g}, random_phase={float(random_control.get('phase_lock_9', 0.0)):.6g}, overcorrected_phase={float(over.get('phase_lock_9', 0.0)):.6g}.",
        f"Promotion gate: {len(passed_rows)} validated rows passed; {len(core_rows)} discovery rows met the core 4x gates before dt preservation.",
        "",
        "## Best By Actuator",
    ]
    for ramp_type, row in by_type.items():
        lines.append(
            f"- {ramp_type}: case={row.get('candidate_id')}, phase={float(row.get('phase_lock_9', 0.0)):.6g}, "
            f"bridge={float(row.get('bridge_ratio', 0.0)):.6g}, purity={float(row.get('spectral_purity_9', 0.0)):.6g}, "
            f"drift_reduction={float(row.get('drift_reduction_percent', 0.0)):.6g}%, work={float(row.get('feedforward_work_fraction', 0.0)):.6g}, "
            f"pass={row.get('passed')}, failure={row.get('failure_mode', '')}"
        )
    lines.extend(["", "## Top Rows"])
    for row in ranked[:24]:
        lines.append(
            f"- {row.get('candidate_id')}: actuator={row.get('ramp_type')}, shape={row.get('ramp_shape')}, size={float(row.get('ramp_size', 0.0)):.6g}, "
            f"score={float(row.get('bridge_drift_feedforward_score', 0.0)):.6g}, pass={row.get('passed')}, 4x={row.get('4x_pass')}, "
            f"phase={float(row.get('phase_lock_9', 0.0)):.6g}, bridge={float(row.get('bridge_ratio', 0.0)):.6g}, purity={float(row.get('spectral_purity_9', 0.0)):.6g}, "
            f"drift_reduction={float(row.get('drift_reduction_percent', 0.0)):.6g}%, work={float(row.get('feedforward_work_fraction', 0.0)):.6g}, "
            f"budget={float(row.get('energy_budget_error', 0.0)):.6g}, failure={row.get('failure_mode', '')}"
        )
    if validation_rows:
        lines.extend(["", "## Dt Validation"])
        for row in validation_rows[:20]:
            lines.append(
                f"- {row.get('candidate_id')}: test={row.get('validation_test', '')}, phase={float(row.get('phase_lock_9', 0.0)):.6g}, "
                f"drift_reduction={float(row.get('drift_reduction_percent', 0.0)):.6g}%, work={float(row.get('feedforward_work_fraction', 0.0)):.6g}, "
                f"budget={float(row.get('energy_budget_error', 0.0)):.6g}, 4x={row.get('4x_pass')}"
            )
    (out_dir / "README_BRIDGE_DRIFT_FEEDFORWARD_REPORT.md").write_text("\n".join(lines), encoding="utf-8")


def experiment_bridge_drift_feedforward(out_dir: Path, seed: int, quick: bool = False,
                                        include_sweeps: bool = False) -> List[Dict[str, float | str]]:
    dt, base_tmax, sample_every = bridge_amp_timebase(quick)
    runtime_factors = [4.0]
    if include_sweeps:
        runtime_factors = [1.0, 2.0, 4.0]
    shapes = ["linear_ramp", "piecewise_linear_ramp", "s_curve_ramp", "hold_after_capture_ramp", "two_stage_ramp"]
    plan_specs = [(shape, 1.0, 0.18, 0.74) for shape in shapes]
    if include_sweeps:
        multiplier_values = [0.75, 1.25] if quick else [0.50, 0.75, 1.25, 1.50]
        plan_specs.extend(("linear_ramp", multiplier, 0.18, 0.74) for multiplier in multiplier_values)
        plan_specs.extend(("linear_ramp", 1.0, start, end) for start, end in [(0.10, 0.62), (0.25, 0.82)])
    correction_clamp = 0.024 if quick and not include_sweeps else 0.036

    summary_rows: List[Dict[str, float | str]] = []
    sweep_rows: List[Dict[str, float | str]] = []
    ledger_rows: List[Dict[str, float | str]] = []
    drift_rows: List[Dict[str, float | str]] = []
    controls: List[Dict[str, float | str]] = []
    config_by_case: Dict[str, BridgeDriftFeedforwardConfig] = {}
    direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]] = {}
    run_index = 0

    for runtime_factor in runtime_factors:
        runtime = base_tmax * 1.25 * runtime_factor
        for seed_family, base_config in bridge_drift_feedforward_seed_templates(quick, include_sweeps):
            is_sweep_seed = seed_family.startswith("sweep_")
            if include_sweeps and is_sweep_seed and runtime_factor < 4.0:
                continue
            if include_sweeps and runtime_factor < 4.0 and seed_family != "receiver_best_4x_raw":
                continue
            baseline_config = bridge_drift_feedforward_baseline_config(seed_family, base_config, runtime_factor, "control", "369")
            baseline_row, baseline_ledger, baseline_drift, baseline_summary = bridge_drift_feedforward_measure(
                baseline_config, seed + run_index * 271, quick, dt, runtime, sample_every, direct_cache
            )
            run_index += 1
            summary_rows.append(baseline_row)
            controls.append(baseline_row)
            if runtime_factor >= 4.0:
                ledger_rows.extend(baseline_ledger)
                drift_rows.extend(baseline_drift)

            signed_drift = bridge_drift_feedforward_signed_drift(baseline_summary)
            for ramp_type, (_, gain) in BRIDGE_DRIFT_FEEDFORWARD_ACTUATORS.items():
                required = -signed_drift / gain if abs(gain) > 1e-12 else 0.0
                active_plan_specs = [("linear_ramp", 1.0, 0.18, 0.74)] if is_sweep_seed else plan_specs
                for shape, multiplier, start_fraction, end_fraction in active_plan_specs:
                    config = bridge_drift_feedforward_make_config(
                        seed_family,
                        base_config,
                        runtime_factor,
                        ramp_type,
                        shape,
                        required,
                        multiplier,
                        start_fraction,
                        end_fraction,
                        correction_clamp,
                    )
                    config_by_case[config.name] = config
                    row, ledger, drift, _ = bridge_drift_feedforward_measure(
                        config, seed + run_index * 271, quick, dt, runtime, sample_every, direct_cache, baseline_summary, baseline_row
                    )
                    run_index += 1
                    summary_rows.append(row)
                    if include_sweeps or config.reference_role == "discovery_candidate":
                        sweep_rows.append(row)
                    if runtime_factor >= 4.0 and (include_sweeps or abs(float(row.get("ramp_size", 0.0))) >= 0.006):
                        ledger_rows.extend(ledger)
                        drift_rows.extend(drift)

                if runtime_factor >= 4.0 and seed_family == "receiver_best_4x_raw":
                    control_specs = [
                        ("wrong_sign_ramp", -1.0, "linear_ramp"),
                        ("overcorrected_ramp", 2.0, "linear_ramp"),
                        ("random_ramp", 1.0, "random_ramp"),
                    ]
                    for role, multiplier, shape in control_specs:
                        config = bridge_drift_feedforward_make_config(
                            seed_family,
                            base_config,
                            runtime_factor,
                            ramp_type,
                            shape,
                            required,
                            multiplier,
                            0.18,
                            0.74,
                            correction_clamp,
                            reference_role="control",
                            family="369",
                            control_role=role,
                        )
                        row, ledger, drift, _ = bridge_drift_feedforward_measure(
                            config, seed + run_index * 271, quick, dt, runtime, sample_every, direct_cache, baseline_summary, baseline_row
                        )
                        run_index += 1
                        summary_rows.append(row)
                        controls.append(row)
                        ledger_rows.extend(ledger)
                        drift_rows.extend(drift)

    for source, target in ((4.0, 12.0), (5.0, 15.0)):
        runtime_factor = 4.0
        runtime = base_tmax * 1.25 * runtime_factor
        seed_family = f"non369_{safe_token(source)}_{safe_token(target)}"
        base_config = bridge_drift_feedforward_non369_template(source, target, seed_family)
        baseline_config = bridge_drift_feedforward_baseline_config(seed_family, base_config, runtime_factor, "control", "non369")
        baseline_row, baseline_ledger, baseline_drift, baseline_summary = bridge_drift_feedforward_measure(
            baseline_config, seed + run_index * 271, quick, dt, runtime, sample_every, direct_cache
        )
        run_index += 1
        summary_rows.append(baseline_row)
        controls.append(baseline_row)
        ledger_rows.extend(baseline_ledger)
        drift_rows.extend(baseline_drift)
        signed_drift = bridge_drift_feedforward_signed_drift(baseline_summary)
        for ramp_type, (_, gain) in BRIDGE_DRIFT_FEEDFORWARD_ACTUATORS.items():
            required = -signed_drift / gain if abs(gain) > 1e-12 else 0.0
            config = bridge_drift_feedforward_make_config(
                seed_family,
                base_config,
                runtime_factor,
                ramp_type,
                "linear_ramp",
                required,
                1.0,
                0.18,
                0.74,
                correction_clamp,
                reference_role="control",
                family="non369",
                control_role="non369_feedforward",
            )
            row, ledger, drift, _ = bridge_drift_feedforward_measure(
                config, seed + run_index * 271, quick, dt, runtime, sample_every, direct_cache, baseline_summary, baseline_row
            )
            run_index += 1
            summary_rows.append(row)
            controls.append(row)
            ledger_rows.extend(ledger)
            drift_rows.extend(drift)

    ranked = sorted(
        summary_rows,
        key=lambda r: (
            float(r.get("bridge_drift_feedforward_score", 0.0)),
            1.0 if str(r.get("reference_role")) == "discovery_candidate" else 0.0,
            1.0 if str(r.get("4x_pass")) == "True" else 0.0,
            float(r.get("phase_lock_9", 0.0)),
            float(r.get("drift_reduction_percent", 0.0)),
            -float(r.get("feedforward_work_fraction", 1.0)),
        ),
        reverse=True,
    )

    validation_rows: List[Dict[str, float | str]] = []
    top_candidates = [r for r in ranked if str(r.get("reference_role")) == "discovery_candidate" and float(r.get("runtime_factor", 1.0)) >= 4.0][:4 if include_sweeps else 2]
    for idx, candidate in enumerate(top_candidates):
        config = config_by_case.get(str(candidate.get("case")))
        if config is None:
            continue
        runtime = base_tmax * 1.25 * float(config.runtime_factor)
        rows, ledger, drift = bridge_drift_feedforward_validation(config, seed + 83000 + idx * 1000, quick, dt, runtime, sample_every)
        validation_rows.extend(rows)
        ledger_rows.extend(ledger)
        drift_rows.extend(drift)
        apply_bridge_drift_feedforward_validation_status(candidate, validation_rows)

    ranked = sorted(
        summary_rows,
        key=lambda r: (
            float(r.get("bridge_drift_feedforward_score", 0.0)),
            1.0 if str(r.get("reference_role")) == "discovery_candidate" else 0.0,
            1.0 if str(r.get("4x_pass")) == "True" else 0.0,
            float(r.get("phase_lock_9", 0.0)),
            float(r.get("drift_reduction_percent", 0.0)),
            -float(r.get("feedforward_work_fraction", 1.0)),
        ),
        reverse=True,
    )

    write_csv(out_dir / "bridge_drift_feedforward_summary.csv", summary_rows + validation_rows)
    write_csv(out_dir / "bridge_drift_feedforward_ranked.csv", ranked)
    write_csv(out_dir / "bridge_drift_feedforward_sweeps.csv", sweep_rows)
    write_csv(out_dir / "bridge_drift_feedforward_timeseries.csv", ledger_rows + drift_rows)
    write_bridge_drift_feedforward_report(out_dir, ranked, validation_rows, controls)

    return [
        {
            "experiment": "bridge_drift_feedforward",
            "case": row.get("case", ""),
            "freqs": row.get("freqs", ""),
            "score": row.get("bridge_drift_feedforward_score", 0.0),
            "passed": row.get("passed", "False"),
            "promotion_ready": row.get("promotion_ready", "False"),
            "ramp_type": row.get("ramp_type", ""),
            "ramp_shape": row.get("ramp_shape", ""),
            "ramp_size": row.get("ramp_size", 0.0),
            "bridge_ratio": row.get("bridge_ratio", 0.0),
            "phase_lock_9": row.get("phase_lock_9", 0.0),
            "spectral_purity_9": row.get("spectral_purity_9", 0.0),
            "energy_budget_error": row.get("energy_budget_error", 0.0),
            "feedforward_work_fraction": row.get("feedforward_work_fraction", 0.0),
            "drift_reduction_percent": row.get("drift_reduction_percent", 0.0),
            "failure_mode": row.get("failure_mode", ""),
            "note": row.get("note", ""),
        }
        for row in ranked[:20]
    ]


# ----------------------------
# Experiment 20: bridge phase servo
# ----------------------------

@dataclass
class BridgePhaseServoConfig:
    name: str
    actuator_type: str
    correction_type: str
    base_config: BridgeMinNudgeConfig
    kp: float
    ki: float
    correction_clamp: float
    smoothing: float
    update_interval: float
    runtime_factor: float = 4.0
    integral_clamp: float = 18.0
    control_mode: str = "normal"
    seed_family: str = "base"
    target_family: str = "369"
    reference_role: str = "discovery_candidate"
    family: str = "369"
    note: str = ""


BRIDGE_PHASE_SERVO_ACTUATORS = {
    "receiver_tuning_servo": "receiver_tuning_nudge",
    "stage_B_detuning_servo": "stage_B_detuning_nudge",
    "magnetic_bias_servo": "magnetic_bias_nudge",
}


def bridge_phase_servo_template(seed_family: str,
                                receiver_tuning: float = 8.90,
                                phase_bias: float = 30.0,
                                stage_b_strength: float = 0.84,
                                stage_b_detuning: float = 0.0,
                                target_family: str = "369",
                                reference_role: str = "discovery_candidate",
                                family: str = "369") -> BridgeMinNudgeConfig:
    return bridge_control_authority_template(
        "receiver_tuning_nudge",
        seed_family,
        receiver_tuning=receiver_tuning,
        phase_bias=phase_bias,
        stage_b_strength=stage_b_strength,
        stage_b_detuning=stage_b_detuning,
        reference_role=reference_role,
        family=family,
    )


def bridge_phase_servo_non369_template(source: float, target: float) -> BridgeMinNudgeConfig:
    magnetic = bridge_min_nudge_non369_seed(source, target)
    bridge = replace(
        magnetic.bridge,
        stage_b_phase_bias_deg=30.0,
        stage_b_nonlinear_strength=0.84,
        note="non-369 bridge phase servo comparison",
    )
    magnetic = replace(magnetic, bridge=bridge, reference_role="control", family="non369")
    return BridgeMinNudgeConfig(
        name=f"phase_servo_non369_template_{safe_token(source)}_{safe_token(target)}",
        correction_type="receiver_tuning_nudge",
        magnetic_config=magnetic,
        kp=0.0,
        correction_clamp=0.0,
        update_interval=1.0,
        smoothing=1.0,
        magnetic_bias_strength=2.0,
        control_mode="no_nudge",
        reference_role="control",
        family="non369",
        note=f"non-369 {source:g} -> {source * 2:g} -> {target:g} phase servo control",
    )


def bridge_phase_servo_seed_templates(quick: bool, include_sweeps: bool) -> List[Tuple[str, str, str, BridgeMinNudgeConfig]]:
    seeds = [
        ("369", "receiver_best_4x_raw", "369", bridge_phase_servo_template("receiver_best_4x_raw", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.84)),
        ("369", "stageB_best_budget_clean", "369", bridge_phase_servo_template("stageB_best_budget_clean", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.84)),
        ("369", "autolock_seed_s0p9", "369", bridge_phase_servo_template("autolock_seed_s0p9", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.90)),
        ("369", "magnetic_stageB0p84_lead", "369", bridge_phase_servo_template("magnetic_stageB0p84_lead", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.84)),
        ("369", "feedforward_best_magnetic_bias", "369", bridge_phase_servo_template("feedforward_best_magnetic_bias", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.84)),
    ]
    if include_sweeps:
        receiver_values = [8.86, 8.90, 8.93] if quick else [8.86, 8.875, 8.90, 8.915, 8.93]
        phase_values = [15.0, 25.0, 35.0] if quick else [15.0, 20.0, 25.0, 30.0, 35.0]
        strength_values = [0.80, 0.84, 0.94] if quick else [0.80, 0.84, 0.88, 0.90, 0.94]
        for receiver in receiver_values:
            seeds.append(("369", f"sweep_receiver_{safe_token(receiver)}", "369", bridge_phase_servo_template(f"sweep_receiver_{safe_token(receiver)}", receiver_tuning=receiver, phase_bias=30.0, stage_b_strength=0.84)))
        for phase in phase_values:
            seeds.append(("369", f"sweep_phase_{safe_token(phase)}", "369", bridge_phase_servo_template(f"sweep_phase_{safe_token(phase)}", receiver_tuning=8.90, phase_bias=phase, stage_b_strength=0.84)))
        for strength in strength_values:
            seeds.append(("369", f"sweep_stageB_{safe_token(strength)}", "369", bridge_phase_servo_template(f"sweep_stageB_{safe_token(strength)}", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=strength)))
    seeds.append(("4812", "non369_4_8_12", "non369", bridge_phase_servo_non369_template(4.0, 12.0)))
    seeds.append(("51015", "non369_5_10_15", "non369", bridge_phase_servo_non369_template(5.0, 15.0)))
    return seeds


def bridge_phase_servo_make_config(target_family: str,
                                   seed_family: str,
                                   base_config: BridgeMinNudgeConfig,
                                   actuator_type: str,
                                   kp: float,
                                   ki: float,
                                   correction_clamp: float,
                                   smoothing: float,
                                   update_interval: float,
                                   runtime_factor: float = 4.0,
                                   control_mode: str = "normal",
                                   reference_role: str = "discovery_candidate",
                                   family: str = "369",
                                   suffix: str = "") -> BridgePhaseServoConfig:
    correction_type = BRIDGE_PHASE_SERVO_ACTUATORS[actuator_type]
    role_token = control_mode if control_mode != "normal" else "pi"
    name = (
        f"phase_servo_{target_family}_{seed_family}_{actuator_type}_{role_token}"
        f"_kp{safe_token(kp)}_ki{safe_token(ki)}_c{safe_token(correction_clamp)}"
        f"_sm{safe_token(smoothing)}_u{safe_token(update_interval)}_r{safe_token(runtime_factor)}x"
    )
    if suffix:
        name = f"{name}_{suffix}"
    servo_base = replace(
        base_config,
        correction_type=correction_type,
        reference_role=reference_role,
        family=family,
        control_mode="no_nudge",
        correction_clamp=0.0,
    )
    return BridgePhaseServoConfig(
        name=name,
        actuator_type=actuator_type,
        correction_type=correction_type,
        base_config=servo_base,
        kp=kp,
        ki=ki,
        correction_clamp=correction_clamp,
        smoothing=smoothing,
        update_interval=update_interval,
        runtime_factor=runtime_factor,
        control_mode=control_mode,
        seed_family=seed_family,
        target_family=target_family,
        reference_role=reference_role,
        family=family,
        note="PI phase servo using physical tuning/bias actuator only; no target-frequency injection",
    )


def bridge_phase_servo_next_correction(config: BridgePhaseServoConfig,
                                       rng: np.random.Generator,
                                       phase_error: float,
                                       integral_phase_error: float,
                                       current: float) -> float:
    if config.control_mode == "no_servo":
        desired = 0.0
    elif config.control_mode == "wrong_sign":
        desired = config.kp * phase_error + config.ki * integral_phase_error
    elif config.control_mode == "random":
        desired = float(rng.uniform(-config.correction_clamp, config.correction_clamp))
    else:
        desired = -config.kp * phase_error - config.ki * integral_phase_error
    desired = float(np.clip(desired, -config.correction_clamp, config.correction_clamp))
    return float(np.clip(current + config.smoothing * (desired - current), -config.correction_clamp, config.correction_clamp))


def simulate_bridge_phase_servo(config: BridgePhaseServoConfig, seed: int, quick: bool,
                                dt: float | None = None, t_max: float | None = None,
                                base_hz: float = 0.045, sample_every: int | None = None
                                ) -> Tuple[Dict[str, object], List[Dict[str, float | str]]]:
    rng = np.random.default_rng(seed)
    default_dt, default_tmax, default_sample = bridge_amp_timebase(quick)
    dt = default_dt if dt is None else dt
    t_max = default_tmax if t_max is None else t_max
    sample_every = default_sample if sample_every is None else sample_every
    drive_until = 0.74 * t_max

    correction = 0.0
    phase_error = 0.0
    integral_phase_error = 0.0
    effective = bridge_min_nudge_effective_bridge(config.base_config, correction)
    omega = 2.0 * np.pi * base_hz * np.asarray(effective.mode_freqs, dtype=float)
    zeta = np.asarray([0.018 * effective.stage_a_damping, 0.012 * effective.stage_b_damping, 0.008 * effective.receiver_damping])

    y = np.zeros(6)
    y[:3] = 1e-4 * rng.normal(size=3)
    y[3:] = 1e-4 * rng.normal(size=3)
    initial_total = float(bridge_amp_potentials(y[:3], y[3:], omega, effective)["total"])
    drive_work = 0.0
    positive_input_work = 0.0
    damping_loss = 0.0
    spark_loss = 0.0
    servo_work_signed = 0.0
    servo_work_abs = 0.0
    servo_energy_in = 0.0
    servo_energy_out = 0.0

    update_steps = max(1, int(config.update_interval / max(dt, 1e-12)))
    sample_dt = dt * sample_every
    times: List[float] = []
    qs: List[np.ndarray] = []
    vs: List[np.ndarray] = []
    energies: List[np.ndarray] = []
    corrections: List[float] = []
    phase_errors: List[float] = []
    integral_errors: List[float] = []
    receiver_trace: List[float] = []
    stage_b_trace: List[float] = []
    magnetic_bias_trace: List[float] = []
    ledger: List[Dict[str, float | str]] = []

    n_steps = int(t_max / dt)
    for step in range(n_steps):
        t = step * dt
        q = y[:3]
        v = y[3:]

        if step > 0 and step % update_steps == 0:
            phase_error = bridge_min_nudge_phase_error(effective, times, qs, sample_dt)
            if config.control_mode == "no_servo":
                integral_phase_error = 0.0
            else:
                integral_phase_error = float(np.clip(
                    integral_phase_error + phase_error * config.update_interval,
                    -config.integral_clamp,
                    config.integral_clamp,
                ))
            next_correction = bridge_phase_servo_next_correction(config, rng, phase_error, integral_phase_error, correction)
            if abs(next_correction - correction) > 1e-15:
                before = bridge_amp_potentials(q, v, omega, effective)
                next_effective = bridge_min_nudge_effective_bridge(config.base_config, next_correction)
                next_omega = 2.0 * np.pi * base_hz * np.asarray(next_effective.mode_freqs, dtype=float)
                after_param = bridge_amp_potentials(q, v, next_omega, next_effective)
                delta_work = float(after_param["total"] - before["total"])
                servo_work_signed += delta_work
                servo_work_abs += abs(delta_work)
                servo_energy_in += max(0.0, delta_work)
                servo_energy_out += max(0.0, -delta_work)
                correction = next_correction
                effective = next_effective
                omega = next_omega
                zeta = np.asarray([0.018 * effective.stage_a_damping, 0.012 * effective.stage_b_damping, 0.008 * effective.receiver_damping])

        drive_forces = bridge_amp_drive_forces(effective, t, base_hz, drive_until, 3)
        drive_power = float(np.dot(drive_forces, v))
        drive_work += drive_power * dt
        positive_input_work += max(0.0, drive_power) * dt
        damping_loss += float(np.sum(2.0 * zeta * omega * (v ** 2))) * dt
        if effective.spark_strength:
            for i, j in ((0, 1), (1, 2)):
                gate = float(spark_gate(q[i] - q[j], threshold=effective.spark_threshold))
                c = 0.030 * effective.spark_strength * gate
                spark_loss += float(c * ((v[i] - v[j]) ** 2)) * dt

        y_next = rk4_step(y, t, dt, bridge_amp_derivative, omega, effective, base_hz, drive_until, zeta)
        qn = y_next[:3]
        vn = y_next[3:]
        after = bridge_amp_potentials(qn, vn, omega, effective)
        y = y_next
        if not np.all(np.isfinite(y)) or np.max(np.abs(y)) > 1e6:
            break

        if step % sample_every == 0:
            modal = clean_modal_energy(qn, vn, omega)
            total_accounted = initial_total + drive_work + servo_work_signed - damping_loss - spark_loss
            error_abs = float(after["total"]) - total_accounted
            error_rel = abs(error_abs) / (abs(float(after["total"])) + abs(total_accounted) + 1e-18)
            now = float(t + dt)
            times.append(now)
            qs.append(qn.copy())
            vs.append(vn.copy())
            energies.append(modal)
            corrections.append(correction)
            phase_errors.append(phase_error)
            integral_errors.append(integral_phase_error)
            receiver_trace.append(float(effective.mode_freqs[2]))
            stage_b_trace.append(float(effective.mode_freqs[1]))
            magnetic_bias_trace.append(float(config.base_config.magnetic_config.magnetic_bias_field + (config.base_config.magnetic_bias_strength * correction if config.correction_type == "magnetic_bias_nudge" else 0.0)))
            ledger.append({
                "case": config.name,
                "time": now,
                "target_family": config.target_family,
                "actuator_type": config.actuator_type,
                "correction_type": config.correction_type,
                "control_mode": config.control_mode,
                "Kp": config.kp,
                "Ki": config.ki,
                "phase_error_9": phase_error,
                "integral_phase_error_9": integral_phase_error,
                "correction_value": correction,
                "receiver_tuning": float(effective.mode_freqs[2]),
                "stage_B_tuning": float(effective.mode_freqs[1]),
                "magnetic_bias_field": magnetic_bias_trace[-1],
                "energy_at_source_mode": float(modal[0]),
                "energy_at_generated_mode": float(modal[1]),
                "energy_at_target_mode": float(modal[2]),
                "total_stored_energy": float(after["total"]),
                "drive_input_work": drive_work,
                "positive_input_work": positive_input_work,
                "damping_loss": damping_loss,
                "spark_loss": spark_loss,
                "servo_work_signed": servo_work_signed,
                "servo_work": servo_work_abs,
                "servo_energy_in": servo_energy_in,
                "servo_energy_out": servo_energy_out,
                "total_accounted_energy": total_accounted,
                "energy_budget_error_abs": error_abs,
                "energy_budget_error_rel": error_rel,
            })

    correction_arr = np.asarray(corrections)
    phase_error_arr = np.asarray(phase_errors)
    integral_arr = np.asarray(integral_errors)
    sim: Dict[str, object] = {
        "times": np.asarray(times),
        "qs": np.asarray(qs),
        "vs": np.asarray(vs),
        "energy": np.asarray(energies),
        "omega": omega,
        "drive_until": drive_until,
        "dt_sample": sample_dt,
        "positive_input_work": positive_input_work,
        "net_input_work": drive_work,
        "damping_loss": damping_loss,
        "spark_loss": spark_loss,
        "servo_work_signed": servo_work_signed,
        "servo_work": servo_work_abs,
        "servo_energy_in": servo_energy_in,
        "servo_energy_out": servo_energy_out,
        "correction_work_signed": servo_work_signed,
        "correction_work": servo_work_abs,
        "correction_energy_in": servo_energy_in,
        "correction_energy_out": servo_energy_out,
        "correction_rms": float(np.sqrt(np.mean(correction_arr ** 2))) if len(correction_arr) else 0.0,
        "correction_peak": float(np.max(np.abs(correction_arr))) if len(correction_arr) else 0.0,
        "correction_mean_abs": float(np.mean(np.abs(correction_arr))) if len(correction_arr) else 0.0,
        "correction_final": float(correction_arr[-1]) if len(correction_arr) else 0.0,
        "phase_error_rms": float(np.sqrt(np.mean(phase_error_arr ** 2))) if len(phase_error_arr) else 0.0,
        "integral_phase_error_rms": float(np.sqrt(np.mean(integral_arr ** 2))) if len(integral_arr) else 0.0,
        "energy_budget_error_rel": float(ledger[-1]["energy_budget_error_rel"]) if ledger else 1.0,
        "max_energy_budget_error_rel": max((float(r["energy_budget_error_rel"]) for r in ledger), default=1.0),
        "effective_config": effective,
        "receiver_tuning_trace": np.asarray(receiver_trace),
        "stage_b_tuning_trace": np.asarray(stage_b_trace),
        "magnetic_bias_trace": np.asarray(magnetic_bias_trace),
    }
    return sim, ledger


def bridge_phase_servo_measure(config: BridgePhaseServoConfig, seed: int, quick: bool,
                               dt: float, runtime: float, sample_every: int,
                               direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]],
                               baseline_row: Dict[str, float | str] | None = None
                               ) -> Tuple[Dict[str, float | str], List[Dict[str, float | str]], List[Dict[str, float | str]]]:
    sim, ledger = simulate_bridge_phase_servo(config, seed, quick, dt=dt, t_max=runtime, sample_every=sample_every)
    effective = sim["effective_config"]  # type: ignore[assignment]
    target_key = f"{effective.mode_freqs[0]:g}:{effective.target_6:g}:{effective.target_9:g}"
    cache_key = (target_key, dt, runtime)
    if cache_key not in direct_cache:
        direct_cfg = bridge_min_nudge_direct_reference(effective)
        direct_sim, _ = simulate_bridge_amp(direct_cfg, seed + 9700, quick, dt=dt, t_max=runtime, sample_every=sample_every)
        direct_row = bridge_metrics_window(direct_cfg, direct_sim, seed + 9700, "direct_reference", "direct_source_plus_generated", "reference", 0.35, 1.0)
        direct_cache[cache_key] = (direct_sim, direct_row)
    direct_sim, direct_row = direct_cache[cache_key]

    row = bridge_metrics_window(effective, sim, seed, "phase_servo", config.control_mode, f"{config.kp:g}:{config.ki:g}", 0.35, 1.0)
    drift_rows, drift_summary = bridge_phase_diagnostic_series(effective, sim, direct_sim, 0.50, 1.0)
    row.update(drift_summary)
    row["experiment"] = "bridge_phase_servo"
    row["case"] = config.name
    row["candidate_id"] = f"{config.name}:{config.runtime_factor:g}x"
    row["target_family"] = config.target_family
    row["actuator_type"] = config.actuator_type
    row["correction_type"] = config.correction_type
    row["control_mode"] = config.control_mode
    row["Kp"] = config.kp
    row["Ki"] = config.ki
    row["correction_clamp"] = config.correction_clamp
    row["smoothing"] = config.smoothing
    row["update_interval"] = config.update_interval
    row["runtime_factor"] = config.runtime_factor
    row["seed_family"] = config.seed_family
    row["reference_role"] = config.reference_role
    row["family"] = config.family
    row["bridge_ratio"] = metric_ratio(float(row.get("energy_at_9", 0.0)), float(direct_row.get("energy_at_9", 0.0)))
    row["generated_vs_direct_bridge_ratio"] = row["bridge_ratio"]
    row["energy_at_target"] = row.get("energy_at_9", 0.0)
    row["energy_at_target_from_direct_reference"] = direct_row.get("energy_at_9", 0.0)
    row["phase_lock_target"] = row.get("phase_lock_9", 0.0)
    row["spectral_purity_target"] = row.get("spectral_purity_9", 0.0)
    row["phase_drift_rate"] = drift_summary.get("phase_drift_rate", 0.0)
    row["effective_generated_frequency"] = drift_summary.get("effective_target_frequency", effective.target_9)
    total_input_before = max(float(row.get("total_input_work", 0.0)), 1e-18)
    total_input_with_servo = total_input_before + float(sim["servo_work"])
    row["total_input_work_before_servo"] = total_input_before
    row["total_input_work"] = total_input_with_servo
    row["servo_work"] = float(sim["servo_work"])
    row["servo_work_signed"] = float(sim["servo_work_signed"])
    row["servo_energy_in"] = float(sim["servo_energy_in"])
    row["servo_energy_out"] = float(sim["servo_energy_out"])
    row["servo_work_fraction"] = metric_ratio(float(sim["servo_work"]), total_input_with_servo)
    row["correction_work"] = row["servo_work"]
    row["correction_work_fraction"] = row["servo_work_fraction"]
    row["correction_rms"] = float(sim["correction_rms"])
    row["correction_peak"] = float(sim["correction_peak"])
    row["correction_mean_abs"] = float(sim["correction_mean_abs"])
    row["correction_final"] = float(sim["correction_final"])
    row["phase_error_rms"] = float(sim["phase_error_rms"])
    row["integral_phase_error_rms"] = float(sim["integral_phase_error_rms"])
    row["baseline_phase_lock_target"] = float(baseline_row.get("phase_lock_target", 0.0)) if baseline_row else float(row.get("phase_lock_target", 0.0))
    row["baseline_phase_drift_rate"] = float(baseline_row.get("phase_drift_rate", 0.0)) if baseline_row else float(row.get("phase_drift_rate", 0.0))
    row["servo_gain_vs_baseline"] = float(row.get("phase_lock_target", 0.0)) - float(row.get("baseline_phase_lock_target", 0.0))
    row["phase_drift_reduction_vs_baseline"] = metric_ratio(
        float(row.get("baseline_phase_drift_rate", 0.0)) - float(row.get("phase_drift_rate", 0.0)),
        float(row.get("baseline_phase_drift_rate", 0.0)),
    )
    row["lock_duration_fraction"] = metric_ratio(float(row.get("lock_duration", 0.0)), float(row.get("runtime", runtime)))
    row["no_direct_6_drive"] = str(not any(abs(freq - effective.target_6) < 1e-9 and mode == 1 for freq, mode in zip(effective.drive_freqs, effective.drive_modes)))
    row["no_direct_9_drive"] = str(not any(abs(freq - effective.target_9) < 1e-9 and mode == 2 for freq, mode in zip(effective.drive_freqs, effective.drive_modes)))
    row["no_target_frequency_injection"] = row["no_direct_9_drive"]
    row["note"] = config.note
    bridge_phase_servo_update_score(row)

    for item in ledger:
        item["experiment"] = "bridge_phase_servo"
        item["candidate_id"] = row["candidate_id"]
        item["runtime_factor"] = config.runtime_factor
        item["target_family"] = config.target_family
    for item in drift_rows:
        item["experiment"] = "bridge_phase_servo"
        item["case"] = config.name
        item["candidate_id"] = row["candidate_id"]
        item["runtime_factor"] = config.runtime_factor
        item["target_family"] = config.target_family
        item["actuator_type"] = config.actuator_type
        item["control_mode"] = config.control_mode
    return row, ledger, drift_rows


def bridge_phase_servo_update_score(row: Dict[str, float | str]) -> None:
    runtime_factor = float(row.get("runtime_factor", 1.0))
    phase_lock = float(row.get("phase_lock_target", row.get("phase_lock_9", 0.0)))
    purity = float(row.get("spectral_purity_target", row.get("spectral_purity_9", 0.0)))
    bridge_ratio = float(row.get("bridge_ratio", row.get("generated_vs_direct_bridge_ratio", 0.0)))
    budget = float(row.get("energy_budget_error", 1.0))
    work = float(row.get("servo_work_fraction", 1.0))
    discovery = str(row.get("reference_role")) == "discovery_candidate"
    direct_clean = (
        str(row.get("no_direct_6_drive", "False")) == "True"
        and str(row.get("no_direct_9_drive", "False")) == "True"
        and str(row.get("no_target_frequency_injection", "False")) == "True"
    )
    core_pass = (
        runtime_factor >= 4.0
        and phase_lock > 0.90
        and purity > 0.60
        and bridge_ratio > 0.75
        and budget < 0.005
        and work < 0.05
        and direct_clean
    )
    has_dt_flags = "half_dt_preserved" in row or "quarter_dt_preserved" in row
    dt_ok = (
        str(row.get("half_dt_preserved", "False")) == "True"
        and str(row.get("quarter_dt_preserved", "False")) == "True"
    ) if has_dt_flags else True
    passed = core_pass and dt_ok and discovery
    strong = (
        passed
        and phase_lock > 0.95
        and purity > 0.75
        and bridge_ratio > 0.85
        and work < 0.02
    )
    failures = []
    if runtime_factor < 4.0:
        failures.append("not_4x_runtime")
    if phase_lock <= 0.90:
        failures.append("phase_lock_target")
    if purity <= 0.60:
        failures.append("spectral_purity_target")
    if bridge_ratio <= 0.75:
        failures.append("bridge_ratio")
    if budget >= 0.005:
        failures.append("energy_budget")
    if work >= 0.05:
        failures.append("servo_work_fraction")
    if not direct_clean:
        failures.append("direct_drive_or_target_injection")
    if has_dt_flags and not dt_ok:
        failures.append("dt_validation")

    if not failures:
        failure_mode = "4x_lock_held"
    elif "phase_lock_target" in failures:
        failure_mode = "phase_drift"
    elif "energy_budget" in failures:
        failure_mode = "energy_budget_drift"
    elif "servo_work_fraction" in failures:
        failure_mode = "overpowered_servo"
    elif "bridge_ratio" in failures:
        failure_mode = "bridge_collapse"
    else:
        failure_mode = failures[0]

    gentle_bonus = 1.0 / (
        1.0
        + 130.0 * max(0.0, work)
        + 15.0 * max(0.0, float(row.get("correction_peak", 0.0)))
        + 650.0 * max(0.0, budget)
        + 0.25 * max(0.0, float(row.get("Kp", 0.0)) * 1000.0)
        + 0.20 * max(0.0, float(row.get("Ki", 0.0)) * 100000.0)
    )
    gain_bonus = 1.0 + max(0.0, min(0.35, float(row.get("servo_gain_vs_baseline", 0.0))))
    score = bridge_ratio * phase_lock * purity * gain_bonus * gentle_bonus
    if not core_pass or not discovery:
        score = 0.0

    row["4x_pass"] = str(core_pass and discovery)
    row["passed"] = str(passed)
    row["strong_passed"] = str(strong)
    row["promotion_ready"] = str(strong)
    row["failed_gate_names"] = ";".join(failures)
    row["failure_mode"] = failure_mode
    row["bridge_phase_servo_score"] = score
    row["score"] = score


def bridge_phase_servo_validation(config: BridgePhaseServoConfig, seed: int, quick: bool,
                                  dt: float, runtime: float, sample_every: int
                                  ) -> Tuple[List[Dict[str, float | str]], List[Dict[str, float | str]], List[Dict[str, float | str]]]:
    tests = [("baseline_dt", dt), ("half_dt", dt * 0.5), ("quarter_dt", dt * 0.25)]
    rows: List[Dict[str, float | str]] = []
    ledger_rows: List[Dict[str, float | str]] = []
    drift_rows: List[Dict[str, float | str]] = []
    for idx, (name, test_dt) in enumerate(tests):
        direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]] = {}
        baseline_config = replace(
            config,
            name=f"{config.name}_validation_no_servo_{name}",
            control_mode="no_servo",
            kp=0.0,
            ki=0.0,
            correction_clamp=0.0,
            reference_role=config.reference_role,
        )
        baseline_row, baseline_ledger, baseline_drift = bridge_phase_servo_measure(
            baseline_config, seed + idx * 197, quick, test_dt, runtime, sample_every, direct_cache
        )
        row, ledger, drift = bridge_phase_servo_measure(
            config, seed + idx * 197 + 23, quick, test_dt, runtime, sample_every, direct_cache, baseline_row
        )
        row["validation_test"] = name
        rows.append(row)
        ledger_rows.extend(baseline_ledger)
        ledger_rows.extend(ledger)
        drift_rows.extend(baseline_drift)
        drift_rows.extend(drift)
    return rows, ledger_rows, drift_rows


def apply_bridge_phase_servo_validation_status(candidate: Dict[str, float | str],
                                               validation_rows: List[Dict[str, float | str]]) -> None:
    rows = [r for r in validation_rows if str(r.get("case")) == str(candidate.get("case"))]
    base = next((r for r in rows if str(r.get("validation_test")) == "baseline_dt"), {})
    half = next((r for r in rows if str(r.get("validation_test")) == "half_dt"), {})
    quarter = next((r for r in rows if str(r.get("validation_test")) == "quarter_dt"), {})
    base_phase = float(base.get("phase_lock_target", candidate.get("phase_lock_target", 0.0)))

    def preserved(row: Dict[str, float | str]) -> bool:
        if not row:
            return False
        core = str(row.get("4x_pass", "False")) == "True"
        phase_ok = float(row.get("phase_lock_target", 0.0)) >= 0.90 or ratio_stability_score(float(row.get("phase_lock_target", 0.0)), base_phase) > 0.85
        budget_ok = float(row.get("energy_budget_error", 1.0)) < 0.005
        work_ok = float(row.get("servo_work_fraction", 1.0)) < 0.05
        return core and phase_ok and budget_ok and work_ok

    half_ok = preserved(half)
    quarter_ok = preserved(quarter)
    candidate["half_dt_preserved"] = str(half_ok)
    candidate["quarter_dt_preserved"] = str(quarter_ok)
    candidate["half_dt_phase_lock_target"] = float(half.get("phase_lock_target", 0.0))
    candidate["quarter_dt_phase_lock_target"] = float(quarter.get("phase_lock_target", 0.0))
    candidate["half_dt_servo_work_fraction"] = float(half.get("servo_work_fraction", 1.0))
    candidate["quarter_dt_servo_work_fraction"] = float(quarter.get("servo_work_fraction", 1.0))
    bridge_phase_servo_update_score(candidate)


def bridge_phase_servo_specs(quick: bool, include_sweeps: bool) -> List[Tuple[str, str, BridgePhaseServoConfig]]:
    specs: List[Tuple[str, str, BridgePhaseServoConfig]] = []
    seeds = bridge_phase_servo_seed_templates(quick, include_sweeps)
    base_gain_sets = [
        ("tiny_pi", 0.00075, 0.000008, 0.012, 0.14, 2.5),
        ("small_pi", 0.00150, 0.000020, 0.018, 0.18, 2.0),
        ("modest_pi", 0.00300, 0.000045, 0.024, 0.22, 1.5),
    ]
    runtime_factors = [4.0]
    if include_sweeps:
        runtime_factors = [1.0, 2.0, 4.0]
    for target_family, seed_family, family, base_config in seeds:
        is_sweep_seed = seed_family.startswith("sweep_")
        reference_role = "discovery_candidate" if target_family == "369" else "control"
        for runtime_factor in runtime_factors:
            if include_sweeps and runtime_factor < 4.0 and seed_family != "receiver_best_4x_raw":
                continue
            gain_sets = [base_gain_sets[1]] if is_sweep_seed else base_gain_sets
            for actuator_type in BRIDGE_PHASE_SERVO_ACTUATORS:
                for label, kp, ki, clamp, smoothing, update_interval in gain_sets:
                    config = bridge_phase_servo_make_config(
                        target_family,
                        seed_family,
                        base_config,
                        actuator_type,
                        kp,
                        ki,
                        clamp,
                        smoothing,
                        update_interval,
                        runtime_factor=runtime_factor,
                        reference_role=reference_role,
                        family=family,
                        suffix=label,
                    )
                    specs.append((label, seed_family, config))
    if include_sweeps:
        primary = bridge_phase_servo_template("receiver_best_4x_raw", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.84)
        sweep_sets = [
            ("Kp", [(0.00035, 0.000020, 0.018, 0.18, 2.0), (0.0022, 0.000020, 0.018, 0.18, 2.0), (0.0045, 0.000020, 0.024, 0.18, 2.0)]),
            ("Ki", [(0.0015, 0.0, 0.018, 0.18, 2.0), (0.0015, 0.000010, 0.018, 0.18, 2.0), (0.0015, 0.000060, 0.024, 0.18, 2.0)]),
            ("correction_clamp", [(0.0015, 0.000020, 0.006, 0.18, 2.0), (0.0015, 0.000020, 0.012, 0.18, 2.0), (0.0015, 0.000020, 0.036, 0.18, 2.0)]),
            ("smoothing", [(0.0015, 0.000020, 0.018, 0.08, 2.0), (0.0015, 0.000020, 0.018, 0.30, 2.0)]),
            ("update_interval", [(0.0015, 0.000020, 0.018, 0.18, 1.0), (0.0015, 0.000020, 0.018, 0.18, 4.0)]),
        ]
        for sweep_name, values in sweep_sets:
            for actuator_type in BRIDGE_PHASE_SERVO_ACTUATORS:
                for kp, ki, clamp, smoothing, update_interval in values:
                    config = bridge_phase_servo_make_config(
                        "369",
                        "receiver_best_4x_raw",
                        primary,
                        actuator_type,
                        kp,
                        ki,
                        clamp,
                        smoothing,
                        update_interval,
                        runtime_factor=4.0,
                        reference_role="discovery_candidate",
                        family="369",
                        suffix=sweep_name,
                    )
                    specs.append((sweep_name, f"{kp:g}:{ki:g}:{clamp:g}:{smoothing:g}:{update_interval:g}", config))
    return specs


def bridge_phase_servo_control_specs(include_sweeps: bool) -> List[Tuple[str, str, BridgePhaseServoConfig]]:
    controls: List[Tuple[str, str, BridgePhaseServoConfig]] = []
    base = bridge_phase_servo_template("control_baseline", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.84, reference_role="control")
    control_modes = [
        ("no_servo", "receiver_tuning_servo", 0.0, 0.0, 0.0),
        ("wrong_sign", "receiver_tuning_servo", 0.0015, 0.000020, 0.018),
        ("random", "receiver_tuning_servo", 0.0015, 0.000020, 0.018),
    ]
    if include_sweeps:
        for actuator_type in BRIDGE_PHASE_SERVO_ACTUATORS:
            control_modes.append(("wrong_sign", actuator_type, 0.0015, 0.000020, 0.018))
            control_modes.append(("random", actuator_type, 0.0015, 0.000020, 0.018))
    seen = set()
    for control_mode, actuator_type, kp, ki, clamp in control_modes:
        key = (control_mode, actuator_type)
        if key in seen:
            continue
        seen.add(key)
        config = bridge_phase_servo_make_config(
            "369",
            "control_baseline",
            base,
            actuator_type,
            kp,
            ki,
            clamp,
            0.18,
            2.0,
            runtime_factor=4.0,
            control_mode=control_mode,
            reference_role="control",
            family="369",
            suffix="control",
        )
        controls.append((control_mode, actuator_type, config))
    return controls


def write_bridge_phase_servo_report(out_dir: Path,
                                    ranked: List[Dict[str, float | str]],
                                    validation_rows: List[Dict[str, float | str]],
                                    controls: List[Dict[str, float | str]]) -> None:
    discovery = [r for r in ranked if str(r.get("reference_role")) == "discovery_candidate"]
    best = discovery[0] if discovery else {}
    passed_rows = [r for r in discovery if str(r.get("passed")) == "True"]
    core_rows = [r for r in discovery if str(r.get("4x_pass")) == "True"]
    by_actuator: Dict[str, Dict[str, float | str]] = {}
    for actuator_type in BRIDGE_PHASE_SERVO_ACTUATORS:
        typed = [r for r in discovery if str(r.get("actuator_type")) == actuator_type]
        if typed:
            by_actuator[actuator_type] = max(typed, key=lambda r: (float(r.get("bridge_phase_servo_score", 0.0)), float(r.get("phase_lock_target", 0.0)), -float(r.get("servo_work_fraction", 1.0))))
    best_by_family: Dict[str, Dict[str, float | str]] = {}
    for family in ["369", "4812", "51015"]:
        rows = [r for r in ranked + controls if str(r.get("target_family")) == family]
        if rows:
            best_by_family[family] = max(rows, key=lambda r: (float(r.get("phase_lock_target", 0.0)), float(r.get("bridge_ratio", 0.0)), -float(r.get("servo_work_fraction", 1.0))))
    no_servo = max([r for r in controls if str(r.get("control_mode")) == "no_servo" and str(r.get("target_family")) == "369"], key=lambda r: float(r.get("phase_lock_target", 0.0)), default={})
    wrong = max([r for r in controls if str(r.get("control_mode")) == "wrong_sign" and str(r.get("target_family")) == "369"], key=lambda r: float(r.get("phase_lock_target", 0.0)), default={})
    random_control = max([r for r in controls if str(r.get("control_mode")) == "random" and str(r.get("target_family")) == "369"], key=lambda r: float(r.get("phase_lock_target", 0.0)), default={})
    best_369 = best_by_family.get("369", {})
    best_4812 = best_by_family.get("4812", {})
    best_51015 = best_by_family.get("51015", {})
    non369_best_phase = max(float(best_4812.get("phase_lock_target", 0.0)), float(best_51015.get("phase_lock_target", 0.0)))
    beats_non369 = bool(best_369) and float(best_369.get("phase_lock_target", 0.0)) > non369_best_phase
    gentle = (
        float(best.get("servo_work_fraction", 1.0)) < 0.02
        and float(best.get("correction_peak", 1.0)) < 0.75 * max(float(best.get("correction_clamp", 1.0)), 1e-18)
        and float(best.get("servo_gain_vs_baseline", 0.0)) >= 0.0
    )
    if passed_rows:
        hold_answer = "yes, at least one dt-preserved 3 -> 6 -> 9 discovery row held the 4x gate"
    elif core_rows:
        hold_answer = "partially; a discovery row met core 4x gates before dt preservation"
    else:
        hold_answer = "no, not under the current promotion gates"
    next_answer = "geometry/evolve can wait; compare controls first"
    if passed_rows and beats_non369:
        next_answer = "geometry/evolve is justified as a follow-up, with non-369 controls kept in every run"
    elif non369_best_phase >= float(best_369.get("phase_lock_target", 0.0)):
        next_answer = "3 -> 6 -> 9 is not uniquely special yet; prioritize control comparisons over geometry/evolve"

    lines = [
        "# Bridge Phase Servo Report",
        "",
        "This mode tests PI feedback through physical tuning/bias actuators only. It uses no direct 6 drive, no direct 9 drive, and no injected 9-frequency reference.",
        "",
        "## Direct Answers",
        f"1. Can a physical tuning servo hold 4x lock? {hold_answer}.",
        f"2. Best actuator: {best.get('actuator_type', 'none')}; phase_lock_target={float(best.get('phase_lock_target', 0.0)):.6g}, bridge={float(best.get('bridge_ratio', 0.0)):.6g}, score={float(best.get('bridge_phase_servo_score', 0.0)):.6g}.",
        f"3. Servo work required: best_work_fraction={float(best.get('servo_work_fraction', 0.0)):.6g}, rms={float(best.get('correction_rms', 0.0)):.6g}, peak={float(best.get('correction_peak', 0.0)):.6g}.",
        f"4. Does 3 -> 6 -> 9 beat controls? {'yes' if beats_non369 else 'no on phase lock; no family passed the full gate'}; phase_369={float(best_369.get('phase_lock_target', 0.0)):.6g}, phase_4812={float(best_4812.get('phase_lock_target', 0.0)):.6g}, phase_51015={float(best_51015.get('phase_lock_target', 0.0)):.6g}.",
        f"5. Servo behavior: {'gentle stabilizing correction' if gentle else 'not proven gentle/effective enough'}; gain_vs_baseline={float(best.get('servo_gain_vs_baseline', 0.0)):.6g}, budget={float(best.get('energy_budget_error', 0.0)):.6g}.",
        f"6. Next move: {next_answer}.",
        f"369 controls: no_servo_phase={float(no_servo.get('phase_lock_target', 0.0)):.6g}, wrong_sign_phase={float(wrong.get('phase_lock_target', 0.0)):.6g}, random_phase={float(random_control.get('phase_lock_target', 0.0)):.6g}.",
        f"Promotion gate: {len(passed_rows)} validated discovery rows passed; {len(core_rows)} discovery rows met the core 4x gates before dt preservation.",
        "",
        "## Best By Actuator",
    ]
    for actuator_type, row in by_actuator.items():
        lines.append(
            f"- {actuator_type}: case={row.get('candidate_id')}, phase={float(row.get('phase_lock_target', 0.0)):.6g}, "
            f"purity={float(row.get('spectral_purity_target', 0.0)):.6g}, bridge={float(row.get('bridge_ratio', 0.0)):.6g}, "
            f"work={float(row.get('servo_work_fraction', 0.0)):.6g}, gain={float(row.get('servo_gain_vs_baseline', 0.0)):.6g}, "
            f"pass={row.get('passed')}, failure={row.get('failure_mode', '')}"
        )
    lines.extend(["", "## Top Rows"])
    for row in ranked[:24]:
        lines.append(
            f"- {row.get('candidate_id')}: target={row.get('target_family')}, actuator={row.get('actuator_type')}, mode={row.get('control_mode')}, "
            f"Kp={float(row.get('Kp', 0.0)):.6g}, Ki={float(row.get('Ki', 0.0)):.6g}, score={float(row.get('bridge_phase_servo_score', 0.0)):.6g}, "
            f"pass={row.get('passed')}, 4x={row.get('4x_pass')}, phase={float(row.get('phase_lock_target', 0.0)):.6g}, "
            f"purity={float(row.get('spectral_purity_target', 0.0)):.6g}, bridge={float(row.get('bridge_ratio', 0.0)):.6g}, "
            f"work={float(row.get('servo_work_fraction', 0.0)):.6g}, budget={float(row.get('energy_budget_error', 0.0)):.6g}, "
            f"gain={float(row.get('servo_gain_vs_baseline', 0.0)):.6g}, failure={row.get('failure_mode', '')}"
        )
    if validation_rows:
        lines.extend(["", "## Dt Validation"])
        for row in validation_rows[:20]:
            lines.append(
                f"- {row.get('candidate_id')}: test={row.get('validation_test', '')}, phase={float(row.get('phase_lock_target', 0.0)):.6g}, "
                f"work={float(row.get('servo_work_fraction', 0.0)):.6g}, budget={float(row.get('energy_budget_error', 0.0)):.6g}, 4x={row.get('4x_pass')}"
            )
    (out_dir / "README_BRIDGE_PHASE_SERVO_REPORT.md").write_text("\n".join(lines), encoding="utf-8")


def experiment_bridge_phase_servo(out_dir: Path, seed: int, quick: bool = False,
                                  include_sweeps: bool = False) -> List[Dict[str, float | str]]:
    dt, base_tmax, sample_every = bridge_amp_timebase(quick)
    specs = bridge_phase_servo_specs(quick, include_sweeps)
    control_specs = bridge_phase_servo_control_specs(include_sweeps)
    summary_rows: List[Dict[str, float | str]] = []
    sweep_rows: List[Dict[str, float | str]] = []
    ledger_rows: List[Dict[str, float | str]] = []
    drift_rows: List[Dict[str, float | str]] = []
    controls: List[Dict[str, float | str]] = []
    config_by_case: Dict[str, BridgePhaseServoConfig] = {}
    baseline_by_key: Dict[Tuple[str, str, float], Dict[str, float | str]] = {}
    direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]] = {}
    run_index = 0

    all_configs = specs + control_specs
    baseline_specs: List[Tuple[str, str, BridgePhaseServoConfig]] = []
    seen_baselines = set()
    for _, _, config in all_configs:
        key = (config.target_family, config.seed_family, config.runtime_factor)
        if key in seen_baselines:
            continue
        seen_baselines.add(key)
        baseline = replace(
            config,
            name=f"phase_servo_{config.target_family}_{config.seed_family}_no_servo_r{safe_token(config.runtime_factor)}x",
            control_mode="no_servo",
            actuator_type="receiver_tuning_servo",
            correction_type="receiver_tuning_nudge",
            kp=0.0,
            ki=0.0,
            correction_clamp=0.0,
            reference_role="control",
            note="no-servo phase baseline",
        )
        baseline_specs.append(("no_servo", config.seed_family, baseline))

    for sweep, value, config in baseline_specs + all_configs:
        runtime = base_tmax * 1.25 * float(config.runtime_factor)
        baseline_key = (config.target_family, config.seed_family, config.runtime_factor)
        baseline_row = baseline_by_key.get(baseline_key)
        row, ledger, drift = bridge_phase_servo_measure(
            config,
            seed + run_index * 307,
            quick,
            dt,
            runtime,
            sample_every,
            direct_cache,
            baseline_row,
        )
        run_index += 1
        row["sweep"] = sweep
        row["sweep_value"] = value
        summary_rows.append(row)
        if str(config.control_mode) == "no_servo":
            baseline_by_key[baseline_key] = row
        if include_sweeps or str(config.reference_role) == "discovery_candidate":
            sweep_rows.append(row)
        if str(config.reference_role) == "control" or str(config.control_mode) != "normal" or str(config.family) == "non369":
            controls.append(row)
        if str(config.reference_role) == "control" or str(config.control_mode) != "normal" or abs(float(row.get("correction_peak", 0.0))) >= 0.004:
            ledger_rows.extend(ledger)
            drift_rows.extend(drift)
        config_by_case[config.name] = config

    ranked = sorted(
        summary_rows,
        key=lambda r: (
            float(r.get("bridge_phase_servo_score", 0.0)),
            1.0 if str(r.get("reference_role")) == "discovery_candidate" else 0.0,
            1.0 if str(r.get("4x_pass")) == "True" else 0.0,
            float(r.get("phase_lock_target", 0.0)),
            float(r.get("servo_gain_vs_baseline", 0.0)),
            -float(r.get("servo_work_fraction", 1.0)),
        ),
        reverse=True,
    )

    validation_rows: List[Dict[str, float | str]] = []
    top_candidates = [r for r in ranked if str(r.get("reference_role")) == "discovery_candidate" and str(r.get("control_mode")) == "normal" and float(r.get("runtime_factor", 1.0)) >= 4.0][:4 if include_sweeps else 2]
    for idx, candidate in enumerate(top_candidates):
        config = config_by_case.get(str(candidate.get("case")))
        if config is None:
            continue
        runtime = base_tmax * 1.25 * float(config.runtime_factor)
        rows, ledger, drift = bridge_phase_servo_validation(config, seed + 91000 + idx * 1000, quick, dt, runtime, sample_every)
        validation_rows.extend(rows)
        ledger_rows.extend(ledger)
        drift_rows.extend(drift)
        apply_bridge_phase_servo_validation_status(candidate, validation_rows)

    ranked = sorted(
        summary_rows,
        key=lambda r: (
            float(r.get("bridge_phase_servo_score", 0.0)),
            1.0 if str(r.get("reference_role")) == "discovery_candidate" else 0.0,
            1.0 if str(r.get("4x_pass")) == "True" else 0.0,
            float(r.get("phase_lock_target", 0.0)),
            float(r.get("servo_gain_vs_baseline", 0.0)),
            -float(r.get("servo_work_fraction", 1.0)),
        ),
        reverse=True,
    )

    write_csv(out_dir / "bridge_phase_servo_summary.csv", summary_rows + validation_rows)
    write_csv(out_dir / "bridge_phase_servo_ranked.csv", ranked)
    write_csv(out_dir / "bridge_phase_servo_sweeps.csv", sweep_rows)
    write_csv(out_dir / "bridge_phase_servo_timeseries.csv", ledger_rows + drift_rows)
    write_bridge_phase_servo_report(out_dir, ranked, validation_rows, controls)

    return [
        {
            "experiment": "bridge_phase_servo",
            "case": row.get("case", ""),
            "freqs": row.get("freqs", ""),
            "score": row.get("bridge_phase_servo_score", 0.0),
            "passed": row.get("passed", "False"),
            "promotion_ready": row.get("promotion_ready", "False"),
            "target_family": row.get("target_family", ""),
            "actuator_type": row.get("actuator_type", ""),
            "phase_lock_target": row.get("phase_lock_target", 0.0),
            "spectral_purity_target": row.get("spectral_purity_target", 0.0),
            "bridge_ratio": row.get("bridge_ratio", 0.0),
            "servo_work_fraction": row.get("servo_work_fraction", 0.0),
            "servo_gain_vs_baseline": row.get("servo_gain_vs_baseline", 0.0),
            "energy_budget_error": row.get("energy_budget_error", 0.0),
            "failure_mode": row.get("failure_mode", ""),
            "note": row.get("note", ""),
        }
        for row in ranked[:20]
    ]


# ----------------------------
# Experiment 21: bridge emergent lock
# ----------------------------

def bridge_emergent_lock_peak_frequency(config: BridgeAmpConfig,
                                        sim: Dict[str, object],
                                        start_fraction: float = 0.50,
                                        end_fraction: float = 1.0,
                                        span_fraction: float = 0.025,
                                        n_grid: int = 81,
                                        base_hz: float = 0.045) -> Tuple[float, float, float]:
    times = sim["times"]  # type: ignore[assignment]
    qs = sim["qs"]  # type: ignore[assignment]
    vs = sim["vs"]  # type: ignore[assignment]
    omega = sim["omega"]  # type: ignore[assignment]
    drive_until = float(sim["drive_until"])
    if len(times) < 12:
        return config.target_9, 0.0, 0.0
    mask = (times >= start_fraction * drive_until) & (times <= end_fraction * drive_until)
    if int(np.sum(mask)) < 12:
        mask = times >= 0.50 * times[-1]
    t_win = times[mask]
    q_win = qs[mask, 2]
    v_win = vs[mask, 2]
    if len(t_win) < 12:
        return config.target_9, 0.0, 0.0
    target = float(config.target_9)
    low = target * (1.0 - span_fraction)
    high = target * (1.0 + span_fraction)
    freqs = np.linspace(low, high, n_grid)
    scores = []
    for freq in freqs:
        q_amp = abs(complex_projection(q_win, t_win, base_hz * freq))
        v_amp = abs(complex_projection(v_win, t_win, base_hz * freq))
        scores.append(q_amp * q_amp + (v_amp / max(float(omega[2]), 1e-12)) ** 2)
    score_arr = np.asarray(scores)
    best_idx = int(np.argmax(score_arr))
    best = float(freqs[best_idx])
    if 0 < best_idx < len(freqs) - 1:
        y0, y1, y2 = score_arr[best_idx - 1], score_arr[best_idx], score_arr[best_idx + 1]
        denom = y0 - 2.0 * y1 + y2
        if abs(float(denom)) > 1e-18:
            offset = 0.5 * float(y0 - y2) / float(denom)
            best = float(freqs[best_idx] + offset * (freqs[1] - freqs[0]))
            best = float(np.clip(best, low, high))
    nominal_energy = target_mode_energy(q_win, v_win, t_win, base_hz * target, float(omega[2]))
    fitted_energy = target_mode_energy(q_win, v_win, t_win, base_hz * best, float(omega[2]))
    return best, fitted_energy, nominal_energy


def bridge_emergent_phase_lock_at(config: BridgeAmpConfig,
                                  sim: Dict[str, object],
                                  target_frequency: float,
                                  start_fraction: float = 0.50,
                                  end_fraction: float = 1.0,
                                  base_hz: float = 0.045) -> Tuple[float, float, float]:
    times = sim["times"]  # type: ignore[assignment]
    qs = sim["qs"]  # type: ignore[assignment]
    drive_until = float(sim["drive_until"])
    if len(times) < 12:
        return 0.0, float("nan"), 0.0
    mask = (times >= start_fraction * drive_until) & (times <= end_fraction * drive_until)
    if int(np.sum(mask)) < 12:
        mask = times >= 0.50 * times[-1]
    if int(np.sum(mask)) < 12:
        return 0.0, float("nan"), 0.0
    lock, lock_std = bridge_phase_lock(
        times[mask],
        qs[mask],
        base_hz,
        config.mode_freqs[0],
        config.target_6,
        target_frequency,
        0,
        1,
        2,
        float(sim["dt_sample"]),
    )
    amp = abs(complex_projection(qs[mask, 2], times[mask], base_hz * target_frequency))
    return lock, lock_std, float(amp)


def bridge_emergent_lock_diagnostics(config: BridgeAmpConfig,
                                     sim: Dict[str, object],
                                     direct_sim: Dict[str, object] | None,
                                     start_fraction: float = 0.50,
                                     end_fraction: float = 1.0,
                                     base_hz: float = 0.045
                                     ) -> Tuple[List[Dict[str, float | str]], Dict[str, float | str]]:
    times = sim["times"]  # type: ignore[assignment]
    qs = sim["qs"]  # type: ignore[assignment]
    vs = sim["vs"]  # type: ignore[assignment]
    energy = sim["energy"]  # type: ignore[assignment]
    omega = sim["omega"]  # type: ignore[assignment]
    drive_until = float(sim["drive_until"])
    if len(times) < 40:
        return [], {
            "fitted_effective_target_frequency": config.target_9,
            "detuning_delta": 0.0,
            "normalized_detuning_delta": 0.0,
            "detuning_drift_rate": 0.0,
            "emergent_phase_lock_target": 0.0,
            "nominal_phase_lock_target": 0.0,
            "spectral_purity_target": 0.0,
            "nominal_spectral_purity_target": 0.0,
            "bridge_ratio": 0.0,
        }

    fitted, fitted_energy, nominal_energy = bridge_emergent_lock_peak_frequency(config, sim, start_fraction, end_fraction)
    emergent_lock, emergent_std, _ = bridge_emergent_phase_lock_at(config, sim, fitted, start_fraction, end_fraction)
    nominal_lock, nominal_std, _ = bridge_emergent_phase_lock_at(config, sim, config.target_9, start_fraction, end_fraction)
    mask = (times >= start_fraction * drive_until) & (times <= end_fraction * drive_until)
    if int(np.sum(mask)) < 12:
        mask = times >= 0.50 * times[-1]
    total_target_energy = float(np.mean(energy[mask, 2]) + 1e-18) if int(np.sum(mask)) else 1e-18
    direct_energy = 0.0
    if direct_sim is not None and int(np.sum(mask)) >= 4:
        direct_times = direct_sim["times"]  # type: ignore[index]
        direct_qs = direct_sim["qs"]  # type: ignore[index]
        direct_vs = direct_sim["vs"]  # type: ignore[index]
        direct_omega = direct_sim["omega"]  # type: ignore[index]
        dmask = (direct_times >= float(times[mask][0])) & (direct_times <= float(times[mask][-1]))
        if int(np.sum(dmask)) >= 4:
            direct_energy = target_mode_energy(
                direct_qs[dmask, 2],
                direct_vs[dmask, 2],
                direct_times[dmask],
                base_hz * fitted,
                float(direct_omega[2]),
            )

    start_idx = int(np.searchsorted(times, start_fraction * drive_until))
    stop_idx = int(np.searchsorted(times, end_fraction * drive_until))
    start_idx = max(0, min(start_idx, len(times) - 2))
    stop_idx = max(start_idx + 2, min(stop_idx, len(times)))
    window = max(30, int(6.0 / max(float(sim["dt_sample"]), 1e-9)))
    step = max(8, window // 3)
    rows: List[Dict[str, float | str]] = []
    for start in range(start_idx, max(start_idx + 1, stop_idx - window), step):
        stop = min(start + window, stop_idx)
        if stop - start < 12:
            continue
        local_sim = {
            "times": times[start:stop],
            "qs": qs[start:stop],
            "vs": vs[start:stop],
            "energy": energy[start:stop],
            "omega": omega,
            "drive_until": float(times[stop - 1]),
            "dt_sample": sim["dt_sample"],
        }
        local_fitted, local_energy, local_nominal_energy = bridge_emergent_lock_peak_frequency(config, local_sim, 0.0, 1.0, span_fraction=0.025, n_grid=51)
        local_lock, _, _ = bridge_emergent_phase_lock_at(config, local_sim, local_fitted, 0.0, 1.0)
        local_nominal_lock, _, _ = bridge_emergent_phase_lock_at(config, local_sim, config.target_9, 0.0, 1.0)
        local_total = float(np.mean(energy[start:stop, 2]) + 1e-18)
        rows.append({
            "time_mid": float(np.mean(times[start:stop])),
            "fitted_effective_target_frequency": local_fitted,
            "detuning_delta": local_fitted - float(config.target_9),
            "normalized_detuning_delta": (local_fitted - float(config.target_9)) / max(float(config.target_9), 1e-18),
            "emergent_phase_lock_target": local_lock,
            "nominal_phase_lock_target": local_nominal_lock,
            "spectral_purity_target": float(min(1.0, local_energy / local_total)),
            "nominal_spectral_purity_target": float(min(1.0, local_nominal_energy / local_total)),
        })
    if len(rows) >= 2:
        t_mid = np.asarray([float(r["time_mid"]) for r in rows])
        detuning = np.asarray([float(r["detuning_delta"]) for r in rows])
        detuning_drift_rate = float(np.polyfit(t_mid, detuning, 1)[0])
    else:
        detuning_drift_rate = 0.0

    detuning_delta = fitted - float(config.target_9)
    summary = {
        "fitted_effective_target_frequency": fitted,
        "detuning_delta": detuning_delta,
        "normalized_detuning_delta": detuning_delta / max(float(config.target_9), 1e-18),
        "detuning_drift_rate": detuning_drift_rate,
        "emergent_phase_lock_target": emergent_lock,
        "emergent_phase_lock_target_std": emergent_std,
        "nominal_phase_lock_target": nominal_lock,
        "nominal_phase_lock_target_std": nominal_std,
        "spectral_purity_target": float(min(1.0, fitted_energy / total_target_energy)),
        "nominal_spectral_purity_target": float(min(1.0, nominal_energy / total_target_energy)),
        "bridge_ratio": metric_ratio(fitted_energy, direct_energy),
        "energy_at_emergent_target": fitted_energy,
        "energy_at_nominal_target": nominal_energy,
        "energy_at_emergent_target_from_direct_reference": direct_energy,
    }
    return rows, summary


def bridge_emergent_lock_family_templates(quick: bool, include_sweeps: bool) -> List[Tuple[str, str, str, BridgeMinNudgeConfig]]:
    templates = [
        ("369", "autolock_seed_s0p9", "369", bridge_phase_servo_template("autolock_seed_s0p9", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.90)),
        ("369", "magnetic_stageB0p84_lead", "369", bridge_phase_servo_template("magnetic_stageB0p84_lead", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.84)),
        ("369", "feedforward_best_magnetic_bias", "369", bridge_phase_servo_template("feedforward_best_magnetic_bias", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=0.84)),
        ("4812", "non369_4_8_12", "non369", bridge_phase_servo_non369_template(4.0, 12.0)),
        ("51015", "non369_5_10_15", "non369", bridge_phase_servo_non369_template(5.0, 15.0)),
        ("61218", "non369_6_12_18", "non369", bridge_phase_servo_non369_template(6.0, 18.0)),
    ]
    if include_sweeps:
        receiver_values = [8.86, 8.90, 8.93] if quick else [8.86, 8.875, 8.90, 8.915, 8.93]
        phase_values = [15.0, 25.0, 35.0] if quick else [15.0, 20.0, 25.0, 30.0, 35.0]
        strength_values = [0.80, 0.84, 0.94] if quick else [0.80, 0.84, 0.88, 0.90, 0.94]
        for receiver in receiver_values:
            templates.append(("369", f"sweep_receiver_{safe_token(receiver)}", "369", bridge_phase_servo_template(f"sweep_receiver_{safe_token(receiver)}", receiver_tuning=receiver, phase_bias=30.0, stage_b_strength=0.84)))
        for phase in phase_values:
            templates.append(("369", f"sweep_phase_{safe_token(phase)}", "369", bridge_phase_servo_template(f"sweep_phase_{safe_token(phase)}", receiver_tuning=8.90, phase_bias=phase, stage_b_strength=0.84)))
        for strength in strength_values:
            templates.append(("369", f"sweep_stageB_{safe_token(strength)}", "369", bridge_phase_servo_template(f"sweep_stageB_{safe_token(strength)}", receiver_tuning=8.90, phase_bias=30.0, stage_b_strength=strength)))
    return templates


def bridge_emergent_lock_make_config(target_family: str,
                                     seed_family: str,
                                     family: str,
                                     base_config: BridgeMinNudgeConfig,
                                     actuator_type: str,
                                     control_mode: str,
                                     kp: float,
                                     ki: float,
                                     clamp: float,
                                     smoothing: float,
                                     update_interval: float,
                                     runtime_factor: float = 4.0,
                                     reference_role: str | None = None,
                                     suffix: str = "") -> BridgePhaseServoConfig:
    reference = reference_role if reference_role is not None else ("discovery_candidate" if family == "369" else "control")
    config = bridge_phase_servo_make_config(
        target_family,
        seed_family,
        base_config,
        actuator_type,
        kp,
        ki,
        clamp,
        smoothing,
        update_interval,
        runtime_factor=runtime_factor,
        control_mode=control_mode,
        reference_role=reference,
        family=family,
        suffix=suffix,
    )
    return replace(
        config,
        name=config.name.replace("phase_servo", "emergent_lock", 1),
        note="emergent pulled-frequency diagnostic; existing discovery gates remain strict",
    )


def bridge_emergent_lock_specs(quick: bool, include_sweeps: bool) -> List[Tuple[str, str, BridgePhaseServoConfig]]:
    gain_sets = [
        ("gentle_pi", 0.0015, 0.000020, 0.018, 0.18, 2.0),
        ("modest_pi", 0.0030, 0.000045, 0.024, 0.22, 1.5),
    ]
    if include_sweeps:
        gain_sets.extend([
            ("tiny_pi", 0.00075, 0.000008, 0.012, 0.14, 2.5),
            ("firm_pi", 0.0045, 0.000060, 0.036, 0.25, 1.0),
        ])
    runtime_factors = [4.0]
    if include_sweeps:
        runtime_factors = [1.0, 2.0, 4.0]
    specs: List[Tuple[str, str, BridgePhaseServoConfig]] = []
    for target_family, seed_family, family, base_config in bridge_emergent_lock_family_templates(quick, include_sweeps):
        is_sweep_seed = seed_family.startswith("sweep_")
        active_gain_sets = [gain_sets[0]] if is_sweep_seed else gain_sets
        for runtime_factor in runtime_factors:
            if include_sweeps and runtime_factor < 4.0 and seed_family != "autolock_seed_s0p9":
                continue
            baseline = bridge_emergent_lock_make_config(
                target_family,
                seed_family,
                family,
                base_config,
                "receiver_tuning_servo",
                "no_servo",
                0.0,
                0.0,
                0.0,
                0.18,
                2.0,
                runtime_factor=runtime_factor,
                suffix="baseline",
            )
            specs.append(("no_servo_baseline", seed_family, baseline))
            for actuator_type in BRIDGE_PHASE_SERVO_ACTUATORS:
                for label, kp, ki, clamp, smoothing, update_interval in active_gain_sets:
                    config = bridge_emergent_lock_make_config(
                        target_family,
                        seed_family,
                        family,
                        base_config,
                        actuator_type,
                        "normal",
                        kp,
                        ki,
                        clamp,
                        smoothing,
                        update_interval,
                        runtime_factor=runtime_factor,
                        suffix=label,
                    )
                    specs.append((label, seed_family, config))
    return specs


def bridge_emergent_lock_measure(config: BridgePhaseServoConfig, seed: int, quick: bool,
                                 dt: float, runtime: float, sample_every: int,
                                 direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]]
                                 ) -> Tuple[Dict[str, float | str], List[Dict[str, float | str]], List[Dict[str, float | str]]]:
    sim, ledger = simulate_bridge_phase_servo(config, seed, quick, dt=dt, t_max=runtime, sample_every=sample_every)
    effective = sim["effective_config"]  # type: ignore[assignment]
    target_key = f"{effective.mode_freqs[0]:g}:{effective.target_6:g}:{effective.target_9:g}"
    cache_key = (target_key, dt, runtime)
    if cache_key not in direct_cache:
        direct_cfg = bridge_min_nudge_direct_reference(effective)
        direct_sim, _ = simulate_bridge_amp(direct_cfg, seed + 10400, quick, dt=dt, t_max=runtime, sample_every=sample_every)
        direct_row = bridge_metrics_window(direct_cfg, direct_sim, seed + 10400, "direct_reference", "direct_source_plus_generated", "reference", 0.35, 1.0)
        direct_cache[cache_key] = (direct_sim, direct_row)
    direct_sim, direct_row = direct_cache[cache_key]

    nominal_row = bridge_metrics_window(effective, sim, seed, "emergent_lock", config.control_mode, f"{config.kp:g}:{config.ki:g}", 0.35, 1.0)
    diagnostic_rows, diagnostic_summary = bridge_emergent_lock_diagnostics(effective, sim, direct_sim, 0.50, 1.0)
    phase_rows, phase_summary = bridge_phase_diagnostic_series(effective, sim, direct_sim, 0.50, 1.0)
    row = dict(nominal_row)
    row.update(diagnostic_summary)
    row["phase_drift_rate"] = phase_summary.get("phase_drift_rate", 0.0)
    row["lock_duration"] = phase_summary.get("lock_duration", 0.0)
    row["time_to_unlock"] = phase_summary.get("time_to_unlock", 0.0)
    row["experiment"] = "bridge_emergent_lock"
    row["case"] = config.name
    row["candidate_id"] = f"{config.name}:{config.runtime_factor:g}x"
    row["target_family"] = config.target_family
    row["source_frequency"] = effective.mode_freqs[0]
    row["generated_frequency"] = effective.target_6
    row["nominal_target"] = effective.target_9
    row["actuator_type"] = config.actuator_type
    row["correction_type"] = config.correction_type
    row["control_mode"] = config.control_mode
    row["Kp"] = config.kp
    row["Ki"] = config.ki
    row["correction_clamp"] = config.correction_clamp
    row["smoothing"] = config.smoothing
    row["update_interval"] = config.update_interval
    row["runtime_factor"] = config.runtime_factor
    row["seed_family"] = config.seed_family
    row["reference_role"] = config.reference_role
    row["family"] = config.family
    row["nominal_phase_lock_target"] = diagnostic_summary.get("nominal_phase_lock_target", row.get("phase_lock_9", 0.0))
    row["nominal_spectral_purity_target"] = diagnostic_summary.get("nominal_spectral_purity_target", row.get("spectral_purity_9", 0.0))
    row["nominal_bridge_ratio"] = metric_ratio(float(row.get("energy_at_9", 0.0)), float(direct_row.get("energy_at_9", 0.0)))
    row["phase_lock_target"] = row["emergent_phase_lock_target"]
    row["energy_at_target"] = row["energy_at_emergent_target"]
    total_input_before = max(float(row.get("total_input_work", 0.0)), 1e-18)
    total_input_with_servo = total_input_before + float(sim["servo_work"])
    row["total_input_work_before_servo"] = total_input_before
    row["total_input_work"] = total_input_with_servo
    row["servo_work"] = float(sim["servo_work"])
    row["servo_work_signed"] = float(sim["servo_work_signed"])
    row["servo_work_fraction"] = metric_ratio(float(sim["servo_work"]), total_input_with_servo)
    row["correction_work"] = row["servo_work"]
    row["correction_work_fraction"] = row["servo_work_fraction"]
    row["correction_rms"] = float(sim["correction_rms"])
    row["correction_peak"] = float(sim["correction_peak"])
    row["detuning_reproducibility"] = 0.0
    row["seed_preserved"] = "False"
    row["half_dt_preserved"] = "False"
    row["quarter_dt_preserved"] = "False"
    row["no_direct_2f_drive"] = str(not any(abs(freq - effective.target_6) < 1e-9 and mode == 1 for freq, mode in zip(effective.drive_freqs, effective.drive_modes)))
    row["no_direct_3f_drive"] = str(not any(abs(freq - effective.target_9) < 1e-9 and mode == 2 for freq, mode in zip(effective.drive_freqs, effective.drive_modes)))
    row["no_target_frequency_injection"] = row["no_direct_3f_drive"]
    row["note"] = config.note
    bridge_emergent_lock_update_labels(row)

    for item in ledger:
        item["experiment"] = "bridge_emergent_lock"
        item["candidate_id"] = row["candidate_id"]
        item["target_family"] = config.target_family
        item["runtime_factor"] = config.runtime_factor
    for item in diagnostic_rows:
        item["experiment"] = "bridge_emergent_lock"
        item["case"] = config.name
        item["candidate_id"] = row["candidate_id"]
        item["target_family"] = config.target_family
        item["runtime_factor"] = config.runtime_factor
        item["diagnostic_type"] = "emergent_frequency_window"
    for item in phase_rows:
        item["experiment"] = "bridge_emergent_lock"
        item["case"] = config.name
        item["candidate_id"] = row["candidate_id"]
        item["target_family"] = config.target_family
        item["runtime_factor"] = config.runtime_factor
        item["diagnostic_type"] = "nominal_phase_window"
    return row, ledger, diagnostic_rows + phase_rows


def bridge_emergent_lock_core_gate(row: Dict[str, float | str]) -> bool:
    return (
        float(row.get("runtime_factor", 1.0)) >= 4.0
        and float(row.get("emergent_phase_lock_target", 0.0)) > 0.90
        and float(row.get("spectral_purity_target", 0.0)) > 0.60
        and float(row.get("bridge_ratio", 0.0)) > 0.75
        and float(row.get("energy_budget_error", 1.0)) < 0.005
        and float(row.get("servo_work_fraction", 0.0)) < 0.05
        and str(row.get("no_direct_2f_drive", "False")) == "True"
        and str(row.get("no_direct_3f_drive", "False")) == "True"
        and str(row.get("no_target_frequency_injection", "False")) == "True"
    )


def bridge_emergent_lock_update_labels(row: Dict[str, float | str]) -> None:
    core = bridge_emergent_lock_core_gate(row)
    has_validation = "detuning_reproducibility" in row and float(row.get("detuning_reproducibility", 0.0)) > 0.0
    dt_seed_ok = (
        str(row.get("seed_preserved", "False")) == "True"
        and str(row.get("half_dt_preserved", "False")) == "True"
        and str(row.get("quarter_dt_preserved", "False")) == "True"
        and float(row.get("detuning_reproducibility", 0.0)) >= 0.70
    )
    harmonic = core and has_validation and dt_seed_ok
    pulled = (
        harmonic
        and float(row.get("nominal_phase_lock_target", 0.0)) <= 0.90
        and float(row.get("emergent_phase_lock_target", 0.0)) > 0.90
        and abs(float(row.get("normalized_detuning_delta", 0.0))) > 2.0e-4
        and abs(float(row.get("detuning_drift_rate", 0.0))) < 5.0e-3
    )
    failures = []
    if float(row.get("runtime_factor", 1.0)) < 4.0:
        failures.append("not_4x_runtime")
    if float(row.get("emergent_phase_lock_target", 0.0)) <= 0.90:
        failures.append("emergent_phase_lock_target")
    if float(row.get("spectral_purity_target", 0.0)) <= 0.60:
        failures.append("spectral_purity_target")
    if float(row.get("bridge_ratio", 0.0)) <= 0.75:
        failures.append("bridge_ratio")
    if float(row.get("energy_budget_error", 1.0)) >= 0.005:
        failures.append("energy_budget")
    if float(row.get("servo_work_fraction", 0.0)) >= 0.05:
        failures.append("servo_work_fraction")
    if str(row.get("no_direct_2f_drive", "False")) != "True" or str(row.get("no_direct_3f_drive", "False")) != "True":
        failures.append("direct_drive_contamination")
    if has_validation and not dt_seed_ok:
        failures.append("detuning_reproducibility")

    if not failures:
        failure_mode = "emergent_lock_candidate"
    elif "emergent_phase_lock_target" in failures:
        failure_mode = "no_emergent_lock"
    elif "energy_budget" in failures:
        failure_mode = "energy_budget_drift"
    elif "bridge_ratio" in failures:
        failure_mode = "weak_bridge_ratio"
    elif "detuning_reproducibility" in failures:
        failure_mode = "unstable_pulled_frequency"
    else:
        failure_mode = failures[0]

    normalized_score = (
        float(row.get("emergent_phase_lock_target", 0.0))
        * float(row.get("spectral_purity_target", 0.0))
        * min(3.0, float(row.get("bridge_ratio", 0.0)))
        / (
            1.0
            + 650.0 * max(0.0, float(row.get("energy_budget_error", 0.0)))
            + 130.0 * max(0.0, float(row.get("servo_work_fraction", 0.0)))
            + 6.0 * abs(float(row.get("normalized_detuning_delta", 0.0)))
            + 12.0 * abs(float(row.get("detuning_drift_rate", 0.0)))
        )
    )
    score = normalized_score if core and str(row.get("reference_role")) == "discovery_candidate" else 0.0
    row["core_harmonic_bridge_candidate"] = str(core)
    row["harmonic_bridge_candidate"] = str(harmonic)
    row["pulled_frequency_discovery"] = str(pulled)
    row["369_unique_candidate"] = str(False)
    row["passed"] = str(harmonic and str(row.get("reference_role")) == "discovery_candidate")
    row["promotion_ready"] = str(pulled and str(row.get("target_family")) == "369")
    row["failed_gate_names"] = ";".join(failures)
    row["failure_mode"] = failure_mode
    row["normalized_emergent_score"] = normalized_score
    row["bridge_emergent_lock_score"] = score
    row["score"] = score


def bridge_emergent_lock_validation(config: BridgePhaseServoConfig, seed: int, quick: bool,
                                    dt: float, runtime: float, sample_every: int
                                    ) -> Tuple[List[Dict[str, float | str]], List[Dict[str, float | str]], List[Dict[str, float | str]]]:
    tests = [("repeat_seed", dt, seed + 101), ("half_dt", dt * 0.5, seed + 211), ("quarter_dt", dt * 0.25, seed + 307)]
    rows: List[Dict[str, float | str]] = []
    ledger_rows: List[Dict[str, float | str]] = []
    diagnostic_rows: List[Dict[str, float | str]] = []
    for name, test_dt, test_seed in tests:
        direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]] = {}
        row, ledger, diag = bridge_emergent_lock_measure(config, test_seed, quick, test_dt, runtime, sample_every, direct_cache)
        row["validation_test"] = name
        rows.append(row)
        ledger_rows.extend(ledger)
        diagnostic_rows.extend(diag)
    return rows, ledger_rows, diagnostic_rows


def apply_bridge_emergent_lock_validation(candidate: Dict[str, float | str],
                                          validation_rows: List[Dict[str, float | str]]) -> None:
    rows = [r for r in validation_rows if str(r.get("case")) == str(candidate.get("case"))]
    repeat = next((r for r in rows if str(r.get("validation_test")) == "repeat_seed"), {})
    half = next((r for r in rows if str(r.get("validation_test")) == "half_dt"), {})
    quarter = next((r for r in rows if str(r.get("validation_test")) == "quarter_dt"), {})
    base_delta = float(candidate.get("detuning_delta", 0.0))
    base_lock = float(candidate.get("emergent_phase_lock_target", 0.0))

    def preserved(row: Dict[str, float | str]) -> bool:
        if not row:
            return False
        delta_ok = ratio_stability_score(float(row.get("detuning_delta", 0.0)), base_delta) > 0.55 if abs(base_delta) > 1e-8 else abs(float(row.get("detuning_delta", 0.0))) < 0.01
        lock_ok = float(row.get("emergent_phase_lock_target", 0.0)) >= 0.90 or ratio_stability_score(float(row.get("emergent_phase_lock_target", 0.0)), base_lock) > 0.85
        budget_ok = float(row.get("energy_budget_error", 1.0)) < 0.005
        work_ok = float(row.get("servo_work_fraction", 0.0)) < 0.05
        return delta_ok and lock_ok and budget_ok and work_ok

    seed_ok = preserved(repeat)
    half_ok = preserved(half)
    quarter_ok = preserved(quarter)
    scores = []
    for row in [repeat, half, quarter]:
        if row:
            delta_score = ratio_stability_score(float(row.get("detuning_delta", 0.0)), base_delta) if abs(base_delta) > 1e-8 else max(0.0, 1.0 - abs(float(row.get("detuning_delta", 0.0))) / 0.01)
            lock_score = ratio_stability_score(float(row.get("emergent_phase_lock_target", 0.0)), base_lock)
            scores.append(min(delta_score, lock_score))
    reproducibility = min(scores) if scores else 0.0
    candidate["seed_preserved"] = str(seed_ok)
    candidate["half_dt_preserved"] = str(half_ok)
    candidate["quarter_dt_preserved"] = str(quarter_ok)
    candidate["detuning_reproducibility"] = reproducibility
    candidate["repeat_seed_detuning_delta"] = float(repeat.get("detuning_delta", 0.0))
    candidate["half_dt_detuning_delta"] = float(half.get("detuning_delta", 0.0))
    candidate["quarter_dt_detuning_delta"] = float(quarter.get("detuning_delta", 0.0))
    candidate["repeat_seed_emergent_phase_lock"] = float(repeat.get("emergent_phase_lock_target", 0.0))
    candidate["half_dt_emergent_phase_lock"] = float(half.get("emergent_phase_lock_target", 0.0))
    candidate["quarter_dt_emergent_phase_lock"] = float(quarter.get("emergent_phase_lock_target", 0.0))
    bridge_emergent_lock_update_labels(candidate)


def annotate_bridge_emergent_lock_uniqueness(rows: List[Dict[str, float | str]]) -> None:
    non369_best = max(
        [float(r.get("normalized_emergent_score", 0.0)) for r in rows if str(r.get("target_family")) != "369"],
        default=0.0,
    )
    for row in rows:
        unique = (
            str(row.get("target_family")) == "369"
            and str(row.get("harmonic_bridge_candidate")) == "True"
            and float(row.get("normalized_emergent_score", 0.0)) > non369_best * 1.02
        )
        row["369_unique_candidate"] = str(unique)
        if unique and str(row.get("pulled_frequency_discovery")) == "True":
            row["promotion_ready"] = str(True)


def write_bridge_emergent_lock_report(out_dir: Path,
                                      ranked: List[Dict[str, float | str]],
                                      validation_rows: List[Dict[str, float | str]]) -> None:
    discovery = [r for r in ranked if str(r.get("reference_role")) == "discovery_candidate"]
    best = ranked[0] if ranked else {}
    best_369 = max([r for r in ranked if str(r.get("target_family")) == "369"], key=lambda r: float(r.get("normalized_emergent_score", 0.0)), default={})
    by_family: Dict[str, Dict[str, float | str]] = {}
    for family in ["369", "4812", "51015", "61218"]:
        rows = [r for r in ranked if str(r.get("target_family")) == family]
        if rows:
            by_family[family] = max(rows, key=lambda r: (float(r.get("normalized_emergent_score", 0.0)), float(r.get("emergent_phase_lock_target", 0.0))))
    harmonic = [r for r in ranked if str(r.get("harmonic_bridge_candidate")) == "True"]
    pulled = [r for r in ranked if str(r.get("pulled_frequency_discovery")) == "True"]
    unique = [r for r in ranked if str(r.get("369_unique_candidate")) == "True"]
    emergent_beats_nominal = float(best.get("emergent_phase_lock_target", 0.0)) > float(best.get("nominal_phase_lock_target", 0.0)) + 0.02
    if pulled:
        failure_answer = "yes; at least one row shows stable pulled-frequency lock while nominal lock fails"
    elif emergent_beats_nominal:
        failure_answer = "partially; emergent fitting improves phase lock, but not enough for the strict pulled-frequency label"
    else:
        failure_answer = "mostly nominal-target drift or broad harmonic behavior; no stable pulled-frequency promotion"
    non369_score = max([float(r.get("normalized_emergent_score", 0.0)) for r in ranked if str(r.get("target_family")) != "369"], default=0.0)
    beats = float(best_369.get("normalized_emergent_score", 0.0)) > non369_score * 1.02
    if unique:
        next_answer = "geometry/evolve is justified as a follow-up, with normalized non-369 controls retained"
    elif harmonic:
        next_answer = "general harmonic-bridge promotion, not 369-specific geometry/evolve"
    else:
        next_answer = "passive tuning or active PLL; geometry/evolve should wait"
    lines = [
        "# Bridge Emergent Lock Report",
        "",
        "This diagnostic track tests whether the bridge is locking to a pulled local target frequency. It does not weaken the existing nominal discovery gates.",
        "",
        "## Direct Answers",
        f"1. Is the 4x phase failure nominal drift or stable emergent-frequency lock? {failure_answer}.",
        f"2. Does 3 -> 6 -> 9 beat normalized controls? {'yes' if beats else 'no'}; score_369={float(best_369.get('normalized_emergent_score', 0.0)):.6g}, best_non369_score={non369_score:.6g}.",
        f"3. Cleanest phase/budget/work row: {best.get('candidate_id', 'none')}; family={best.get('target_family', '')}, emergent_lock={float(best.get('emergent_phase_lock_target', 0.0)):.6g}, budget={float(best.get('energy_budget_error', 0.0)):.6g}, work={float(best.get('servo_work_fraction', 0.0)):.6g}.",
        f"4. Next step: {next_answer}.",
        f"Promotion labels: harmonic_bridge_candidate={len(harmonic)}, 369_unique_candidate={len(unique)}, pulled_frequency_discovery={len(pulled)}.",
        "",
        "## Best By Family",
    ]
    for family, row in by_family.items():
        lines.append(
            f"- {family}: case={row.get('candidate_id')}, nominal_lock={float(row.get('nominal_phase_lock_target', 0.0)):.6g}, "
            f"emergent_lock={float(row.get('emergent_phase_lock_target', 0.0)):.6g}, fitted={float(row.get('fitted_effective_target_frequency', 0.0)):.6g}, "
            f"delta={float(row.get('detuning_delta', 0.0)):.6g}, purity={float(row.get('spectral_purity_target', 0.0)):.6g}, "
            f"bridge={float(row.get('bridge_ratio', 0.0)):.6g}, budget={float(row.get('energy_budget_error', 0.0)):.6g}, "
            f"work={float(row.get('servo_work_fraction', 0.0)):.6g}, harmonic={row.get('harmonic_bridge_candidate')}, failure={row.get('failure_mode', '')}"
        )
    lines.extend(["", "## Top Rows"])
    for row in ranked[:24]:
        lines.append(
            f"- {row.get('candidate_id')}: family={row.get('target_family')}, mode={row.get('control_mode')}, actuator={row.get('actuator_type')}, "
            f"nominal={float(row.get('nominal_phase_lock_target', 0.0)):.6g}, emergent={float(row.get('emergent_phase_lock_target', 0.0)):.6g}, "
            f"fitted={float(row.get('fitted_effective_target_frequency', 0.0)):.6g}, norm_delta={float(row.get('normalized_detuning_delta', 0.0)):.6g}, "
            f"purity={float(row.get('spectral_purity_target', 0.0)):.6g}, bridge={float(row.get('bridge_ratio', 0.0)):.6g}, "
            f"budget={float(row.get('energy_budget_error', 0.0)):.6g}, work={float(row.get('servo_work_fraction', 0.0)):.6g}, "
            f"score={float(row.get('normalized_emergent_score', 0.0)):.6g}, harmonic={row.get('harmonic_bridge_candidate')}, pulled={row.get('pulled_frequency_discovery')}, unique369={row.get('369_unique_candidate')}, failure={row.get('failure_mode', '')}"
        )
    if validation_rows:
        lines.extend(["", "## Reproducibility Checks"])
        for row in validation_rows[:20]:
            lines.append(
                f"- {row.get('candidate_id')}: test={row.get('validation_test', '')}, emergent={float(row.get('emergent_phase_lock_target', 0.0)):.6g}, "
                f"fitted={float(row.get('fitted_effective_target_frequency', 0.0)):.6g}, delta={float(row.get('detuning_delta', 0.0)):.6g}, "
                f"budget={float(row.get('energy_budget_error', 0.0)):.6g}, work={float(row.get('servo_work_fraction', 0.0)):.6g}"
            )
    (out_dir / "README_BRIDGE_EMERGENT_LOCK_REPORT.md").write_text("\n".join(lines), encoding="utf-8")


def experiment_bridge_emergent_lock(out_dir: Path, seed: int, quick: bool = False,
                                    include_sweeps: bool = False) -> List[Dict[str, float | str]]:
    dt, base_tmax, sample_every = bridge_amp_timebase(quick)
    specs = bridge_emergent_lock_specs(quick, include_sweeps)
    summary_rows: List[Dict[str, float | str]] = []
    timeseries_rows: List[Dict[str, float | str]] = []
    config_by_case: Dict[str, BridgePhaseServoConfig] = {}
    direct_cache: Dict[Tuple[str, float, float], Tuple[Dict[str, object], Dict[str, float | str]]] = {}
    for idx, (sweep, value, config) in enumerate(specs):
        runtime = base_tmax * 1.25 * float(config.runtime_factor)
        row, ledger, diag = bridge_emergent_lock_measure(config, seed + idx * 331, quick, dt, runtime, sample_every, direct_cache)
        row["sweep"] = sweep
        row["sweep_value"] = value
        summary_rows.append(row)
        config_by_case[str(row.get("case"))] = config
        if include_sweeps or str(config.control_mode) == "no_servo" or abs(float(row.get("correction_peak", 0.0))) >= 0.004:
            timeseries_rows.extend(diag)
        if str(config.control_mode) == "no_servo" or (str(config.reference_role) == "control" and str(config.target_family) != "369"):
            timeseries_rows.extend(ledger)

    ranked = sorted(
        summary_rows,
        key=lambda r: (
            float(r.get("bridge_emergent_lock_score", 0.0)),
            float(r.get("normalized_emergent_score", 0.0)),
            1.0 if str(r.get("reference_role")) == "discovery_candidate" else 0.0,
            float(r.get("emergent_phase_lock_target", 0.0)),
            -float(r.get("energy_budget_error", 1.0)),
        ),
        reverse=True,
    )
    validation_rows: List[Dict[str, float | str]] = []
    top_candidates = [r for r in ranked if float(r.get("runtime_factor", 1.0)) >= 4.0][:4 if include_sweeps else 3]
    for idx, candidate in enumerate(top_candidates):
        config = config_by_case.get(str(candidate.get("case")))
        if config is None:
            continue
        runtime = base_tmax * 1.25 * float(config.runtime_factor)
        rows, ledger, diag = bridge_emergent_lock_validation(config, seed + 97000 + idx * 1200, quick, dt, runtime, sample_every)
        validation_rows.extend(rows)
        timeseries_rows.extend(diag)
        if include_sweeps:
            timeseries_rows.extend(ledger)
        apply_bridge_emergent_lock_validation(candidate, validation_rows)
    annotate_bridge_emergent_lock_uniqueness(summary_rows)
    ranked = sorted(
        summary_rows,
        key=lambda r: (
            float(r.get("bridge_emergent_lock_score", 0.0)),
            float(r.get("normalized_emergent_score", 0.0)),
            1.0 if str(r.get("reference_role")) == "discovery_candidate" else 0.0,
            float(r.get("emergent_phase_lock_target", 0.0)),
            -float(r.get("energy_budget_error", 1.0)),
        ),
        reverse=True,
    )

    write_csv(out_dir / "bridge_emergent_lock_summary.csv", summary_rows + validation_rows)
    write_csv(out_dir / "bridge_emergent_lock_ranked.csv", ranked)
    write_csv(out_dir / "bridge_emergent_lock_timeseries.csv", timeseries_rows)
    write_bridge_emergent_lock_report(out_dir, ranked, validation_rows)
    return [
        {
            "experiment": "bridge_emergent_lock",
            "case": row.get("case", ""),
            "freqs": row.get("freqs", ""),
            "score": row.get("bridge_emergent_lock_score", 0.0),
            "passed": row.get("passed", "False"),
            "promotion_ready": row.get("promotion_ready", "False"),
            "target_family": row.get("target_family", ""),
            "nominal_phase_lock_target": row.get("nominal_phase_lock_target", 0.0),
            "emergent_phase_lock_target": row.get("emergent_phase_lock_target", 0.0),
            "fitted_effective_target_frequency": row.get("fitted_effective_target_frequency", 0.0),
            "detuning_delta": row.get("detuning_delta", 0.0),
            "spectral_purity_target": row.get("spectral_purity_target", 0.0),
            "bridge_ratio": row.get("bridge_ratio", 0.0),
            "energy_budget_error": row.get("energy_budget_error", 0.0),
            "servo_work_fraction": row.get("servo_work_fraction", 0.0),
            "harmonic_bridge_candidate": row.get("harmonic_bridge_candidate", "False"),
            "369_unique_candidate": row.get("369_unique_candidate", "False"),
            "pulled_frequency_discovery": row.get("pulled_frequency_discovery", "False"),
            "failure_mode": row.get("failure_mode", ""),
            "note": row.get("note", ""),
        }
        for row in ranked[:20]
    ]


